-- Poems batch 345
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('965327d1-fd65-49bc-908b-e61a4999c510','感春二首  其二','張耒','宋','宋诗','song-poetry','','[]','爲問閑茅客，窮愁何所歡。',48,'全唐诗/poet.song.66000.json','["爲問閑茅客，窮愁何所歡。", "焚香延晝睡，酤酒過春寒。", "歲月顛毛換，古今行路難。", "浮生付造物，留滯復何歎。"]'),
('aa7c6eb3-1dc1-43bc-976c-8286e163685e','晚春','張耒','宋','宋诗','song-poetry','','[]','積雨桃李暗，西園已晚春。',48,'全唐诗/poet.song.66000.json','["積雨桃李暗，西園已晚春。", "平池花照影，深樹鳥窺人。", "飛近燕知主，青分柳過鄰。", "浮生似群動，聊復共欣欣。"]'),
('5206dc9c-24c7-472f-82e1-c5582a405bb3','送春','張耒','宋','宋诗','song-poetry','','[]','莽莽平原綠，悠悠晚樹紅。',48,'全唐诗/poet.song.66000.json','["莽莽平原綠，悠悠晚樹紅。", "巢成鶯哺子，柳老絮飛空。", "碧草長亭路，青旂野店風。", "傷心對千里，無酒奈愁攻。"]'),
('14386c9c-334e-487d-8d08-a3061f426985','遲日','張耒','宋','宋诗','song-poetry','','[]','遲日花光亂，東風酒浪深。',48,'全唐诗/poet.song.66000.json','["遲日花光亂，東風酒浪深。", "天邊爲客恨，老去惜春心。", "起舞狂猶在，悲歌病不禁。", "高樓見千里，不醉莫登臨。"]'),
('c38ab6f1-967c-427e-b6ef-10308d65fa82','晚晴','張耒','宋','宋诗','song-poetry','','[]','裛塵朝雨細，透竹夕陽明。',48,'全唐诗/poet.song.66000.json','["裛塵朝雨細，透竹夕陽明。", "鳥雀知春去，牛羊散晚晴。", "官閑端欲老，謀拙漫無成。", "堂下清溪水，三逢蘋芷生。"]'),
('102a5e85-67bc-4059-a8f3-700b6cfc43b2','秋晚','張耒','宋','宋诗','song-poetry','','[]','鳥栖林已靜，門掩吏家歸。',48,'全唐诗/poet.song.66000.json','["鳥栖林已靜，門掩吏家歸。", "黄葉雨中盡，鳴蟲霜後微。", "塵凝經暑扇，貂敝早寒衣。", "頼有清尊酒，山爐徹夜圍。"]'),
('077c5016-9501-4c2c-bbbe-07d4e613f245','黄人謂寒食上冢爲澆山其祭饌多用蒻菜事已則鳴鉦而歸','張耒','宋','宋诗','song-poetry','','[]','携酒澆山去，鳴鉦徹祭歸。',48,'全唐诗/poet.song.66000.json','["携酒澆山去，鳴鉦徹祭歸。", "青蔬蒸果蒻，白酒市無旗。", "日暮人皆醉，夜深歌似啼。", "故人書問我，何用久居夷。"]'),
('235ab42c-cb55-4e06-8fa7-c8f352e438f9','東池','張耒','宋','宋诗','song-poetry','','[]','東池久不到，摇落過秋中。',48,'全唐诗/poet.song.66000.json','["東池久不到，摇落過秋中。", "萬竹蕭蕭雨，孤荷嫋嫋風。", "遣秋詩酒在，久客歲時窮。", "唯有思鄉夢，長隨洛水東。"]'),
('d111b775-3eae-409d-86ae-fa806f8a1b0f','和應之盛夏','張耒','宋','宋诗','song-poetry','','[]','驅馬畏炎暑，杜門常鮮歡。',48,'全唐诗/poet.song.66000.json','["驅馬畏炎暑，杜門常鮮歡。", "吳綃朝扇薄，越布夜衾單。", "飲沼山禽渴，沾泥雨果殘。", "二年薇與蕨，實厭野人餐。"]'),
('84f95697-6c38-450d-bb3e-2e549a866e0d','和應之永日','張耒','宋','宋诗','song-poetry','','[]','多病倦煩暑，幸茲山水幽。',48,'全唐诗/poet.song.66000.json','["多病倦煩暑，幸茲山水幽。", "惜芳悲鷤䳏，占雨聽鳴鳩。", "池影澄當戶，山陰暮轉樓。", "黄昏螢點點，秋信與堪愁。"]'),
('df92a4b0-fd80-4b58-9f9d-6d6c2db8ba82','偶摘梅數枝致案上盎中芬然遂開因爲作一詩','張耒','宋','宋诗','song-poetry','','[]','偶別霜城陋，來蒙玉案登。',48,'全唐诗/poet.song.66000.json','["偶別霜城陋，來蒙玉案登。", "清香侵硯水，寒影伴書燈。", "見我粲如笑，贈人慵未能。", "將何伴高潔，清曉誦黄庭。"]'),
('45bce13f-5f3a-44a0-914f-e52f70242018','初冬小園寓目','張耒','宋','宋诗','song-poetry','','[]','獨樹翹寒色，閑雲澹落暉。',48,'全唐诗/poet.song.66000.json','["獨樹翹寒色，閑雲澹落暉。", "新霜黄菊重，久雨翠梧稀。", "暝雀鳴還啄，高烏定更飛。", "敝貂猶故在，卒歲免無衣。"]'),
('e497fc01-7f1d-4c17-bc7f-fa8b270e238c','冬日作二首  其一','張耒','宋','宋诗','song-poetry','','[]','南雨不成雪，北風樓觀寒。',48,'全唐诗/poet.song.66000.json','["南雨不成雪，北風樓觀寒。", "眉顰魯酒薄，腸斷楚梅酸。", "雲夢寒全薄，湖湘春欲還。", "舉頭瞻去雁，羨爾有輕翰。"]'),
('78d2a6c7-5bac-4473-b8fe-cab420a46247','冬日作二首  其二','張耒','宋','宋诗','song-poetry','','[]','澤國久還雨，頻妨裘褐溫。',48,'全唐诗/poet.song.66000.json','["澤國久還雨，頻妨裘褐溫。", "羈懷常悄悄，醉眼任昏昏。", "雲赴荆王夢，天迷楚客魂。", "飄萍惟泥酒，吾事肯輕論。"]'),
('9ff7c105-2513-4446-b203-af2d84d88fc6','冬日即事','張耒','宋','宋诗','song-poetry','','[]','郡閑多暇日，况乃值清冬。',48,'全唐诗/poet.song.66000.json','["郡閑多暇日，况乃值清冬。", "風葉已成掃，霜蕪猶復重。", "佛香留夜火，蔬飯候晨鐘。", "誰信二千石，心如一衲翁。"]'),
('005d4ab5-83e7-4c05-ae29-da06cb8e7f10','冬日書事二首  其一','張耒','宋','宋诗','song-poetry','','[]','草草漫翁居，心安知有餘。',48,'全唐诗/poet.song.66000.json','["草草漫翁居，心安知有餘。", "風高收野潦，霜晚足園蔬。", "宿火溫茶篋，明燈轉素書。", "御冬無旨蓄，漬藥酒盈壺。"]'),
('31d63110-5279-4f3e-8428-927802bdfb49','冬日書事二首  其二','張耒','宋','宋诗','song-poetry','','[]','孤城已慘淡，晚色復朦朧。',48,'全唐诗/poet.song.66000.json','["孤城已慘淡，晚色復朦朧。", "日動烏栖葉，雲開雁去風。", "草繁田尚綠，霜薄葉微紅。", "已是悲摇落，那堪歲更窮。"]'),
('d75ff232-5a53-446e-830e-0d3e24695e01','臘日晚步','張耒','宋','宋诗','song-poetry','','[]','喜覺陽和近，山園策杖行。',48,'全唐诗/poet.song.66000.json','["喜覺陽和近，山園策杖行。", "草應知地暖，柳欲向人輕。", "殘雪通春信，鳴禽報曉晴。", "田閭未成計，搔首向春耕。"]'),
('f886f319-8620-4ee1-8540-0d86c28a6557','臘日四首  其一','張耒','宋','宋诗','song-poetry','','[]','今日何妍暖，青春亦不遲。',48,'全唐诗/poet.song.66000.json','["今日何妍暖，青春亦不遲。", "竹尋穿地筍，梅有犯寒枝。", "雲物晴無事，禽魚暖自私。", "芳菲行滿眼，準擬報愁知。"]'),
('091e3704-586d-4fee-b83a-fba6751b3777','臘日四首  其二','張耒','宋','宋诗','song-poetry','','[]','臘雲寒不動，殘歲轉蕭條。',48,'全唐诗/poet.song.66000.json','["臘雲寒不動，殘歲轉蕭條。", "雪意千山靜，天形一雁高。", "冰留簷舊滴，紅到杏新梢。", "寂寞群兒笑，因文更解嘲。"]'),
('c22ac332-bfe0-41ce-8333-2fee55c715c3','臘日四首  其三','張耒','宋','宋诗','song-poetry','','[]','日暖村村路，人家迭送迎。',48,'全唐诗/poet.song.66000.json','["日暖村村路，人家迭送迎。", "婚姻須歲暮，酒醴幸年登。", "簫鼓兒童集，衣裳婦女矜。", "敢辭雞黍費，農事及春興。"]'),
('1b730ffa-a1f7-4dd7-9573-857f25f90e55','臘日四首  其四','張耒','宋','宋诗','song-poetry','','[]','園冷無人掃，門荒少客過。',48,'全唐诗/poet.song.66000.json','["園冷無人掃，門荒少客過。", "槐高庭日少，竹近野風多。", "霰雪催殘臘，山川對浩歌。", "飄蓬求季主，身世問如何。"]'),
('85fc1767-21f4-47a1-be6b-fe6daa316bbd','冬夜二首  其一','張耒','宋','宋诗','song-poetry','','[]','慘慘諸山暮，寥寥老樹空。',48,'全唐诗/poet.song.66000.json','["慘慘諸山暮，寥寥老樹空。", "尚飛霜雁急，不動雪雲重。", "掛冷寒燈壁，悲傳夜柝風。", "隔窗無恨竹，蕭颯到晨鐘。"]'),
('27a47c05-ae56-40d0-8ef2-43a920c1cea0','冬夜二首  其二','張耒','宋','宋诗','song-poetry','','[]','歲晚轉無趣，席門誰駐車。',48,'全唐诗/poet.song.66000.json','["歲晚轉無趣，席門誰駐車。", "澗泉分當井，山葉掃供厨。", "謀拙從人笑，身閑讀我書。", "幸知霜霰晚，時得灌園蔬。"]'),
('142481d0-0540-4f0d-879b-d9dee30951a7','臘月書事','張耒','宋','宋诗','song-poetry','','[]','荆棘連昌路，珠璣久化塵。',48,'全唐诗/poet.song.66000.json','["荆棘連昌路，珠璣久化塵。", "青山飛白鳥，野水渡行人。", "寂寂繁華盡，悠悠草木春。", "人間有興廢，何事獨傷神。"]'),
('6a05be4c-5e75-4dbe-a01a-fe152233c9b4','十一月七日五首  其一','張耒','宋','宋诗','song-poetry','','[]','寒更催欲盡，曙色轉雞吭。',48,'全唐诗/poet.song.66000.json','["寒更催欲盡，曙色轉雞吭。", "鳴雁背曉斗，清笳吟宿霜。", "空山歲華晚，故園歸夢長。", "晨起臨清鏡，悲嗟髮已蒼。"]'),
('bf479294-9885-4f95-a60e-bdeee414e0c4','十一月七日五首  其二','張耒','宋','宋诗','song-poetry','','[]','寒暑添線衲，朝晡折足鐺。',48,'全唐诗/poet.song.66000.json','["寒暑添線衲，朝晡折足鐺。", "無言病居士，面壁老胡僧。", "佛祖豈欺我，乾坤終有憑。", "窮年無一事，高卧醉騰騰。"]'),
('20389d9e-80b9-408f-aefa-71c66aaa8d4d','十一月七日五首  其三','張耒','宋','宋诗','song-poetry','','[]','山與晴天晚，江連夕照紅。',48,'全唐诗/poet.song.66000.json','["山與晴天晚，江連夕照紅。", "高鴻知夜渚，喬木要霜風。", "買酒缸須滿，溫爐火屢供。", "窮通定何物，隨意樂衰翁。"]'),
('2e21bd55-6b95-41cc-a284-bbf214da587b','十一月七日五首  其四','張耒','宋','宋诗','song-poetry','','[]','三杯無奈醉，一褐有餘溫。',48,'全唐诗/poet.song.66000.json','["三杯無奈醉，一褐有餘溫。", "眼下幸無事，世間何足論。", "山僧元飽飯，詞客謾招魂。", "杖策知何詣，門前老圃村。"]'),
('95a11d01-26e8-49b5-9570-c2e4749ba2f5','十一月七日五首  其五','張耒','宋','宋诗','song-poetry','','[]','水霧今晨重，山川不復分。',48,'全唐诗/poet.song.66000.json','["水霧今晨重，山川不復分。", "自然無日色，那更挾霜分。", "烏鳥依寒寂，漁樵散暝昏。", "一杯聊愈疾，令我憶違君。"]'),
('5c126ec3-5582-496a-814c-18b4781974c6','冬至後三日三首  其一','張耒','宋','宋诗','song-poetry','','[]','寒暑添線衲，朝晡折足鐺。',48,'全唐诗/poet.song.66000.json','["寒暑添線衲，朝晡折足鐺。", "何勞問榮辱，便是了平生。", "理自陰陽運，吾寧口舌爭。", "深居玩吾寶，不遺世人輕。"]'),
('fdafd86a-4bad-4fa8-a52d-9379e06f97bb','冬至後三日三首  其二','張耒','宋','宋诗','song-poetry','','[]','水國過冬至，風光春已生。',48,'全唐诗/poet.song.66000.json','["水國過冬至，風光春已生。", "梅如相見喜，雁有欲歸聲。", "老去書全懶，閑中酒愈傾。", "窮通付吾道，不復問君平。"]'),
('f5f41ce9-9a1a-447c-8cb2-a65144fb51d2','冬至後三日三首  其三','張耒','宋','宋诗','song-poetry','','[]','梅柳有情態，江城過歲除。',48,'全唐诗/poet.song.66000.json','["梅柳有情態，江城過歲除。", "山村見霜橘，江市出寒魚。", "謫久衣冠懶，身閑故舊疏。", "傍籬挑翠甲，憶我故園蔬。"]'),
('1302e73a-2f86-4f89-bbea-d59667b001a6','歲暮閑韵四首  其一','張耒','宋','宋诗','song-poetry','','[]','歲暮柯山客，端居不出門。',120,'全唐诗/poet.song.66000.json','["歲暮柯山客，端居不出門。", "風烟限僻壤，閭井若荒村。", "江鳥占寒暑，樓笳報曉昏。", "風枝吹斷蔓，霜葉擁陳根。", "慷慨看星劍，煩愁泥酒樽。", "孤烟吹日晏，寸炭語宵分。", "未肯傷麟泣，還須視舌存。", "可能天理錯，難與俗人論。", "魑魅徒爲爾，梟鸞竟異羣。", "江湖休浩渺，心拱北辰尊。"]'),
('7cba542e-6846-44a1-8358-63fe262ef782','歲暮閑韵四首  其二','張耒','宋','宋诗','song-poetry','','[]','歲暮柯山客，蕭條酒一樽。',120,'全唐诗/poet.song.66000.json','["歲暮柯山客，蕭條酒一樽。", "貧閑緣事少，老冷頼爐溫。", "草木千山麓，蓬茅數畝村。", "相逢半農圃，無事理雞豚。", "落井吹鳴碓，橫參對掩門。", "人歸邑犬吠，江黑夜虹翻。", "櫛感顛毛減，書愁病眼昏。", "按方成小釀，徵古搆新文。", "默喻乾坤意，靜看魑魅奔。", "何須歎虎兕，吾道古來尊。"]'),
('11e1c69b-8ad2-42d1-b19e-5a245a85e39f','歲暮閑韵四首  其三','張耒','宋','宋诗','song-poetry','','[]','歲暮柯山客，晨興理小堂。',96,'全唐诗/poet.song.66000.json','["歲暮柯山客，晨興理小堂。", "重雲隔短日，老樹拱清霜。", "暖足加爐炭，翻經炷佛香。", "蠲疴藥探篋，破悶酒盈觴。", "江落朝宗急，年登播殖忙。", "江魚切玉白，楚稻撲雲黄。", "獵獲頻供炙，鄰蔬屢許嘗。", "吾謀殊未失，曝背負朝陽。"]'),
('14c0fa48-43b0-4bc1-959e-c3a87119ce34','歲暮閑韵四首  其四','張耒','宋','宋诗','song-poetry','','[]','歲暮柯山客，端居欲滯淫。',96,'全唐诗/poet.song.66000.json','["歲暮柯山客，端居欲滯淫。", "空山唯古木，短日更層陰。", "水國風霜晚，幽人井磑深。", "年饑無貸粟，冬暖有殘砧。", "靜枕聞鳴雁，開門對遠林。", "烏賓朝日上，雞送曙河沉。", "今古竟一致，乾坤固有心。", "悲歌激壯氣，未覺鬢霜侵。"]'),
('6aca7905-4ff5-4972-b042-59c1be21015a','歲暮','張耒','宋','宋诗','song-poetry','','[]','歲暮無聊客，端居如坐禪。',48,'全唐诗/poet.song.66000.json','["歲暮無聊客，端居如坐禪。", "薄霜猶衣裌，多雨急收田。", "落日烏鳶集，晴林橘柚懸。", "已無軒冕念，岑寂度殘年。"]'),
('911f3599-adfc-4909-b184-d6847e918306','小雨','張耒','宋','宋诗','song-poetry','','[]','小雨廉纖晚，幽花寂歷秋。',48,'全唐诗/poet.song.66000.json','["小雨廉纖晚，幽花寂歷秋。", "嘉時空冉冉，白日付悠悠。", "亂思工縈恨，危腸只貯愁。", "唯應時扣寂，一念萬緣休。"]'),
('ae513e85-00de-43a5-86b7-64f63a0e3ab8','和應之細雨','張耒','宋','宋诗','song-poetry','','[]','朝烟和細雨，病眼暗難分。',48,'全唐诗/poet.song.66000.json','["朝烟和細雨，病眼暗難分。", "有潤物皆澤，無聲人不聞。", "綠連平野稼，翠雜亂山氛。", "晚霽復何有，飄飄神女雲。"]'),
('7092786d-61f6-4a68-a434-400f8f2974f0','和小雨','張耒','宋','宋诗','song-poetry','','[]','入夜雨聲急，坐愁衾枕單。',48,'全唐诗/poet.song.66000.json','["入夜雨聲急，坐愁衾枕單。", "春歸千里恨，夢斷五更寒。", "遣興芳樽滿，驚心節物殘。", "山城近野水，半夜有歸翰。"]'),
('d59431bf-d9f1-46ec-b63e-e9a3559971c8','晚霽','張耒','宋','宋诗','song-poetry','','[]','山川收滯雨，烏鵲有和聲。',48,'全唐诗/poet.song.66000.json','["山川收滯雨，烏鵲有和聲。", "半嶺日猶照，一天雲盡行。", "人皆理牆壁，吾亦掃柴荆。", "鵝鴨何多喜，渠流漾淺清。"]'),
('3a0c8d03-c0c6-4222-a98f-fe6388069185','秋雨書事','張耒','宋','宋诗','song-poetry','','[]','荏苒歲云暮，空山朝夕陰。',216,'全唐诗/poet.song.66000.json','["荏苒歲云暮，空山朝夕陰。", "可堪連日雨，併作晚秋霖。", "蕭颯三川合，凄凉八月深。", "衰荷啼卧水，怨葉泣辭林。", "徑滑蓬蒿長，庭荒苔蘚侵。", "遠聲連促織，疏滴和清砧。", "燈暗殘更夢，閨寒向曉衾。", "沾衣貧路客，啼苦失巢禽。", "天接崗巒近，雲連草樹深。", "川容千仗肅，溪力萬艘沉。", "紅濕梨垂頰，黄沾菊破金。", "苑荒懷古恨，樓遠望鄉心。", "碧漲池中浪，青藏雲外岑。", "客城陰燐走，敗舍濕蝸尋。", "騎省驚衰颯，荆州嘆滯淫。", "恨饒經暑扇，冷入補衣針。", "懶學書高閣，驅愁酒細斟。", "離憂殊未闋，悵望一長吟。"]'),
('84917784-99e3-4d02-b30b-84ae746e83fa','雨中五首  其一','張耒','宋','宋诗','song-poetry','','[]','手種階前樹，今朝亦有花。',48,'全唐诗/poet.song.66000.json','["手種階前樹，今朝亦有花。", "春陰寒食節，陋巷逐臣家。", "欲酌消愁酒，先澆破睡茶。", "游人歸踏雨，里巷晚喧譁。"]'),
('7cc35535-40a6-49e8-af57-bf0157a3ff70','雨中五首  其二','張耒','宋','宋诗','song-poetry','','[]','節物即自好，客心何落然。',48,'全唐诗/poet.song.66000.json','["節物即自好，客心何落然。", "早寒清野市，夜雨濕江天。", "破屋疏茅滴，空厨濕葦烟。", "政須一杯酒，相與度殘年。"]'),
('a276ea8a-f868-4cc5-b61e-ef35be6f9e1a','雨中五首  其三','張耒','宋','宋诗','song-poetry','','[]','積雨暗春色，東風還慘悽。',48,'全唐诗/poet.song.66000.json','["積雨暗春色，東風還慘悽。", "梅殘無復笑，鶯怨欲成啼。", "暇日無民訟，芳時有酒携。", "不辭乘興出，病足畏深泥。"]'),
('a080a9cf-c57b-4ac2-972a-4268d9f2c107','雨中五首  其四','張耒','宋','宋诗','song-poetry','','[]','春殘厭寒攪，雨多空日長。',48,'全唐诗/poet.song.66000.json','["春殘厭寒攪，雨多空日長。", "飯餘時策杖，睡足獨焚香。", "芍藥正酣寢，海棠渾未妝。", "賢哉堂下竹，相對只蒼蒼。"]'),
('288e447f-5420-4fc2-916d-c8c90d967f63','雨中五首  其五','張耒','宋','宋诗','song-poetry','','[]','三日雨不止，陰雲生我堂。',48,'全唐诗/poet.song.66000.json','["三日雨不止，陰雲生我堂。", "曉寒如臘月，凍坐憶朝陽。", "過雁低薄屋，高梅飄度牆。", "呼童傾一榼，獨對孟光嘗。"]'),
('00e9d84f-b48b-43ac-b1f0-60befe71d143','大雪苦寒五更無睡枕上成兩篇  其一','張耒','宋','宋诗','song-poetry','','[]','大雪人跡絕，衡門閉不知。',48,'全唐诗/poet.song.66000.json','["大雪人跡絕，衡門閉不知。", "寒城悲角迥，幽谷曉雞遲。", "歲月去如失，窮通默自知。", "但知飽寢飯，天道兩無私。"]'),
('c773a51a-16d2-407e-bab9-f237bbf36149','大雪苦寒五更無睡枕上成兩篇  其二','張耒','宋','宋诗','song-poetry','','[]','雪氣著我屋，雞膚畏薄衾。',48,'全唐诗/poet.song.66000.json','["雪氣著我屋，雞膚畏薄衾。", "春寒竹窗睡，曉夢故鄉心。", "多病妨豪飲，無私稱苦吟。", "小爐熾新炭，卯酒再三斟。"]'),
('be8a5e9f-4941-489b-9928-e3915a921cbd','雪晴苦寒','張耒','宋','宋诗','song-poetry','','[]','水驛微茫外，檣烏蒼莽中。',48,'全唐诗/poet.song.66000.json','["水驛微茫外，檣烏蒼莽中。", "人愁暮村雪，雁急夜淮風。", "大澤凍相接，羣山深未窮。", "蕭條歲事晚，舟檝伴南翁。"]'),
('fa4d5c07-5bd9-47e5-9dbe-5d04b5e750a5','雪齋','張耒','宋','宋诗','song-poetry','','[]','雪霽山堆黛，江晴日炫金。',48,'全唐诗/poet.song.66000.json','["雪霽山堆黛，江晴日炫金。", "風烟調柳態，冰雪徹梅心。", "節物何嫵媚，端居自滯淫。", "無眠聽雲雁，稍有北歸音。"]'),
('fb6aa878-d3b0-40d8-91a4-3d0b90acbab4','賦得風示秬秸','張耒','宋','宋诗','song-poetry','','[]','寂寂含至韵，清風時見嘉。',48,'全唐诗/poet.song.66000.json','["寂寂含至韵，清風時見嘉。", "無意偶自動，雖鳴終不譁。", "宮懸奏編磬，朝佩響衝牙。", "誰知無譜曲，舉世好黄華。"]'),
('dd2ff1c9-f563-468f-ae22-323851309490','福昌書事言懷一百韵上運判唐通直','張耒','宋','宋诗','song-poetry','','[]','戰國韓餘壤，王畿漢舊京。',288,'全唐诗/poet.song.66000.json','["戰國韓餘壤，王畿漢舊京。", "南圍山峙秀，東泛洛浮清。", "女几荒遺廟，宜陽認故城。", "千秋迷佩玦，百戰有榛荆。", "路失三鄉驛，崗餘世祖營。", "山疑熊耳甲，墓記赤眉兵。", "昌水行宮廢，穀州遺堞傾。", "斷壕收劍鏃，耕隴得瑶瓊。", "姬冢丘陵抱，韓祠草木平。", "傳家亡譜牒，懷德薦牢牲。", "峽勢開雙璧，川形畫一枰。", "謀臣赤松友，詩客錦囊生。", "莽莽繁華盡，悠悠井邑更。", "興亡誰與弔，今古一傷情。", "官舍連麋鹿，人家雜鼬鼪。", "秋心悲杜宇，春候聽鶬鶊。", "賓榻無談笑，塵鞍罷送迎。", "平池宵檻影，萬竹曉堂聲。", "放宕書千卷，栖遲歲再正。", "野胥形矍掠，村隸語生獰。", "脫粟供朝飯，孤豚計日烹。", "里閭輕學校，兒稚駭冠纓。", "最苦衝風隧，奔如萬戰輣。", "木號驚浪涌，谷震疾雷轟。"]'),
('451769dc-1be5-4cc9-9946-207d67ad1387','送胡唐臣赴蘇州僉判','張耒','宋','宋诗','song-poetry','','["\u592a\u6e56"]','他日馳戎馬，風塵從事衫。',48,'全唐诗/poet.song.66000.json','["他日馳戎馬，風塵從事衫。", "花開大梁酒，木落太湖帆。", "幕府煩精悍，吳山入笑談。", "長安米不賤，君與問江南。"]'),
('1aeb6583-76c9-47ac-aa4b-30d94374c272','泛宛溪至敬亭祠送別','張耒','宋','宋诗','song-poetry','','[]','南國初寒候，扁舟遠客心。',48,'全唐诗/poet.song.66000.json','["南國初寒候，扁舟遠客心。", "歸人出斷岸，晚翼會疏林。", "漁市臨官道，叢祠蔽木陰。", "長年多感慨，况此對分襟。"]'),
('b58fb1c8-fda5-4f79-9cdf-7ed12c8c5037','送丁秀才侍竹之邕州','張耒','宋','宋诗','song-poetry','','[]','五嶺天南極，扁舟到幾時。',48,'全唐诗/poet.song.66000.json','["五嶺天南極，扁舟到幾時。", "山川故國遠，猿鳥異鄉悲。", "書史傳家舊，功名及壯期。", "相携有佳客，莫負錦囊時。"]'),
('9539d318-2354-40f4-bd36-49b302e4e383','送蔡彥規之任風泉主簿','張耒','宋','宋诗','song-poetry','','[]','四十曳青袍，功名晚未遭。',48,'全唐诗/poet.song.66000.json','["四十曳青袍，功名晚未遭。", "賢人固難進，小邑且徒勞。", "秦俗謳謠口，雍州形勢豪。", "憑君懷古意，一一寄風騷。"]'),
('52f4a7b5-16e7-4a55-8d76-b372943ab341','別外甥楊克一二首  其一','張耒','宋','宋诗','song-poetry','','[]','東南秋雨足，澤國水連天。',48,'全唐诗/poet.song.66000.json','["東南秋雨足，澤國水連天。", "日出數聲雁，風高何處船。", "寒葅初獲韭，野餉屢烹鮮。", "吾事無淹速，悠悠得醉眠。"]'),
('1a40090b-41c6-4564-a92c-1c0aab4df1bd','別外甥楊克一二首  其二','張耒','宋','宋诗','song-poetry','','[]','澤國授衣早，今辰絺紵單。',48,'全唐诗/poet.song.66000.json','["澤國授衣早，今辰絺紵單。", "孤城遠目斷，秋水去帆寒。", "相見不再少，此生何日閑。", "殷勤換美酒，要對蟹螯槃。"]'),
('6c969354-7c65-4036-a07a-a9b24aacb985','送劉南夫赴任京師','張耒','宋','宋诗','song-poetry','','[]','却掃楚山根，相過唯有君。',48,'全唐诗/poet.song.66000.json','["却掃楚山根，相過唯有君。", "齊年未白髮，不日上青雲。", "送別悲秋早，傷離頼酒醺。", "青衫老司馬，落淚獨紛紛。"]'),
('56b27890-10a9-4d69-b10f-67d4845d8815','和見夢','張耒','宋','宋诗','song-poetry','','[]','青山將白髮，奔走倦埃塵。',48,'全唐诗/poet.song.66000.json','["青山將白髮，奔走倦埃塵。", "與物拙難合，惟君心獨親。", "相思成夜夢，得句寄游鱗。", "未得親談笑，書來莫厭頻。"]'),
('870da9f7-0889-4d4c-9b59-7e996dbe31a6','和應之雨中見懷之作','張耒','宋','宋诗','song-poetry','','[]','官居苦岑寂，容易過花時。',48,'全唐诗/poet.song.66000.json','["官居苦岑寂，容易過花時。", "綠暗野初秀，紅乾風更吹。", "燕游心未展，歸去意猶遲。", "浩蕩雲山外，新詩寄我思。"]'),
('5a137f1e-f450-4d14-b1bc-9d881290ddbd','用元韵因寄邦直','張耒','宋','宋诗','song-poetry','','[]','濠上昔相逢，同時執桂叢。',48,'全唐诗/poet.song.66000.json','["濠上昔相逢，同時執桂叢。", "遠遊悲聚散，投老信窮通。", "靜見賢人節，恬知達士風。", "淹留君莫嘆，榮辱竟虛空。"]'),
('ca5daa45-f287-4746-b5f6-a2b4a112d77f','書事寄晁應之','張耒','宋','宋诗','song-poetry','','[]','野筍空階短，蒲芽出水齊。',240,'全唐诗/poet.song.66000.json','["野筍空階短，蒲芽出水齊。", "柳垂縈鵲重，花裊带蜂低。", "桑弱蠶登箔，池晴燕啄泥。", "官閑無事役，地僻斷招携。", "目極榛蕪地，心傷桃李蹊。", "萎花辭雨泣，幽鳥別春啼。", "白髮驚身老，高樓對日西。", "運逢詩將健，路入醉鄉迷。", "燒醑傾新臘，輕羅換舊裾。", "香紈裁暑扇，密幄徹寒閨。", "喬木陰垂屋，清渠冷接溪。", "惜芳幽閟䳏，催夢怨黄鸝。", "高會思前日，酣歌到曉雞。", "駕羊君自幼，倚玉我慚黳。", "誰解藏車轄，歸來信馬蹄。", "還家門寂寂，過雨草萋萋。", "氣合非容易，官拘坐阻睽。", "孤吟唯酒對，愁立見烏栖。", "學懶因循過，詩成取次題。", "相思不可望，烟靄暮凄凄。"]'),
('9a04f5fb-63f2-4de0-ab24-6248b3e3b3c5','題所居西齋','張耒','宋','宋诗','song-poetry','','[]','幽居不厭小，小院有深庭。',48,'全唐诗/poet.song.66000.json','["幽居不厭小，小院有深庭。", "一曲秋風地，低簷夕照明。", "脫條株有態，止水瑩含清。", "中有支離客，吟腰瘦沈卿。"]'),
('4812b25c-279f-4cce-94a9-0ad3af76a782','題楚州聖井并贈主僧','張耒','宋','宋诗','song-poetry','','[]','古佛勝妙力，一泓常湛然。',48,'全唐诗/poet.song.66000.json','["古佛勝妙力，一泓常湛然。", "禱祈供衆欲，守護頼師賢。", "清碧晨齋罷，秋登寶供前。", "自憐多病質，時許挹清泉。"]'),
('c5894e05-fad2-4f5e-b658-4aa59adf3fd8','題倪敦復北軒','張耒','宋','宋诗','song-poetry','','[]','瀟洒倪夫子，新城面北堂。',48,'全唐诗/poet.song.66000.json','["瀟洒倪夫子，新城面北堂。", "庭前無獄訟，客至有壺觴。", "晝靜塵埃絕，春餘花草香。", "爲君題素壁，容我醉中狂。"]'),
('380d7356-8d8e-4eb6-854d-ea4e8aa54b5d','書壁','張耒','宋','宋诗','song-poetry','','[]','後院人稀到，荒池半是苔。',48,'全唐诗/poet.song.66000.json','["後院人稀到，荒池半是苔。", "好花隨地有，幽鳥自山來。", "靡靡香草合，陰陰夏木催。", "昭亭有佳色，每至不容回。"]'),
('9559e463-01c6-42be-908a-9b382f546521','和應之石澗','張耒','宋','宋诗','song-poetry','','[]','麥氣朝含露，溪光夕照烟。',48,'全唐诗/poet.song.66000.json','["麥氣朝含露，溪光夕照烟。", "鬭麋蒼角老，雛雉絳毛鮮。", "葵折紅繒縐，蓮香水麝燃。", "敢辭幽僻處，直恐負林泉。"]'),
('696dead5-0493-4d1b-a612-9f94ead212c6','李贊皇畫像','張耒','宋','宋诗','song-poetry','','[]','管樂久寥闊，興王一士多。',48,'全唐诗/poet.song.66000.json','["管樂久寥闊，興王一士多。", "平生自龍虎，功業在山河。", "公子悲黄犬，騷人赴汨羅。", "當年閱川恨，流落復如何。"]'),
('1227cf0f-fa4c-48cf-8791-091baa24b0d6','散步西園','張耒','宋','宋诗','song-poetry','','[]','歲晚傷局促，散懷唯小園。',48,'全唐诗/poet.song.66000.json','["歲晚傷局促，散懷唯小園。", "鳴禽下荒寂，孤木倚高寒。", "閏月長蔬甲，清霜瘦竹竿。", "荆人重鮮食，怪我厭魚餐。"]'),
('bb8fbf45-b2d6-434c-83ef-cb710eabd672','七月七日晚步園中見落葉如積感而作','張耒','宋','宋诗','song-poetry','','[]','東園久不到，落葉曲池平。',48,'全唐诗/poet.song.66000.json','["東園久不到，落葉曲池平。", "摇落遽如許，歲時真可驚。", "衡茅望故里，漁釣寄餘生。", "放逐逢艱歲，藜羹未敢輕。"]'),
('53329a8e-0fdf-48e4-8741-d2312272fde6','秋園','張耒','宋','宋诗','song-poetry','','[]','山蹊久不到，落葉滿秋園。',48,'全唐诗/poet.song.66000.json','["山蹊久不到，落葉滿秋園。", "幽草自寒綠，晚花翹碧鮮。", "鷄豚放斜日，鷗鷺下遙天。", "閭里經過熟，居夷已一年。"]'),
('50503cfd-a6f1-44b7-889f-e65a82a8bd7a','種圃','張耒','宋','宋诗','song-poetry','','[]','僦舍亦爲圃，從人笑我癡。',48,'全唐诗/poet.song.66000.json','["僦舍亦爲圃，從人笑我癡。", "自求佳草木，仍補小藩籬。", "吾事正如此，人生聊自怡。", "霜松未及尺，獨我見奇姿。"]'),
('73555e37-7a15-4dd4-b8f7-75cac76d9544','幽草二首  其一','張耒','宋','宋诗','song-poetry','','[]','幽草堂軒秀，盆池遇雨添。',48,'全唐诗/poet.song.66000.json','["幽草堂軒秀，盆池遇雨添。", "新晴雀哺子，永日燕穿簾。", "世事休驚目，閑中且養恬。", "黄公有美酒，時得醉厭厭。"]'),
('4e316661-a028-4435-97c6-262b6609085e','幽草二首  其二','張耒','宋','宋诗','song-poetry','','[]','衰草已無頼，秋花只强名。',48,'全唐诗/poet.song.66000.json','["衰草已無頼，秋花只强名。", "雨園蛩響細，寒樹鳥啼清。", "淹泊知吾道，幽居見物情。", "唯應有鄰叟，足雨問農耕。"]'),
('0f94b4c6-4671-4e37-b701-5395c3841ada','山暝孤猿吟','張耒','宋','宋诗','song-poetry','','[]','平野何岑寂，空山晚易陰。',72,'全唐诗/poet.song.66000.json','["平野何岑寂，空山晚易陰。", "微雲數峰暝，幽谷一猿吟。", "風果饑遇少，霜枝冷不禁。", "引吭當落日，激響度前林。", "最惻騷人興，偏悽遠客心。", "空齋懷謝守，空復昔時音。"]'),
('f60fd3b4-7c92-4355-92b1-b12271885b48','新葺附火小閣','張耒','宋','宋诗','song-poetry','','[]','低牖僅障風，深爐宿火紅。',48,'全唐诗/poet.song.66000.json','["低牖僅障風，深爐宿火紅。", "忘懷榮辱外，無事寂寥中。", "隕葉鳴寒瓦，飛霜皎夜空。", "宵分未投宿，饑苦北來鴻。"]'),
('4f54ebcb-101a-499b-aa7a-8f2f1cbc00ad','泛江偶成','張耒','宋','宋诗','song-poetry','','[]','扁舟漾寒水，暫使客心清。',48,'全唐诗/poet.song.66000.json','["扁舟漾寒水，暫使客心清。", "天與秋陰合，江連野色平。", "洪波迴赤壁，蒼野带孤城。", "更想孫郎戰，臨風動壯情。"]'),
('54a1d7e7-8529-4248-819f-18c869e74a56','潤州書事','張耒','宋','宋诗','song-poetry','','[]','野蔓封城堞，疏松隔麗譙。',48,'全唐诗/poet.song.66000.json','["野蔓封城堞，疏松隔麗譙。", "樓臨寒洶湧，門揖翠岧嶢。", "客思閑易感，歸心去莫招。", "何時送客處，看我理歸橈。"]'),
('851bff09-1474-46c3-92d3-66dfcfcba9cd','暮歸','張耒','宋','宋诗','song-poetry','','[]','牛羊久已下，寂寂掩城扉。',48,'全唐诗/poet.song.66000.json','["牛羊久已下，寂寂掩城扉。", "水鶴鳴城堞，飛螢上戟衣。", "夜凉江海近，天闊斗牛微。", "何日招舟子，寒江北渡歸。"]'),
('49da2352-5d2d-4fe4-9ceb-b9b73cf9b76d','九月十八日夢中作聞雁詩','張耒','宋','宋诗','song-poetry','','[]','何日離燕磧，來投江上洲。',48,'全唐诗/poet.song.66000.json','["何日離燕磧，來投江上洲。", "高鳴雲際夜，冷度雨中秋。", "繒繳遠須避，稻粱寒未收。", "春風歸翼便，容易一冬留。"]'),
('5e6b7384-4119-4d37-b875-192d25b54cc5','和晁十七晝眠','張耒','宋','宋诗','song-poetry','','[]','冉冉殘春去，悠悠歸夢賒。',48,'全唐诗/poet.song.66000.json','["冉冉殘春去，悠悠歸夢賒。", "窗圍幽幌靜，風引晝簾斜。", "清蔭延高柳，餘紅惜晚花。", "山居諳靜僻，詩句是生涯。"]'),
('6bcfeae1-35fa-4115-a872-ba58b725175f','早起偶成','張耒','宋','宋诗','song-poetry','','[]','枕席清如水，蕭然一老僧。',48,'全唐诗/poet.song.66000.json','["枕席清如水，蕭然一老僧。", "鷄聲消壁月，曉日失窗燈。", "山葉寒逾響，江雲薄易凝。", "老僧曾教我，任運且騰騰。"]'),
('6eeec66b-8b1a-44d5-b6d8-c7c34e65b936','正月二十日夢在京師','張耒','宋','宋诗','song-poetry','','[]','客睡何展轉，青燈暗又明。',48,'全唐诗/poet.song.66000.json','["客睡何展轉，青燈暗又明。", "春雲藏澤國，夜雨嘯山城。", "許國有寸鐵，耕田無一成。", "朦朧五更夢，俄頃踏王京。"]'),
('5bd15d51-e07d-4c71-9a17-f9590e03753c','夢中作','張耒','宋','宋诗','song-poetry','','[]','去路迎朝日，齊安客馬西。',48,'全唐诗/poet.song.66000.json','["去路迎朝日，齊安客馬西。", "山行逢曉雨，客褲濺寒泥。", "歷險輿何健，衝風酒自携。", "回頭思舊止，陳迹已凄凄。"]'),
('535037b1-b3f4-49fc-a4b6-e9a725656625','八月十一日晨興三首  其一','張耒','宋','宋诗','song-poetry','','[]','老人秋少睡，禪誦每晨興。',48,'全唐诗/poet.song.66000.json','["老人秋少睡，禪誦每晨興。", "鄰碓舂殘月，床蛩語暗燈。", "高林鳥聲起，幽草露華凝。", "筇杖兼禪榻，生涯一野僧。"]'),
('264cb7e4-b4f1-4f4f-b35f-526fe5195f2c','八月十一日晨興三首  其二','張耒','宋','宋诗','song-poetry','','[]','端居歲已宴，杖履亦蕭然。',48,'全唐诗/poet.song.66000.json','["端居歲已宴，杖履亦蕭然。", "雲露窗前日，秋明樹外天。", "大江寒欲落，諸嶺霽逾鮮。", "白首無聊劇，昏昏只醉眠。"]'),
('d83cbad3-d004-4fef-be23-3e9692f942ac','八月十一日晨興三首  其三','張耒','宋','宋诗','song-poetry','','[]','江上秋陰合，柯山曉雨來。',48,'全唐诗/poet.song.66000.json','["江上秋陰合，柯山曉雨來。", "貂裘欲辭篋，紈扇已生埃。", "落葉濕相藉，晚花寒未開。", "殷勤探黄菊，九日泛清杯。"]'),
('acf61b95-758d-44f4-aa27-a75215041ea3','晨起','張耒','宋','宋诗','song-poetry','','[]','曉色淡朦朧，園林白露濃。',48,'全唐诗/poet.song.66000.json','["曉色淡朦朧，園林白露濃。", "寒叢蛩響畔，秋屋葉聲中。", "更老心猶壯，雖貧尊不空。", "浮生仗天理，不擬哭途窮。"]'),
('7a802446-d5e0-4d1d-b9bc-3e0b572333c9','曉作','張耒','宋','宋诗','song-poetry','','[]','靜枕有遠聽，風聲带曉江。',48,'全唐诗/poet.song.66000.json','["靜枕有遠聽，風聲带曉江。", "寒雲垂紞紞，嚴鼓已逢逢。", "功業驚殘歲，江山隠陋邦。", "寒雞憎客夢，呼日上低窗。"]'),
('9c6c44f9-e28a-41a9-a6a5-aa944b5883e0','小齋夜思','張耒','宋','宋诗','song-poetry','','[]','夜久高籟息，燈明一室虛。',48,'全唐诗/poet.song.66000.json','["夜久高籟息，燈明一室虛。", "過聲寒鷺鵠，落影老楸梧。", "大澤星河淡，孤城更漏疏。", "安能久鬰鬰，興發付歸歟。"]'),
('5835b251-9d46-499f-b888-20e7a9c3461d','晚同永源小酌漫成','張耒','宋','宋诗','song-poetry','','[]','庭竹晚風細，階莎絡緯鳴。',48,'全唐诗/poet.song.66000.json','["庭竹晚風細，階莎絡緯鳴。", "連山沉落日，萬竅起秋聲。", "客思方凄切，流年可嘆驚。", "平生一樽酒，正爲此時傾。"]'),
('15688658-239b-4b79-9600-3d05aa8400d6','冒雨歸飲酒','張耒','宋','宋诗','song-poetry','','[]','密雨集春庭，花含曉氣清。',48,'全唐诗/poet.song.66000.json','["密雨集春庭，花含曉氣清。", "喜傾燒酒釅，更御暑衣輕。", "老惜春無日，窮欣歲有成。", "杖藜園徑曉，坐見小池平。"]'),
('cfeca78b-b32b-469e-adba-2029ddd07e8a','和蘇仲南邵湖會飲三首  其一','張耒','宋','宋诗','song-poetry','','[]','老病倦岑寂，燕游聊與俱。',48,'全唐诗/poet.song.66000.json','["老病倦岑寂，燕游聊與俱。", "開樽當勝地，飛蓋渡平湖。", "落日晚明滅，烟林遠有無。", "歸來燈火夜，人影亂栖鳬。"]'),
('a81cbbba-7e48-43c5-80a0-ef16a5e4d38a','和蘇仲南邵湖會飲三首  其二','張耒','宋','宋诗','song-poetry','','[]','交友不在眼，逢君懷抱開。',48,'全唐诗/poet.song.66000.json','["交友不在眼，逢君懷抱開。", "主人容客醉，樽酒犯寒來。", "老境侵霜鬢，羈愁付酒杯。", "身閑不易得，相與且徘徊。"]'),
('dbc71f83-0d0a-494b-991a-8cd488a4f4e3','和蘇仲南邵湖會飲三首  其三','張耒','宋','宋诗','song-poetry','','[]','新亭當絕島，景物更清妍。',48,'全唐诗/poet.song.66000.json','["新亭當絕島，景物更清妍。", "耳熱風前酒，心澄水底天。", "觀魚方有得，薦味肯烹鮮。", "默坐吟春草，知君似惠連。"]'),
('36fae26f-4d27-4790-aa44-c05d0bc9874b','人家','張耒','宋','宋诗','song-poetry','','[]','人家依古木，雞犬亂山深。',48,'全唐诗/poet.song.66000.json','["人家依古木，雞犬亂山深。", "積雪暗猶壯，寒雲晚易陰。", "斷荷欹凍水，孤月戰風林。", "稍稍栖烏定，饑啼何處禽。"]'),
('fbf5e0f6-fddc-47d9-b311-1582a03ae185','山城','張耒','宋','宋诗','song-poetry','','[]','野縣閉門早，山深更漏微。',48,'全唐诗/poet.song.66000.json','["野縣閉門早，山深更漏微。", "薄雲依月宿，孤翼犯霜歸。", "弓冷新膠健，貂寒舊縷紕。", "旗亭換新酒，不惜篋中衣。"]'),
('656bbb40-0583-4f11-a5bc-9d1cf033ea72','他鄉','張耒','宋','宋诗','song-poetry','','[]','春寒客古寺，草草過鶯花。',48,'全唐诗/poet.song.66000.json','["春寒客古寺，草草過鶯花。", "小榼供朝酒，溫爐煮夜茶。", "柏庭鳴曉吹，樓角麗朝霞。", "莫嘆萍蓬迹，心安即是家。"]'),
('cb154620-23c8-44e3-8dfd-201f439709eb','山夜','張耒','宋','宋诗','song-poetry','','[]','更漏孤城迥，簾帷靜夜長。',48,'全唐诗/poet.song.66000.json','["更漏孤城迥，簾帷靜夜長。", "天高風送雁，月冷樹浮霜。", "晚菊差池綠，高桐次第黄。", "曉來南國夢，不覺寄他鄉。"]'),
('027b9718-c25d-4414-bb73-eaa02f636728','偶成','張耒','宋','宋诗','song-poetry','','[]','却掃客不至，端爲四國騷。',48,'全唐诗/poet.song.66000.json','["却掃客不至，端爲四國騷。", "杯寒薦園實，食儉煮溪毛。", "霜過橘柚熟，天晴鴻鵠高。", "幽齋高木近，不寢聽雞號。"]'),
('65496707-1677-44d2-9214-a8d3a4843538','溝泥二首  其一','張耒','宋','宋诗','song-poetry','','[]','溝泥不可步，况復雨清晨。',48,'全唐诗/poet.song.66000.json','["溝泥不可步，况復雨清晨。", "下直休半日，閉門閑晚春。", "著書聊爾耳，隠市笑徒云。", "買酒待新月，奈茲千里雲。"]'),
('fe1bf6c4-9234-42d8-89f4-11e268b9ea24','溝泥二首  其二','張耒','宋','宋诗','song-poetry','','[]','不嫌泥潦巷，自掃寂寥居。',48,'全唐诗/poet.song.66000.json','["不嫌泥潦巷，自掃寂寥居。", "雨已標新杏，春猶遺老樗。", "風光習暖事，雲物或寒除。", "頗復撩詩句，時時漫與書。"]'),
('21a1ce95-90bd-4788-ab73-2c2ddf6b6993','柯谷','張耒','宋','宋诗','song-poetry','','[]','柯谷秋已晚，衡門終日閒。',48,'全唐诗/poet.song.66000.json','["柯谷秋已晚，衡門終日閒。", "老唯謀酒食，病更怯風寒。", "暖脚氈鞋穩，蒙頭衲帽寬。", "年來諳世事，對客欲忘言。"]'),
('4ce349fd-b4da-4153-9c20-20d61c2a68b0','東堂','張耒','宋','宋诗','song-poetry','','[]','杳杳寒鷄唱，漫漫夜色深。',48,'全唐诗/poet.song.66000.json','["杳杳寒鷄唱，漫漫夜色深。", "斗柄垂地直，河勢向江沉。", "林鳥栖欲去，草蟲寒尚吟。", "幽人揜蓬蓽，不睡擁單衾。"]'),
('7ae284d3-b94c-4f5e-9c06-17059b903b50','和晁應之山中','張耒','宋','宋诗','song-poetry','','[]','康樂雖爲吏，不忘山水情。',48,'全唐诗/poet.song.66000.json','["康樂雖爲吏，不忘山水情。", "我無連璧美，君許託車行。", "幽鳥花前語，春泉竹外鳴。", "勒移無草草，吾友笑功名。"]'),
('5590fcf1-9d18-4d9a-93a1-48ca53d12cb7','和出山','張耒','宋','宋诗','song-poetry','','[]','曉別招提去，春風信馬行。',48,'全唐诗/poet.song.66000.json','["曉別招提去，春風信馬行。", "路幽皆竹影，山遠尚松聲。", "嶺斷晴天闊，川橫綠野平。", "不因泉石好，安覺利名輕。"]'),
('61301909-956f-4711-bc93-04ee9abf41e4','偶成二首  其一','張耒','宋','宋诗','song-poetry','','[]','鳥啼宮直散，歸舍日猶長。',48,'全唐诗/poet.song.66000.json','["鳥啼宮直散，歸舍日猶長。", "暗樹殘春綠，回風欲雨凉。", "久知癡有絕，端爲酒成忙。", "可是嘲須解，平生一漫郎。"]'),
('3b06d573-81d2-44ea-be55-85981013aeb0','偶成二首  其二','張耒','宋','宋诗','song-poetry','','[]','綠遍長安樹，春歸空隔年。',48,'全唐诗/poet.song.66000.json','["綠遍長安樹，春歸空隔年。", "愁多落花地，情遠倚樓天。", "河漢崑崙外，蒼龍北極天。", "老知玄有味，羞更賦神仙。"]'),
('49b35593-8f75-40f9-aa7b-87b18ed86289','晚凉行稻畦間','張耒','宋','宋诗','song-poetry','','[]','草木秋微警，山川夏已深。',48,'全唐诗/poet.song.66000.json','["草木秋微警，山川夏已深。", "迎風雲卷幕，沉日水浮金。", "晚鳥吟高木，霏烟暝遠林。", "杖藜循野澤，談笑不行吟。"]'),
('b83d63b1-0487-47b8-8216-a6321a32224f','登城二首  其一','張耒','宋','宋诗','song-poetry','','[]','楚望迷千里，孤城草樹濃。',48,'全唐诗/poet.song.66000.json','["楚望迷千里，孤城草樹濃。", "憑臨點衣雨，容易落花風。", "人事年年改，風光處處同。", "未能忘出處，徙倚更書空。"]'),
('26b0b9dc-7fb0-4ae4-a2ae-a01bf8afa6a3','登城二首  其二','張耒','宋','宋诗','song-poetry','','[]','綠野望不極，登臨引興長。',48,'全唐诗/poet.song.66000.json','["綠野望不極，登臨引興長。", "憑高延澤國，搔首對風光。", "乍出鶯貪柳，新歸燕揀梁。", "欣欣物華好，吾亦引清觴。"]'),
('32f20692-4a50-4393-9d0a-7abdeba2d375','登夢野亭','張耒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','危亭瞰雲夢，眼界浩無邊。',48,'全唐诗/poet.song.66000.json','["危亭瞰雲夢，眼界浩無邊。", "秋見長江路，晴寬七澤天。", "永懷哀郢賦，誰弔獨醒賢。", "俯仰悲千古，披襟尚颯然。"]'),
('c06c108d-123a-40a1-9d88-0972ebf532e4','同應之登大宋陂','張耒','宋','宋诗','song-poetry','','[]','望闊真多思，憑高更損神。',48,'全唐诗/poet.song.66000.json','["望闊真多思，憑高更損神。", "山川散白日，草木共青春。", "寂寂興亡事，悠悠來往人。", "素衣吳白紵，盡化洛陽塵。"]'),
('3a9cf3cd-fd1e-453b-8394-a2a9d2883fdc','正月十八日晴霽登柯眺望二首  其一','張耒','宋','宋诗','song-poetry','','[]','柯山通細履，幽步近青紅。',48,'全唐诗/poet.song.66000.json','["柯山通細履，幽步近青紅。", "送目無窮浪，吹花盡日風。", "餘生付沮溺，高論看夔龍。", "陳許春多雪，吾行亦欲東。"]'),
('d5937fa8-ab84-4feb-a007-bf90f798f4e8','正月十八日晴霽登柯眺望二首  其二','張耒','宋','宋诗','song-poetry','','[]','寂寂池亭古，園荒草自春。',48,'全唐诗/poet.song.66000.json','["寂寂池亭古，園荒草自春。", "東風獨游客，遲日未歸人。", "久雨衆山晦，初晴萬境新。", "長歌視天壤，高興不無人。"]'),
('9f363e5f-bcf9-4066-81c7-5bc57ffb5013','在告家居示內','張耒','宋','宋诗','song-poetry','','[]','雖云官事簡，不似在家安。',48,'全唐诗/poet.song.66000.json','["雖云官事簡，不似在家安。", "晏晏婦子語，嬉嬉兒稚閑。", "甘餐失粗糲，獨酌置杯槃。", "老覺偎綏好，莫將年少看。"]'),
('d45ac7ea-9e5f-4eff-adfe-9f0695b44536','寒食日同婦子輩東園小宴','張耒','宋','宋诗','song-poetry','','[]','寒食無與樂，携孥宴小園。',48,'全唐诗/poet.song.66000.json','["寒食無與樂，携孥宴小園。", "青春積雨霽，白日萬花繁。", "時節悲江國，窮愁泥酒尊。", "故鄉終在眼，樂不得重論。"]'),
('6f0de144-3fd5-483b-ae6a-4f80c8e2446c','東堂夜坐偶成示秬秸和','張耒','宋','宋诗','song-poetry','','[]','東堂歲云暮，永夜有餘清。',48,'全唐诗/poet.song.66000.json','["東堂歲云暮，永夜有餘清。", "月暗雁程急，霜嚴雞夢驚。", "微明旁舍火，斷續戍樓更。", "老眼渾無睡，偏聞曉雨聲。"]'),
('d0eb7c78-748d-4368-88be-9dd9f77ca5e6','同晁郎及秬秸步游乾明晚逾柯山歸','張耒','宋','宋诗','song-poetry','','[]','野水菰蒲秀，荒陂薺麥長。',48,'全唐诗/poet.song.66000.json','["野水菰蒲秀，荒陂薺麥長。", "卑田留積雨，荒寺掩斜陽。", "遠樹連雲夢，群山近武昌。", "言歸日已夕，村徑度牛羊。"]'),
('25137aca-52ab-481c-aa59-0c0e8e1b5348','斷雲','張耒','宋','宋诗','song-poetry','','[]','斷雲秋望闊，山靄夕成霞。',48,'全唐诗/poet.song.66000.json','["斷雲秋望闊，山靄夕成霞。", "凄冷初高月，喧闐未定鴉。", "伏羈良馬瘦，挂壁寶月斜。", "寂寂山城夜，明燈照鬢華。"]'),
('e5cf88c4-dfb1-42e5-b096-8b55b59fe287','秀蔓','張耒','宋','宋诗','song-poetry','','[]','秀蔓依簷老，寒枝映屋疏。',48,'全唐诗/poet.song.66000.json','["秀蔓依簷老，寒枝映屋疏。", "寒暄候蟲報，昏旦老雞呼。", "已飯新收稻，仍烹自種蔬。", "鄰邦有佳釀，衝雨隔江沽。"]'),
('4b5148b1-46bc-4a8d-bf21-62edc286b15a','謁敬亭祠','張耒','宋','宋诗','song-poetry','','[]','古廟依山麓，開門石磴深。',48,'全唐诗/poet.song.66000.json','["古廟依山麓，開門石磴深。", "疏林歸鳴鳥，野殿宿寒陰。", "落日魚鹽市，豐年簫鼓音。", "我來無所禱，壁宇歎塵侵。"]'),
('6923511f-6d3c-4f11-9345-2e99434eeeee','謁告之楚出都晚泊','張耒','宋','宋诗','song-poetry','','[]','馬跡不在眼，浪聲初泊船。',48,'全唐诗/poet.song.66000.json','["馬跡不在眼，浪聲初泊船。", "蒼禾荒霽澤，紅樹表霜川。", "淮海南浮地，星辰北拱天。", "東方聊一飽，楚稻不論錢。"]'),
('70e302b8-a320-47cd-a75d-461bdbd93b85','晚泊襄邑','張耒','宋','宋诗','song-poetry','','[]','月暗風林靜，斗垂霜夜清。',48,'全唐诗/poet.song.66000.json','["月暗風林靜，斗垂霜夜清。", "疏燈隔樹小，暗水歷船鳴。", "學字聲形苦，紬書卜祝輕。", "此身南北慣，隨處有平生。"]'),
('61879b81-43d6-4b4d-b34f-176dbc9a4fe2','柘城道中','張耒','宋','宋诗','song-poetry','','[]','欲雪日易晚，不寒風更清。',48,'全唐诗/poet.song.66000.json','["欲雪日易晚，不寒風更清。", "崩橋斷官路，積水入空城。", "屏翳野初燒，降丘民始耕。", "冬暉疾如馬，汲汲暝猶征。"]'),
('52be225a-8583-40d6-b382-2689a45c3f5f','離陳至華西','張耒','宋','宋诗','song-poetry','','[]','落日照原隰，晚風吹客鞭。',48,'全唐诗/poet.song.66000.json','["落日照原隰，晚風吹客鞭。", "空巢霜後木，殘枿燒餘田。", "憔悴貧中客，蒼茫歲暮天。", "遠遊輕道路，無地息勞肩。"]'),
('ea187751-cec1-4c9f-a16c-49c8fbea7a1b','離宛丘斗門','張耒','宋','宋诗','song-poetry','','[]','檣烏映高柳，晚泊近晴川。',72,'全唐诗/poet.song.66000.json','["檣烏映高柳，晚泊近晴川。", "野日離烟樹，風霜斷夕天。", "牛羊知別塹，燈火認鄰船。", "獨客歸何晚，平蕪遠更連。", "孤城飛鳥外，春水片帆前。", "蕭瑟孤征恨，更深獨未眠。"]'),
('fcbc0665-9d11-44d8-941d-754ed217a1d6','二十二日立秋夜行泊林皇港二首  其一','張耒','宋','宋诗','song-poetry','','[]','蕭蕭晚風起，孤舟愁思生。',48,'全唐诗/poet.song.66000.json','["蕭蕭晚風起，孤舟愁思生。", "篷窗一螢過，葦岸數蛩鳴。", "老大畏爲客，風波難計程。", "家人夜深語，應念客猶征。"]'),
('df6699db-3e2e-47a8-9ec1-143dfae22f51','二十二日立秋夜行泊林皇港二首  其二','張耒','宋','宋诗','song-poetry','','[]','吳楚封疆接，東南澤國寬。',48,'全唐诗/poet.song.66000.json','["吳楚封疆接，東南澤國寬。", "江流秋日盡，山對暮雲閑。", "囊有離騷賦，頭餘騎省斑。", "前秋聊把酒，一笑且開筵。"]'),
('cfe9be59-061b-4a10-b23b-e54cf7722f77','四安道中','張耒','宋','宋诗','song-poetry','','[]','地平彌望水，舟穩滿帆風。',48,'全唐诗/poet.song.66000.json','["地平彌望水，舟穩滿帆風。", "黄葉新霜後，青山落照中。", "封疆天象別，風俗島夷同。", "黯黯危橋夜，疏燈照閉蓬。"]'),
('6fc17f37-fe36-4107-bbf8-ae32b2a3aeb3','赴宣城守吳興道中','張耒','宋','宋诗','song-poetry','','[]','秋野連雲靜，三吳稻熟時。',48,'全唐诗/poet.song.66000.json','["秋野連雲靜，三吳稻熟時。", "風江客帆疾，晴野雁行遲。", "草木霜天晚，山川澤國卑。", "宣城不負汝，好繼謝公詩。"]'),
('d8d98c0a-c536-4bd4-9a2b-6b7040f570e9','白羊道中二首  其一','張耒','宋','宋诗','song-poetry','','[]','徒旅已屢憩，過山知幾峰。',48,'全唐诗/poet.song.66000.json','["徒旅已屢憩，過山知幾峰。", "空畦鳴野水，壞道拱寒松。", "醁酒自能暖，褐裘初御冬。", "朝饑久未食，林寺已鳴鐘。"]'),
('4b209824-e373-43c8-82ee-cdacaf9e45e2','白羊道中二首  其二','張耒','宋','宋诗','song-poetry','','[]','日出客心喜，路平人足輕。',48,'全唐诗/poet.song.66000.json','["日出客心喜，路平人足輕。", "風高不成冷，雨過有餘清。", "水落溪魚出，村深田鸛鳴。", "勝遊須秀句，多愧謝宣城。"]'),
('95142260-d9cb-4b0c-ac96-fa489daaa2ae','驅馬','張耒','宋','宋诗','song-poetry','','[]','駸駸驅馬去，秋晚思悠哉。',48,'全唐诗/poet.song.66000.json','["駸駸驅馬去，秋晚思悠哉。", "日暖禾黍熟，霜晴鴻雁來。", "晚篁經雨出，幽菊犯寒開。", "官冷無拘束，尋山首易迴。"]'),
('d9c4336b-d1a5-41b1-81a0-5c4491b19944','楮河','張耒','宋','宋诗','song-poetry','','[]','土壁裂如削，流泉漱雨間。',48,'全唐诗/poet.song.66000.json','["土壁裂如削，流泉漱雨間。", "平沙放清淺，小石聚潺湲。", "絕岸木斜出，隔橋人暮還。", "憑鞍照毛髮，羈旅易衰顔。"]'),
('a9fe8079-2ddd-47ea-b231-cf63ab634626','惠莊道中','張耒','宋','宋诗','song-poetry','','[]','山雨夜塵息，林霜晨氣清。',48,'全唐诗/poet.song.66000.json','["山雨夜塵息，林霜晨氣清。", "荒城餘古木，破冢有新耕。", "風俗通秦壤，川原抱洛京。", "憑高時駐馬，指點問山名。"]'),
('39ff00f5-de1f-4dc3-860d-807d1ec400da','山行','張耒','宋','宋诗','song-poetry','','[]','驅馬春山去，山蹊繞澗斜。',48,'全唐诗/poet.song.66000.json','["驅馬春山去，山蹊繞澗斜。", "淺清沙岸水，疏瘦石岩花。", "放蕩從生事，殷勤向物華。", "依微聽雞犬，深柳映人家。"]'),
('4795f252-9122-4e70-beb9-966e408564e0','子權朝散久在蕪湖寄郡酒四壺副以小詩','張耒','宋','宋诗','song-poetry','','[]','寒流不相待，舟楫定何如。',48,'全唐诗/poet.song.66000.json','["寒流不相待，舟楫定何如。", "歲事日已宴，客行誰與娛。", "淮魚將入饌，江酒且傾壺。", "我似離群雁，汀洲片影無。"]'),
('05314693-1fca-4358-9ae5-9a8f8897662e','務中晚作','張耒','宋','宋诗','song-poetry','','[]','官事一酒甕，寢齋低竹簷。',48,'全唐诗/poet.song.66000.json','["官事一酒甕，寢齋低竹簷。", "朝昏睡過半，老病醉相兼。", "樓晚雙旂裊，城昏疊鼓嚴。", "隔江吹笛處，空碧帖新蟾。"]'),
('ce354887-a5ff-447b-a4e6-4953c3f9dd10','齊安秋日','張耒','宋','宋诗','song-poetry','','[]','齊安荒僻郡，平昔處放臣。',48,'全唐诗/poet.song.66000.json','["齊安荒僻郡，平昔處放臣。", "幸此公酒美，復此高秋晨。", "百憂雖搶攘，一榼奈芳醇。", "舉杯三酌後，遙作葛天民。"]'),
('f47c91e1-8418-4883-a8d0-749ac8613242','書直舍','張耒','宋','宋诗','song-poetry','','[]','爲官不治民，清坐晚秋晨。',48,'全唐诗/poet.song.66000.json','["爲官不治民，清坐晚秋晨。", "隨事文書了，偷閑筆硯親。", "吏歸雅集定，門鎖月華新。", "野鳥何勞問，窮通理有神。"]'),
('c12ff315-3b93-4ef0-a8bf-8255a0b877c5','晨起雨霽作','張耒','宋','宋诗','song-poetry','','[]','寂寂柯山曲，悠悠放逐臣。',48,'全唐诗/poet.song.66000.json','["寂寂柯山曲，悠悠放逐臣。", "雨晴人踏曉，山靜鳥啼春。", "最惜庭梅謝，猶欣壠麥新。", "但知年歲好，飽飯任乾坤。"]'),
('8acea53d-fd87-42d7-8c4f-37c9a234f3c0','永寧遣興三首  其一','張耒','宋','宋诗','song-poetry','','[]','國破空陵墓，時移改要衝。',48,'全唐诗/poet.song.66000.json','["國破空陵墓，時移改要衝。", "人隨幽谷路，縣隠亂山峰。", "零落荒祠樹，悠揚晚寺鐘。", "猶傳仙舊隠，跨鹿有遺蹤。"]'),
('78049609-d51f-46e5-b817-1e7302f464e0','永寧遣興三首  其二','張耒','宋','宋诗','song-poetry','','[]','朱顔潘令尹，不肯事輕肥。',48,'全唐诗/poet.song.66000.json','["朱顔潘令尹，不肯事輕肥。", "筍逕青無地，苔牆綠有衣。", "書勤枯簡斷，詩疾紫毫飛。", "應笑疏慵尉，朝游暮醉歸。"]'),
('f8960b15-b9f1-453f-b13f-b31cedc5dfd6','永寧遣興三首  其三','張耒','宋','宋诗','song-poetry','','[]','花縣春曾到，人家幽谷間。',48,'全唐诗/poet.song.66000.json','["花縣春曾到，人家幽谷間。", "市門猶礙石，耕壠盡依山。", "地僻荆榛秀，人稀魚鳥閑。", "頼逢賢令尹，沉醉不知還。"]'),
('6a673d70-c47d-49aa-9e20-fbc5f77233fa','寄文剛求蟹','張耒','宋','宋诗','song-poetry','','[]','遙知漣水蟹，九月已經霜。',48,'全唐诗/poet.song.66000.json','["遙知漣水蟹，九月已經霜。", "筐實黄金重，螯肥白玉香。", "塵埃離故國，詩酒寄他鄉。", "苦乏西來使，何緣至洛陽。"]'),
('9c2cf04c-687e-464b-a76d-be9012d814f9','雙鳬','張耒','宋','宋诗','song-poetry','','[]','雙鳬元自白，况乃小池清。',48,'全唐诗/poet.song.66000.json','["雙鳬元自白，况乃小池清。", "逐伴知身潔，當庭獨眼明。", "暖沙晴共戲，寒渚夜多驚。", "何事秋風起，軒然向主鳴。"]'),
('bb75e289-53ba-42da-9aca-e924c76b53ba','代人上潁川韓端明生日','張耒','宋','宋诗','song-poetry','','[]','實歷休明運，金貂將相門。',288,'全唐诗/poet.song.66000.json','["實歷休明運，金貂將相門。", "産材皆巨植，流慶出深源。", "世仰風規舊，公膺戩穀繁。", "人間見麟鳳，天路引鵬鯤。", "諸老推淵懿，英儒伏討論。", "韋平家學盛，黄綺帝師尊。", "天步開華旦，離明照厚坤。", "曳裾趨法從，操筆代王言。", "諫說傾朝聽，公忠報主恩。", "高風何凜凜，讜議在元元。", "夷險千途歷，清明一志存。", "寶圭純不琢，秋漢闊無渾。", "鳴佩登書殿，均勞鎮輔藩。", "洪樞歸少第，玉節對元昆。", "臘報新春近，陽生厚地溫。", "當年占夢寐，此日降璵璠。", "賀宴開瑶席，陳庭列壽尊。", "簪纓羅盛族，蘭玉立諸孫。", "霜鶴寒逾健，岩松老更蕃。", "人祈賢相雨，國倚太師垣。", "留滯瞻雲館，飛馳有去魂。", "微官守山邑，無路走賓軒。", "中外心方注，君臣契已敦。", "佇觀登輔弼，飛潤及孤根。"]'),
('2ac0fbae-7e85-469a-92ff-f638289a9047','魯直示其伯父祖善馬鞍松隠齋詩次其韵','張耒','宋','宋诗','song-poetry','','[]','老鶴閱世久，歸來毛骨寒。',48,'全唐诗/poet.song.66000.json','["老鶴閱世久，歸來毛骨寒。", "田園半拱木，兒稚總勝冠。", "愛客能酤酒，尋山不跨鞍。", "平生未見面，試作阿咸看。"]'),
('d9723827-7fc0-4417-9e8d-43457d506878','次韵孔舍人曝書','張耒','宋','宋诗','song-poetry','','[]','圖書陳秘奧，樽俎肆雍容。',48,'全唐诗/poet.song.66000.json','["圖書陳秘奧，樽俎肆雍容。", "玉殿朝回客，蓬山深處峰。", "探囊圖軸舊，題壁姓名重。", "盛世年年事，新篇莫厭供。"]'),
('5cbfe6cf-1456-4f26-bb19-ee4129d26894','夜讀賈長江詩效其體','張耒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','五字一篇詩，人傳賈島詞。',48,'全唐诗/poet.song.66000.json','["五字一篇詩，人傳賈島詞。", "清秋千古在，幽淡幾人知。", "霜夜燈前讀，林間靜處思。", "恍然如見面，更對七朱絲。"]'),
('9f8b1e09-321c-4946-9b50-02ac121ea735','和天啟畫古木山石詩','張耒','宋','宋诗','song-poetry','','[]','有待雲雨在，無傷斤斧餘。',48,'全唐诗/poet.song.66000.json','["有待雲雨在，無傷斤斧餘。", "將軍漫弓箭，居士或眉須。", "缺記共工怒，深資夸父腴。", "攀條感衰變，恨汝亦非夫。"]'),
('9dc0cf28-26e0-4e37-8e94-498001ce0c5d','少年','張耒','宋','宋诗','song-poetry','','[]','朱繩縛天狗，白羽射旄頭。',48,'全唐诗/poet.song.66000.json','["朱繩縛天狗，白羽射旄頭。", "新佩將軍印，初成甲第樓。", "綺羅諸院夜，鞍馬五陵秋。", "惟有如霜鬢，令君覽鏡愁。"]'),
('33c7d292-69e2-4826-a089-366be29078a4','暮春游柯市人家有作','張耒','宋','宋诗','song-poetry','','[]','桃李雖云過，林塘老景濃。',48,'全唐诗/poet.song.66000.json','["桃李雖云過，林塘老景濃。", "幽花冠曉露，高柳旆和風。", "草木家家秀，溝壑處處通。", "况聞如雨足，高枕待年豐。"]'),
('44c76ba2-0cd5-4485-a6bb-2b05e543e2ff','秋日游柯市','張耒','宋','宋诗','song-poetry','','[]','柯市漁樵暮，游人落落稀。',48,'全唐诗/poet.song.66000.json','["柯市漁樵暮，游人落落稀。", "肩禾新穫野，炷火欲鳴機。", "草木經寒雨，川原淡夕暉。", "北歸吾敢必，身世正多違。"]'),
('9c953b8d-9f12-4141-8656-51b1dd2ea1c0','手種芭蕉秋來特盛成二大叢','張耒','宋','宋诗','song-poetry','','[]','移植自磽瘠，秋來成兩叢。',48,'全唐诗/poet.song.66000.json','["移植自磽瘠，秋來成兩叢。", "翠旌舒曉日，綠錦障西風。", "雨砌珠珮委，風簷翬扇重。", "主人培壅厚，未肯畏嚴冬。"]'),
('05895ec5-a4ea-4c1e-a18c-5eda44df8e0c','山舍','張耒','宋','宋诗','song-poetry','','[]','蕭蕭山舍靜，誰復與相親。',48,'全唐诗/poet.song.66000.json','["蕭蕭山舍靜，誰復與相親。", "琴酒忘塵事，詩書有古人。", "歲豐民事少，地闢土風淳。", "聊樂身無事，功名喪我真。"]'),
('01189e0c-38a3-4f03-b228-16ca86df33b6','秋夜','張耒','宋','宋诗','song-poetry','','[]','月到啼蛩壁，風摇睡鵲枝。',48,'全唐诗/poet.song.66000.json','["月到啼蛩壁，風摇睡鵲枝。", "秋來客不寐，遙夜漏何遲。", "已近風霜節，寂無蚊蚋時。", "天時只自爾，浪遣宋生悲。"]'),
('2cc33b29-26c7-40f1-b30c-67e6dcb19315','寂寂','張耒','宋','宋诗','song-poetry','','[]','寂寂秋日暮，輝輝簷影斜。',48,'全唐诗/poet.song.66000.json','["寂寂秋日暮，輝輝簷影斜。", "鳴蟲隠衰蔓，晚蝶守餘花。", "雨急荷翻葉，牆崩竹引芽。", "不才非吏隠，雞黍學山家。"]'),
('a54eb118-44b0-4e18-a4e7-e5e1a205aec2','即事','張耒','宋','宋诗','song-poetry','','[]','雨枿生朝菌，秋牆長若邪。',48,'全唐诗/poet.song.66000.json','["雨枿生朝菌，秋牆長若邪。", "槐榆蔽窮巷，藜藋接鄰家。", "但願好事酒，無勞長者車。", "御冬須旨蓄，吾亦問生涯。"]'),
('e6fa716a-29b5-4019-8254-84a22a51df0d','落莫','張耒','宋','宋诗','song-poetry','','[]','歲晚苦落莫，獨遊情易傷。',48,'全唐诗/poet.song.66000.json','["歲晚苦落莫，獨遊情易傷。", "晴溪沙漾碧，秋徑葉鋪黄。", "幽菊開經雨，疏槐老奈霜。", "閉門無俗客，攄散有林塘。"]'),
('72eec99a-ec6d-45c2-b458-ef3f9d977395','冬日雜書六首  其一','張耒','宋','宋诗','song-poetry','','[]','地僻秋將老，山深客未歸。',48,'全唐诗/poet.song.66000.json','["地僻秋將老，山深客未歸。", "閉門朝對雨，搜篋冷添衣。", "圖暗經陰畫，琴昏在匣徽。", "妻孥慣山藪，不復問珠璣。"]'),
('811aaa0e-0b04-4a80-945c-d90622430cb1','冬日雜書六首  其二','張耒','宋','宋诗','song-poetry','','[]','歲暮北風疾，山深寒日昏。',48,'全唐诗/poet.song.66000.json','["歲暮北風疾，山深寒日昏。", "授衣貧厭補，添纊老須溫。", "懶慢拋書卷，晴明到藥園。", "鄰家新酒熟，吾敢但空樽。"]'),
('d0e1d6ab-305c-4859-9e58-8e3589890d22','冬日雜書六首  其三','張耒','宋','宋诗','song-poetry','','[]','一逕秋風起，牛羊晚自歸。',48,'全唐诗/poet.song.66000.json','["一逕秋風起，牛羊晚自歸。", "寒燈明野店，吠犬守荆扉。", "空峽風霜急，孤村火燭微。", "庭梧摇落盡，栖鳥夜歸稀。"]'),
('e2fe66d8-b013-4bb8-84db-d211ddaf6b1b','冬日雜書六首  其四','張耒','宋','宋诗','song-poetry','','[]','歲暮周南遠，驚心鬢欲絲。',48,'全唐诗/poet.song.66000.json','["歲暮周南遠，驚心鬢欲絲。", "風霜爲客老，淮海寄書遲。", "峽冷重雲夜，天昏斷雁悲。", "山爐通夕火，頼爾獨吾私。"]'),
('44b9123d-469a-423c-896e-e71dbff161a1','冬日雜書六首  其五','張耒','宋','宋诗','song-poetry','','[]','短景冰霜地，人稀豹虎村。',48,'全唐诗/poet.song.66000.json','["短景冰霜地，人稀豹虎村。", "風連諸壑動，日带亂山昏。", "浩蕩空回首，蕭條獨掩門。", "東周舊耆老，留滯飽知聞。"]'),
('21582dc8-9148-4225-b86d-125f6d76bc60','冬日雜書六首  其六','張耒','宋','宋诗','song-poetry','','[]','望極添秋思，樓高動旅懷。',48,'全唐诗/poet.song.66000.json','["望極添秋思，樓高動旅懷。", "天寒諸瀨急，野闊四山來。", "餘葉能幾許，高鴻殊未迴。", "年年洛陽道，歲晚厭風埃。"]'),
('e1c7f4f1-c11e-4048-a541-65137172292e','出都之宛丘贈寄參寥','張耒','宋','宋诗','song-poetry','','[]','蕭然耳目清，驅馬別都城。',48,'全唐诗/poet.song.66000.json','["蕭然耳目清，驅馬別都城。", "岸斷秋光出，川平雨氣橫。", "浮生歸物理，閑景付詩情。", "歲晚江湖客，何爲滯玉京。"]'),
('321a0e8a-7b33-4c3f-b3a9-90a5db8e6371','和葺西齋','張耒','宋','宋诗','song-poetry','','[]','川舟真有待，勿歎滯塘坳。',48,'全唐诗/poet.song.66000.json','["川舟真有待，勿歎滯塘坳。", "自古荆榛地，豈容鸞鳳巢。", "君才宜柱石，我志老衡茅。", "從此延風月，新詩與細嘲。"]'),
('5a58510c-ce0f-4a49-b805-4f606e2a63e6','同戚郎夜飲','張耒','宋','宋诗','song-poetry','','[]','雲物歲將暮，風烟晚自凄。',48,'全唐诗/poet.song.66000.json','["雲物歲將暮，風烟晚自凄。", "更人初授宿，晚翼已歸栖。", "美酒淺深酌，新詩取次題。", "親交盡在眼，幸不費招携。"]'),
('bfe378ca-2330-4cb0-80ab-42be37295014','春日','張耒','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u601d\u4e61", "\u5199\u666f", "\u5b8b\u8bd7"]','如絲苣甲飣春盤，韭葉金黄雪未乾。',64,'全唐诗/poet.song.66000.json','["如絲苣甲飣春盤，韭葉金黄雪未乾。", "旅飯二年無此味，故園千里幾時還。", "異方時節三巵酒，殘歲風烟一慘顔。", "曾奉龍旂典邦禮，歲窮祠祀少休閑。"]'),
('2abe9d80-f214-4855-a196-dae178811f04','晚望','張耒','宋','宋诗','song-poetry','','[]','長林脫葉委高風，晚菊依依發舊叢。',64,'全唐诗/poet.song.66000.json','["長林脫葉委高風，晚菊依依發舊叢。", "夢澤雲低銜落日，中洲山斷見來鴻。", "行吟騷客三年謫，嗜酒衰翁百事慵。", "歲晚不須求季主，從來天理有窮通。"]'),
('6134a9d7-eb85-4765-8dc6-cdd78d17cd08','四月二十日書二首  其一','張耒','宋','宋诗','song-poetry','','[]','十步荒園亦懶窺，枕書小醉睡移時。',64,'全唐诗/poet.song.66000.json','["十步荒園亦懶窺，枕書小醉睡移時。", "健如黄犢時無幾，鈍似寒蠅老自知。", "休惜飛馳春過眼，但求强健酒盈巵。", "枇杷著子紅榴綻，正是清和未暑時。"]'),
('28165baf-c8a7-4c62-8968-08a8d0746c9e','四月二十日書二首  其二','張耒','宋','宋诗','song-poetry','','[]','久將醉眼視羣兒，只與旁觀作笑嘻。',64,'全唐诗/poet.song.66000.json','["久將醉眼視羣兒，只與旁觀作笑嘻。", "賦芋狙公曾未悟，牽絲木偶幾多時。", "雲間炎景人方畏，地下微陰誰得知。", "榮謝古今同此理，老翁端坐但忘機。"]'),
('6dd0b84a-a18c-4a59-9b88-b07b80792f0a','早起觀雨','張耒','宋','宋诗','song-poetry','','[]','雨葉風枝日夜長，東園穠密欲生光。',64,'全唐诗/poet.song.66000.json','["雨葉風枝日夜長，東園穠密欲生光。", "可憐積雨過初暑，更轉餘寒作曉凉。", "蠶事已成家媼喜，麥畦初潑老農忙。", "綵絲結縷催端午，又見黄頭鼓楫郎。"]'),
('515579f0-b24e-4d94-9197-2d475509d8f9','十二月十七日移病家居成五長句  其一','張耒','宋','宋诗','song-poetry','','[]','水國窮冬猶未雪，木牙草色似春餘。',64,'全唐诗/poet.song.66000.json','["水國窮冬猶未雪，木牙草色似春餘。", "醫教治嗽停朝飲，目爲方眠廢夜書。", "衆醉羞隨人鼓舞，天知誰怕鬼揶揄。", "久已率野由吾道，又信從來德不孤。"]'),
('49a7d4e4-66c3-4bed-99a8-6b2efdbe1a54','十二月十七日移病家居成五長句  其二','張耒','宋','宋诗','song-poetry','','[]','老去塵懷痛洗煎，虛舟不繫任回沿。',64,'全唐诗/poet.song.66000.json','["老去塵懷痛洗煎，虛舟不繫任回沿。", "寸心若變有如日，萬事不憂終在天。", "莫爲饑寒棄南畝，須知穮蔉有豐年。", "桃符侲子喧閭巷，又向江城十歲捐。"]'),
('4312aa01-cd9a-48e3-af54-50706350cc2e','十二月十七日移病家居成五長句  其三','張耒','宋','宋诗','song-poetry','','[]','憑高游目快遐瞻，落日孤雲與水兼。',64,'全唐诗/poet.song.66000.json','["憑高游目快遐瞻，落日孤雲與水兼。", "萬頃澤空供雪意，一枝梅笑破冬嚴。", "擎蒼未減飛揚興，引滿何辭斗石添。", "楊柳催春兼警客，荒溝照影弄纖纖。"]'),
('214475d3-e3fb-4705-86ee-559530fa1539','十二月十七日移病家居成五長句  其四','張耒','宋','宋诗','song-poetry','','[]','從今羞復走功名，鹵莽因循已半生。',64,'全唐诗/poet.song.66000.json','["從今羞復走功名，鹵莽因循已半生。", "心遣我愚應有謂，眼看人智亦何成。", "夢爲蝴蝶因觀化，目送飛鴻漫寄情。", "堪笑妻兒懷土甚，謫期未滿已謀行。"]'),
('8ce4b5b6-38c7-4c47-a267-09edb620aafa','十二月十七日移病家居成五長句  其五','張耒','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','紙窗低下火爐邊，有底宜人意若便。',64,'全唐诗/poet.song.66000.json','["紙窗低下火爐邊，有底宜人意若便。", "移疾何妨閑五日，放慵猶欲醉終年。", "平生親友懷天末，談笑妻兒在目前。", "誰似匡廬白居士，暮年華髮洛陽仙。"]'),
('f00505af-9601-422c-a063-49a574588546','寒食前一日大雨不止','張耒','宋','宋诗','song-poetry','','[]','寒食窮愁嘆陋邦，可憐終日雨淙淙。',64,'全唐诗/poet.song.66000.json','["寒食窮愁嘆陋邦，可憐終日雨淙淙。", "不妨農畝連雲稼，獨惜園花脫錦杠。", "最苦繁聲欺屋漏，願看霽色放春江。", "明朝日出誰能料，已喜燈花照夜窗。"]'),
('3a286028-c814-4a75-b62a-ab6b959d8efd','喜雨贈潘邠老昆仲','張耒','宋','宋诗','song-poetry','','[]','卧聞飛雨響高堂，已覺翛翛短幌凉。',64,'全唐诗/poet.song.66000.json','["卧聞飛雨響高堂，已覺翛翛短幌凉。", "悔禍畢方收烈燄，知時田祖放新秧。", "簞瓢幸免遷三徑，穀麥行看糶萬箱。", "欲過東坡泥沒脚，春餘烟柳正蒼蒼。"]'),
('4ef628bb-c72e-4dd2-b45b-6eaeeefabec6','和蘇仲南柳湖會飲','張耒','宋','宋诗','song-poetry','','[]','北風閣雪不到地，寒日自同雲外天。',64,'全唐诗/poet.song.66000.json','["北風閣雪不到地，寒日自同雲外天。", "愁人得酒百不問，滿引聊作諸公先。", "少休歌舞進棋局，更放旌旗移樓船。", "我欲吳歌恐驚坐，戲揮如意扣船舷。"]'),
('4f019c10-22e3-44f8-af8e-e9a3d9098da1','夜霜','張耒','宋','宋诗','song-poetry','','[]','夜霜偏警軍城角，晚日如催林寺鐘。',64,'全唐诗/poet.song.66000.json','["夜霜偏警軍城角，晚日如催林寺鐘。", "蹭蹬此身甘已老，推遷世事本無窮。", "邯鄲夢裏忘將寤，蠻觸軍中尚戰雄。", "我有一言開達者，到頭可倚是天公。"]'),
('da4a00e0-3606-4614-810a-dec5062b97e6','十月二十日夜大雨雹震電先是數日極暖至是方稍晴','張耒','宋','宋诗','song-poetry','','[]','江鄉節候異中州，十月狂雷震未休。',64,'全唐诗/poet.song.66000.json','["江鄉節候異中州，十月狂雷震未休。", "二年到耳同常事，一夜雨聲如蚤秋。", "想見麥畦添宿潤，更欣蔬甲長新柔。", "東堂晚望無氛祲，洗出樊山紫翠浮。"]'),
('a65650f6-2dcb-4619-b99c-51e837f889d7','晨興自籬西望東園新開花','張耒','宋','宋诗','song-poetry','','[]','東園本是吾家有，不到經旬亦可嗟。',64,'全唐诗/poet.song.66000.json','["東園本是吾家有，不到經旬亦可嗟。", "步出寢門迎曉日，却從籬外望新花。", "安禪豈問荒三徑，閱古終須飽五車。", "兒女相憐牢落甚，爲翁淺盞酌流霞。"]'),
('e12a51eb-80c4-4a2f-ac57-5f6c0ee4ae6f','潘大臨蓮池二首  其一','張耒','宋','宋诗','song-poetry','','[]','避暑人人得自怡，坐曹最苦劇囚纍。',64,'全唐诗/poet.song.66000.json','["避暑人人得自怡，坐曹最苦劇囚纍。", "江邊金石焦流日，堂上糟漿酷烈時。", "一酌甘寒煩素綆，終朝揮拂倦蒲葵。", "誰知顔巷簞瓢外，更有秋風菡萏池。"]'),
('9d0200bf-0c9a-4485-b434-dea15fbb0eb9','潘大臨蓮池二首  其二','張耒','宋','宋诗','song-poetry','','[]','年年酷暑軫皇慈，恩詔猶矜庶獄纍。',64,'全唐诗/poet.song.66000.json','["年年酷暑軫皇慈，恩詔猶矜庶獄纍。", "白首坐曹真有罪，清風高枕歎無時。", "乘軒敢望終如鶴，用智從前不及葵。", "他日東門驅匹馬，故應難忘習家池。"]'),
('6bf4848b-9604-41ab-8fca-5ac92c5a8747','九月末大風一夕遂安置火爐有感二首  其一','張耒','宋','宋诗','song-poetry','','[]','謫官兩向黄州火，知是明年何處冬。',64,'全唐诗/poet.song.66000.json','["謫官兩向黄州火，知是明年何處冬。", "須信炎凉相代至，亦知榮辱到頭空。", "怨咨莫起天公念，燕坐何妨佛理通。", "更有牆邊一樽酒，能於愁面放春紅。"]'),
('5bb7cd4c-5e4f-4053-9334-c2a1b28331e8','九月末大風一夕遂安置火爐有感二首  其二','張耒','宋','宋诗','song-poetry','','[]','風聲一夜下林端，遽作霜天十月寒。',64,'全唐诗/poet.song.66000.json','["風聲一夜下林端，遽作霜天十月寒。", "三伏炎蒸不可過，北風栗烈亦何難。", "人情何待常從緩，天令難移古不刊。", "幸有布裘氈履在，雪深高卧更安閑。"]'),
('c6adbe0d-0ee5-49ad-a331-c183d6cd200e','冬至贈潘郎','張耒','宋','宋诗','song-poetry','','[]','曉鏡星星華髮新，江山流落未歸人。',64,'全唐诗/poet.song.66000.json','["曉鏡星星華髮新，江山流落未歸人。", "五紋暗度人間線，九寸潜通地下春。", "歌笑欣欣環老稚，杯盤草草稱清貧。", "與君同是柯山客，窗外梅花解笑人。"]'),
('414b726c-bfed-4983-9034-02311af3db9c','丁丑歲與德載相別辛巳復會於潁相視而歎仍蒙先惠佳句謹次韵','張耒','宋','宋诗','song-poetry','','[]','重入修門一見春，衰容仍是卧漳濱。',64,'全唐诗/poet.song.66000.json','["重入修門一見春，衰容仍是卧漳濱。", "歸來未解纍囚服，揮去真同下坂輪。", "痛飲久無連夜醉，白頭何啻二毛新。", "□□□□□□□，□□□□□□□。"]'),
('e2a34a35-e966-4f18-b77d-eb45d77a1e92','寓居春日書事','張耒','宋','宋诗','song-poetry','','[]','禪宮寂寂白晝長，出門江山悲異鄉。',64,'全唐诗/poet.song.66000.json','["禪宮寂寂白晝長，出門江山悲異鄉。", "歌簷日暖好鳥語，空庭客稀春草長。", "紅樹人家隔修竹，青蕪村路達橫塘。", "欲向東城踏青去，碧雲何處水茫茫。"]'),
('a78ab0e7-b6c4-4c9d-a388-c3babc7e4c6f','臘日二首  其一','張耒','宋','宋诗','song-poetry','','[]','臘日開門雪滿山，愁陰短景歲將闌。',64,'全唐诗/poet.song.66000.json','["臘日開門雪滿山，愁陰短景歲將闌。", "江梅飄落香元在，汀雁飛鳴意已還。", "佳節再逢身且健，一樽相屬鬢毛斑。", "明光起草真榮事，寂寂衡門我自閑。"]'),
('b7caeaed-89cb-4ffb-89ca-ea6da4158f1f','臘日二首  其二','張耒','宋','宋诗','song-poetry','','[]','異鄉懷舊人千里，勝日難忘酒一杯。',64,'全唐诗/poet.song.66000.json','["異鄉懷舊人千里，勝日難忘酒一杯。", "不恨北風催短景，最憐殘雪冷疏梅。", "江邊寒色雁催盡，天上春光斗挹回。", "我獨呼兒剩丸藥，微功聊取助衰骸。"]'),
('6ee6e406-947f-448e-acc3-f25d39db03ce','偶成題裴晉公祠','張耒','宋','宋诗','song-poetry','','[]','獨持將鉞靜氛妖，後世英名日月昭。',64,'全唐诗/poet.song.66000.json','["獨持將鉞靜氛妖，後世英名日月昭。", "善聽聖君非易遇，將亡凶豎不難梟。", "悲風蔓草移今古，野殿空庭鎖寂寥。", "更有從軍老司馬，銘功文字配咸韶。"]'),
('68802c16-3f59-4729-9e6c-0752f02d7728','冬日書事','張耒','宋','宋诗','song-poetry','','[]','昨夜新霜著瓦乾，西園梧葉盡飛翻。',64,'全唐诗/poet.song.66000.json','["昨夜新霜著瓦乾，西園梧葉盡飛翻。", "楚鄉原野長青草，澤國風雲只薄寒。", "梅蕊半含空有待，菊叢已過似無言。", "杖藜引望仍搔首，羨爾鳴鴻整羽翰。"]'),
('c0d9373a-4911-436b-b873-61c1a7a39aac','齊安今秋酒殊惡對岸武昌酒可飲故人潘主簿時惠雙榼','張耒','宋','宋诗','song-poetry','','[]','軍城曉鼓已蓬蓬，城下秋雲卷暮江。',64,'全唐诗/poet.song.66000.json','["軍城曉鼓已蓬蓬，城下秋雲卷暮江。", "祇有老雞能換卧，更無佳客可傾缸。", "衝風時動蕭蕭葉，晚日斜窺寂寂窗。", "猶喜江南有佳客，憐貧時致玉壺雙。"]'),
('21c94e13-0b94-42a4-8e13-7ee48af0f4fe','東堂即事','張耒','宋','宋诗','song-poetry','','[]','東堂歲晚直窮寂，落葉寒蔬風雨餘。',64,'全唐诗/poet.song.66000.json','["東堂歲晚直窮寂，落葉寒蔬風雨餘。", "下里數家同井臼，荒山十里半榛蕪。", "夜霜摧菊房俱斂，晴日薰梅氣欲蘇。", "誰似樊山偏得意，倚天紫翠照空虛。"]'),
('c3841247-2f21-4423-8dfb-8246494db18b','八月六日西風極凉如十月間晨起偶題','張耒','宋','宋诗','song-poetry','','[]','初過三伏暑初歸，風景誰知遽慘悽。',64,'全唐诗/poet.song.66000.json','["初過三伏暑初歸，風景誰知遽慘悽。", "短日旅愁消美酒，五更鄉夢託晨雞。", "江天水冷魚龍蟄，野澤風多鴻雁稀。", "塵篋敝貂猶得在，過冬偶免嘆無衣。"]'),
('3e0b3d80-86cd-4efc-9077-665129568b9e','正月三日大雪雪晴有感','張耒','宋','宋诗','song-poetry','','[]','平生對雪須千首，何事今春無片詞。',64,'全唐诗/poet.song.66000.json','["平生對雪須千首，何事今春無片詞。", "老大怯寒唯泥酒，窮愁須醉不吟詩。", "潤催庭柳將開眼，冷送江梅欲別枝。", "何處高樓有殘白，舊遊無處寄相思。"]'),
('b93e91c8-c89a-4ef2-8210-95ab8d99fe2c','雪晴','張耒','宋','宋诗','song-poetry','','[]','荒園雪晴愁徑滑，濕柴堅坐戀爐紅。',64,'全唐诗/poet.song.66000.json','["荒園雪晴愁徑滑，濕柴堅坐戀爐紅。", "寒香委地梅無頼，嫩坼抽苗麥有功。", "瘴癘潜消人氣樂，豐登定慰客途窮。", "暖寒破悶功無敵，頼有尊中臘酒醲。"]'),
('8e218883-ae3c-4ce0-bb59-28b010488f25','久陰忽晴作詩寄秬秸時二子沿幹在陽翟鎮','張耒','宋','宋诗','song-poetry','','[]','想爾扁舟野岸橫，久陰今旦喜晴明。',64,'全唐诗/poet.song.66000.json','["想爾扁舟野岸橫，久陰今旦喜晴明。", "天寒野曠北風利，雲霽江渾春水生。", "家近凍醪時可致，旅庖鳴雁足供烹。", "東園早作歸來計，紅紫紛紛日向榮。"]'),
('666e054c-1c90-4903-92cd-a2a1ec825e86','冬後三日郊赦到同郡官拜敕回有感','張耒','宋','宋诗','song-poetry','','[]','詔書夜下走風雷，清曉州門拜敕回。',64,'全唐诗/poet.song.66000.json','["詔書夜下走風雷，清曉州門拜敕回。", "天上六龍歸禁闕，人間一雨到根荄。", "江邊時日將舒柳，雪後春光欲到梅。", "白首放臣隨衆喜，教兒深酌手中杯。"]'),
('556010ac-d37a-468a-b203-1b4bd6dfc2db','探梅有感','張耒','宋','宋诗','song-poetry','','[]','澤畔騷人未放回，江邊又探臘前梅。',64,'全唐诗/poet.song.66000.json','["澤畔騷人未放回，江邊又探臘前梅。", "已知無木相先得，固使凌寒特地開。", "杜老閣前勞賦詠，玉川窗外獨驚猜。", "試思感舊傷千里，可以臨風舉一杯。"]'),
('528a6650-2c6a-4fc8-be16-3acc058324dd','三月十二日作詩董氏欲爲築堂','張耒','宋','宋诗','song-poetry','','[]','黄鳥聲中花已盡，綠楊風外日何長。',64,'全唐诗/poet.song.66000.json','["黄鳥聲中花已盡，綠楊風外日何長。", "柯家山下有幽築，雲夢澤南飛故鄉。", "老病裌衣猶怯冷，春深煮酒漸聞香。", "本無智術爭榮辱，只鬭尊前身健强。"]'),
('bf34b5ed-1c06-4ecd-a90e-c46798551712','草舍','張耒','宋','宋诗','song-poetry','','[]','草舍蘆藩百事貧，有時遇酒暫曛曛。',64,'全唐诗/poet.song.66000.json','["草舍蘆藩百事貧，有時遇酒暫曛曛。", "天邊日落未歸客，江上春寒多思人。", "寄遠相思時有夢，感時長嘯不無神。", "東風又欲催桃李，搔首花前獨岸巾。"]'),
('f46c67af-f13a-4a85-ab6e-fd7ed528d262','贈龐安常先生','張耒','宋','宋诗','song-poetry','','[]','德公本自隠襄陽，治病翻成客滿堂。',64,'全唐诗/poet.song.66000.json','["德公本自隠襄陽，治病翻成客滿堂。", "懶把窮通求日者，試將多病問醫王。", "一丸五色寧無藥，兩部千金合有方。", "他日傾河如石鼓，著書猶願記柴桑。"]'),
('444b998f-8f09-4b11-a585-39517492d223','三月二十四日聞鶯','張耒','宋','宋诗','song-poetry','','[]','桃蹊李逕有埃塵，寂寂青陰蔽四鄰。',64,'全唐诗/poet.song.66000.json','["桃蹊李逕有埃塵，寂寂青陰蔽四鄰。", "落月半窗幽夢斷，隔窗芳樹語鶯新。", "忽忘身是三年客，便覺樓瞻二室雲。", "佳境故人如一夢，懶將白髮望餘春。"]'),
('35fe86b1-4636-42f2-93ae-57d3714f25aa','柯山聞鵯鵊','張耒','宋','宋诗','song-poetry','','[]','三年不聽早朝雞，慚愧高林鵯鵊兒。',64,'全唐诗/poet.song.66000.json','["三年不聽早朝雞，慚愧高林鵯鵊兒。", "滿眼山林春已去，五更風露月沉西。", "厭聽田舍驅牛苦，想見天門寶馬嘶。", "獨我朦朧貪曉睡，故園門巷夢中迷。"]'),
('b19ac2ed-ba7d-4c10-aa2c-7b2dab8ea2da','齊安食蔞蒿根菊茁','張耒','宋','宋诗','song-poetry','','[]','故園蔬甲又逢春，想見雕槃巧鬭新。',64,'全唐诗/poet.song.66000.json','["故園蔬甲又逢春，想見雕槃巧鬭新。", "强掘蔞根槃鬰屈，故挑菊茁嚼芳辛。", "春來小疾妨杯切，老去懷鄉役夢頻。", "堪笑吳傖戀蓴鱠，素衣愁化洛陽塵。"]'),
('eec57fe1-767a-43b3-91d0-caa5964fadaf','汴上書事','張耒','宋','宋诗','song-poetry','','[]','荒陂浮雁啄寒水，古木老烏啼夕陽。',128,'全唐诗/poet.song.66000.json','["荒陂浮雁啄寒水，古木老烏啼夕陽。", "酒市喧呼人醉餘，叢祠歌舞歲豐穰。", "黄花半落經寒雨，紅稻初堅得早霜。", "倚岸老枝榆骨白，出林丹實柿肌黄。", "空林啅起團驚鵲，槁葉悲啼有暗螿。", "腰兔暮歸人臂隼，扣門問宿客擔囊。", "貂裘西去衝寒早，澤國東歸寄夢長。", "入洛自慚文價薄，却憑山水助清狂。"]'),
('3bc5ece6-c2d6-4130-8ff6-efc37369ef81','次韵黄汝器與君謨唱和三首  其一','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','飲量平吞叔度陂，宣城風月舊相知。',64,'全唐诗/poet.song.66000.json','["飲量平吞叔度陂，宣城風月舊相知。", "雪霜欺客凋新鬢，珠玉投人出好詩。", "門對洞庭書滿架，飲翻雲夢酒盈巵。", "江城少駐還鄉棹，一伴山翁醉習池。"]'),
('23e80302-d98c-42c6-a173-5794736159f6','次韵黄汝器與君謨唱和三首  其二','張耒','宋','宋诗','song-poetry','','[]','吳門韋白舊推賢，文雅相望數百年。',64,'全唐诗/poet.song.66000.json','["吳門韋白舊推賢，文雅相望數百年。", "千里江山留醉墨，五湖風月縱歸船。", "書來遠慰連鐶夢，歲熟歸收種秫田。", "仕祿及親身早退，高名榮事更誰先。"]'),
('43f62dfc-fc83-4662-a8f8-3b434e82fd4b','次韵黄汝器與君謨唱和三首  其三','張耒','宋','宋诗','song-poetry','','[]','愛君退易似前賢，投劾歸來不待年。',64,'全唐诗/poet.song.66000.json','["愛君退易似前賢，投劾歸來不待年。", "世故飽諳真昨夢，道心不繫學虛船。", "莫悲白雪凋玄鬢，自有丹砂暖寸田。", "兩郡詩筒屢傳寄，主盟騷雅定誰先。"]'),
('1871ed53-37a4-4297-93ca-fd0e48ae86ee','三月一日馬令送花','張耒','宋','宋诗','song-poetry','','[]','未說潯陽別淚痕，江邊蘋芷不勝繁。',64,'全唐诗/poet.song.66000.json','["未說潯陽別淚痕，江邊蘋芷不勝繁。", "不知來歲在何處，又對新花憶故園。", "插帽每慚輝白髮，飛香曾伴照清尊。", "去年今日淮陽道，落絮殘紅正斷魂。"]'),
('46ca87be-86e0-4f57-b837-ec5c135196ca','木香','張耒','宋','宋诗','song-poetry','','[]','紫皇寶輅張珠幰，玉女熏籠覆繡衾。',32,'全唐诗/poet.song.66000.json','["紫皇寶輅張珠幰，玉女熏籠覆繡衾。", "萬紫千紅休巧笑，人間春色在檀心。"]'),
('aa9ae4ce-a69d-45f5-b6c6-75c048cacc7f','九月末風雨初寒  其一','張耒','宋','宋诗','song-poetry','','[]','栗冽已戒候，陰淡達朝昏。',72,'全唐诗/poet.song.66000.json','["栗冽已戒候，陰淡達朝昏。", "出門無所詣，幽齋誰與言。", "塵埃羣書積，興至時一翻。", "呼兒具棗栗，時亦頼芳樽。", "老肌畏寒苦，幸此手足溫。", "窗間有舊筆，得句時復援。"]'),
('03b71873-fab0-48c0-8393-750b530039a1','九月末風雨初寒  其二','張耒','宋','宋诗','song-poetry','','[]','愛此庭下菊，蕭蕭何及時。',72,'全唐诗/poet.song.66000.json','["愛此庭下菊，蕭蕭何及時。", "郊原一秋暵，麥種待榮滋。", "今年真有秋，禾菽實纍纍。", "老農笑謂予，不復憫汝饑。", "桑榆可析薪，秋風可夜吹。", "晴明理罝繳，雉兔日已肥。"]'),
('b76bfca1-8f68-49c7-ad54-63a899ed6105','立秋後便凉詩示秬等','張耒','宋','宋诗','song-poetry','','[]','暑別齊紈知有日，秋生蘄竹果如期。',64,'全唐诗/poet.song.66000.json','["暑別齊紈知有日，秋生蘄竹果如期。", "月明半夜似相覓，角怨五更知爲誰。", "風露滿天河轉後，江山千里雁來時。", "短檠莫倦親燈火，又見槐花黄滿枝。"]'),
('d035a97e-90a9-41b0-b65b-c56f8018eee6','曉意','張耒','宋','宋诗','song-poetry','','[]','城頭清角已三奏，樹間眠鳩方一鳴。',64,'全唐诗/poet.song.66000.json','["城頭清角已三奏，樹間眠鳩方一鳴。", "風霜凄緊雁南向，星河橫斜天左傾。", "待旦枕戈無怨敵，將朝盛服非公卿。", "不如衲被蒙頭睡，直至東窗海日生。"]'),
('e056cdd3-5b6a-42ff-b820-1da7436b2bde','歲晚有感','張耒','宋','宋诗','song-poetry','','[]','疏梅點點柳毿毿，殘臘新春氣候參。',64,'全唐诗/poet.song.66000.json','["疏梅點點柳毿毿，殘臘新春氣候參。", "天靜秋鴻來塞北，雲收片月出江南。", "青霄雨露將回律，白首江湖尚避讒。", "未信斯途無倚伏，有時清鏡理朝鬖。"]'),
('dbd819e5-67c7-4b85-a335-914d4315c594','新正二首  其一','張耒','宋','宋诗','song-poetry','','[]','新正閱月天苦陰，白日未照草木心。',32,'全唐诗/poet.song.66000.json','["新正閱月天苦陰，白日未照草木心。", "黄州城中人迹少，江濤湧洶山崎嶔。"]'),
('635aab83-82f6-4072-a5b3-d408f4791301','新正二首  其二','張耒','宋','宋诗','song-poetry','','[]','柯山老人盡日閑，暖依薪炭不出山。',32,'全唐诗/poet.song.66000.json','["柯山老人盡日閑，暖依薪炭不出山。", "闌風伏雨莫收拾，不念厚土何時乾。"]'),
('058e09d0-560e-4255-beb3-4267b8518738','中秋夜東剎贈仁公','張耒','宋','宋诗','song-poetry','','[]','盈盈秋月不餘分，葉露懸光可數塵。',32,'全唐诗/poet.song.66000.json','["盈盈秋月不餘分，葉露懸光可數塵。", "此地正須煩一笑，要令排戶問東鄰。"]'),
('ff3d3302-63ef-441c-aa27-b64a7da20b54','送黄師是梓州提刑','張耒','宋','宋诗','song-poetry','','[]','嘉陵江邊樹，他日繫我駒。',120,'全唐诗/poet.song.66000.json','["嘉陵江邊樹，他日繫我駒。", "當時挾書兒，抱子鑷白鬚。", "傷懷洒孤淚，一夢百崎嶇。", "西城送我處，今日攬君袪。", "君才如涌泉，隨用隨有餘。", "中年頗流落，四駕使者車。", "持節豈不貴，列城隨慘舒。", "君看冒軒冕，奴隸笑金朱。", "猿鳥日異音，山川開畫圖。", "懷君即飲酒，念我當寄書。"]'),
('739b99b8-ed7c-4f64-921a-d6fa6bce6c0d','林居','張耒','宋','宋诗','song-poetry','','[]','林居觀變化，寒暑無時停。',72,'全唐诗/poet.song.66000.json','["林居觀變化，寒暑無時停。", "日月迭奔走，汲汲作昏明。", "彼人於其間，起妄自經營。", "寧知運之去，不受如力爭。", "終古一逝川，聖達亦歎驚。", "寄言夸毘子，豪奪竟何成。"]'),
('4cb196a5-825d-452b-81ac-b565f532faf0','有所歎五首  其一','張耒','宋','宋诗','song-poetry','','[]','十夫操戈羣入市，市人奔走爭逃死。',64,'全唐诗/poet.song.66000.json','["十夫操戈羣入市，市人奔走爭逃死。", "鷄飛犬逝閭里空，攘奪金珠虜妻子。", "世人惡盜恐不深，真不爲盜能有幾。", "何況蚩蚩田野人，欲使饑寒不爲此。"]'),
('6bafc04d-2fb4-4290-8bff-75a767a3597f','有所歎五首  其二','張耒','宋','宋诗','song-poetry','','[]','饑兒無食偷鄰桑，主人殺兒屍道傍。',64,'全唐诗/poet.song.66000.json','["饑兒無食偷鄰桑，主人殺兒屍道傍。", "母兄知兒死不直，行哭吞聲空歎息。", "生重於桑亦易明，何爲以身邀所輕。", "沒身毫釐易其死，世上誰非竊桑子。"]'),
('6a982567-3035-41bd-9348-fd7e760f01a9','有所歎五首  其三','張耒','宋','宋诗','song-poetry','','[]','蛙鳴聒聒滿我池，我寧知爾樂與悲。',64,'全唐诗/poet.song.66000.json','["蛙鳴聒聒滿我池，我寧知爾樂與悲。", "周公洒灰教後世，顧我齷齪不忍施。", "越人嗜汝過芻豢，芼以芳香侑朝飯。", "藏身泥沙勿妄出，世人重味輕天物。"]'),
('98d9a59d-59aa-4927-8162-ed5aabd9e686','有所歎五首  其四','張耒','宋','宋诗','song-poetry','','[]','蝎能毒人不能死，人能捕蝎殘其類。',64,'全唐诗/poet.song.66000.json','["蝎能毒人不能死，人能捕蝎殘其類。", "世人意惡蝎爲虐，人蝎相殘竟誰至。", "不參彼已怨一方，自古詩人以爲刺。", "我疑人酷蝎所羞，何暇區區論蝎罪。"]'),
('243f99fc-e045-4122-8dbf-a834e58d8647','有所歎五首  其五','張耒','宋','宋诗','song-poetry','','[]','衛青功高不薦賢，猶有蘇建能拳拳。',64,'全唐诗/poet.song.66000.json','["衛青功高不薦賢，猶有蘇建能拳拳。", "魏其已誅武安死，將軍畏禍無敢言。", "田竇安知天下士，可是一言誰得罪。", "當憂磊落世上奇，白頭騎奴安得知。"]'),
('4494a9bb-aee4-4a7a-89b0-fd9df8b7d7a3','登汴岸','張耒','宋','宋诗','song-poetry','','[]','悠悠十月尾，野靜田事息。',48,'全唐诗/poet.song.66000.json','["悠悠十月尾，野靜田事息。", "嚴霜草木黄，千里樹一色。", "呼鷹者誰子，窘兔保深棘。", "物皆愛其死，吾寧忍鮮食。"]'),
('f61d9604-edf6-4752-8f0b-45f27a357dd1','宿州','張耒','宋','宋诗','song-poetry','','[]','野雲不作雪，仲冬氣猶蒸。',96,'全唐诗/poet.song.66000.json','["野雲不作雪，仲冬氣猶蒸。", "岸雨濕枯柳，北風生浪聲。", "昨日飲我者，主人出金觥。", "酒薄亦足醉，青蛾慣逢迎。", "紛紛舟車地，主吏困怨憎。", "樽罍備人事，起論愛客誠。", "世途聊復爾，物態惡分明。", "十年五往返，撫事感飄零。"]'),
('33827071-3a5f-4124-8d30-99e36aadddfe','出都門泊鎮外失飲食節中夕暴下用氣術消息之即癒','張耒','宋','宋诗','song-poetry','','[]','畏途戒十一，飲食玩死地。',120,'全唐诗/poet.song.66000.json','["畏途戒十一，飲食玩死地。", "防患迷輕重，達者笑不智。", "古人慎寢食，愛生良有待。", "從來天下圖，不易無名指。", "甘飧冒物禁，中夕得顛沛。", "坐令妻孥憂，憊腹委如带。", "頼知仙聖術，杳杳存一氣。", "船輕曉眠足，扣齒無餘滯。", "艱難衆所虞，君子謹容易。", "永懷青精飯，聊欲屏俗嗜。"]'),
('5eb36b5a-f8cb-4ce2-8aac-0e8458b1d108','過臨淮','張耒','宋','宋诗','song-poetry','','[]','衝寒發孤城，带雪入異縣。',72,'全唐诗/poet.song.66000.json','["衝寒發孤城，带雪入異縣。", "春陰舟楫迴，遠眼烟木亂。", "朝來雲間塔，別我忽不見。", "春流背客去，應過前日岸。", "懷居念繾綣，送別祝寢飯。", "撫事良有懷，申情能無歎。"]'),
('98f77e52-deb6-4e00-bd60-fcba7d2812a4','泗州阻風七日投佛經禱斗山下','張耒','宋','宋诗','song-poetry','','[]','山根受重淵，石脚插九地。',120,'全唐诗/poet.song.66000.json','["山根受重淵，石脚插九地。", "千年無支祈，閉穴守禹誓。", "扁舟七日閑，浪作老龍戲。", "舟師慎艱險，長跪請佛事。", "晚山水如屋，曉山水如地。", "清平一潭風，浪陣卷旂旆。", "煌煌金仙語，鬼物所尊畏。", "無心服毒猛，慧眼出幽穢。", "人間慢聖賢，諄戒遭侮易。", "誰肯一卷書，脫此千里滯。"]'),
('a3568278-f300-46f9-9a4d-da85af67de72','陽翟道中','張耒','宋','宋诗','song-poetry','','[]','客行趨陽翟，驅馬登高崗。',96,'全唐诗/poet.song.66000.json','["客行趨陽翟，驅馬登高崗。", "羣山拱西都，迴首瞰許昌。", "原田秀且潤，烟水遠分行。", "荒冢卧石獸，古祠摧畫牆。", "我行日已遠，風物非故鄉。", "隨俗强飲食，所求肢體强。", "兒生事弧矢，有志行四方。", "秣馬訪前古，吾將問興亡。"]'),
('12a6b282-65f0-4955-9288-9686d6773b1b','阻風累日泊寶積山下','張耒','宋','宋诗','song-poetry','','[]','繫船淮北雨如軸，繫船淮南風斷橋。',64,'全唐诗/poet.song.66000.json','["繫船淮北雨如軸，繫船淮南風斷橋。", "客行有期日月疾，歲事欲晚霰雪驕。", "山根浪頭作雷吼，縮手敢試舟師篙。", "不用燃犀照幽怪，要須拔劍斷長蛟。"]'),
('f6394ac3-9fe6-45be-8dda-c2107e852357','宿州道中','張耒','宋','宋诗','song-poetry','','[]','眼明初見淮南樹，十客相逢九吳語。',64,'全唐诗/poet.song.66000.json','["眼明初見淮南樹，十客相逢九吳語。", "旅程已付夜帆風，客睡不妨船背雨。", "黄柑紫蟹見江海，紅稻白魚飽兒女。", "殷勤買酒謝船師，千里勞君聊轉櫓。"]'),
('923182e2-6b43-4d76-ad54-9aa8e907b6ab','春陰泊龜山寄園明','張耒','宋','宋诗','song-poetry','','[]','東風淮聲鳴萬鼓，山頭孤塔藏烟霧。',64,'全唐诗/poet.song.66000.json','["東風淮聲鳴萬鼓，山頭孤塔藏烟霧。", "一庵老宿何處峰，孤舟倦客沙邊雨。", "楊柳梢頭春未多，白蘋汀下正滄波。", "莫向春陰開病眼，風烟如此奈愁何。"]'),
('51288e24-90ca-41d1-bea5-b87924acdace','初夏步園','張耒','宋','宋诗','song-poetry','','[]','夏木皆秀茂，小園交茂林。',72,'全唐诗/poet.song.66000.json','["夏木皆秀茂，小園交茂林。", "巢成雛欲出，上下鳴時禽。", "中有支離翁，行憩佳樹陰。", "好風爲我來，蕭然散煩襟。", "物化日遷逝，客居何滯淫。", "虧行天有數，隠顯我無心。"]'),
('91e00e85-959c-4833-9f44-34e07f226523','雨夜懷陳永源山莊','張耒','宋','宋诗','song-poetry','','[]','陳君爲生廉易足，水石田園藏一曲。',64,'全唐诗/poet.song.66000.json','["陳君爲生廉易足，水石田園藏一曲。", "畦田已作故侯業，種竹未享封君祿。", "干名懶復觀書卷，濟病時能開藥籙。", "夜來秋雨如决渠，不寐憂君玉川屋。"]'),
('ea361669-2478-468e-b495-03554b2865b9','效二謝體','張耒','宋','宋诗','song-poetry','','[]','棄斥非高隠，林居值晚秋。',72,'全唐诗/poet.song.66000.json','["棄斥非高隠，林居值晚秋。", "風雲日慘變，感彼歲月遒。", "秀蔓依簷槁，陳葉當窗投。", "晚花弄餘秀，畦菜枝新柔。", "閑居妙觀物，貧賤吾何憂。", "寂念師竺瞿，齊物信蒙周。"]'),
('4eecaaaf-9e25-4a75-96a2-561ce7024e29','秋雨獨酌三首  其一','張耒','宋','宋诗','song-poetry','','[]','秋陰不可解，澍雨忽連朝。',96,'全唐诗/poet.song.66000.json','["秋陰不可解，澍雨忽連朝。", "貧居庭除狹，漲潦時驚飄。", "老夫凌晨起，山木鳴蕭蕭。", "開門買野菜，菘薤喜新苗。", "鄙人晚耽佛，像設如僧寮。", "焚香翻貝葉，禪誦安不勞。", "日高出道場，傾蓋盈山瓢。", "醺然知體暢，誰共此逍遙。"]'),
('92c8fb72-1451-4e11-8b2e-fd06b16fb2fd','秋雨獨酌三首  其二','張耒','宋','宋诗','song-poetry','','[]','羲和隔重雲，不復知下土。',96,'全唐诗/poet.song.66000.json','["羲和隔重雲，不復知下土。", "商羊何爲者，得時方鼓舞。", "老人閑不出，秋草生環堵。", "況茲陰霖時，塊坐誰與語。", "江人雨不魚，魴鯉不登俎。", "晨烹亦何有，藜藿恣烹煮。", "壺中有芳春，造物不得與。", "一醉興未終，連延忽三舉。"]'),
('e69032ca-8ab4-4451-b9b4-fcf016e59d99','秋雨獨酌三首  其三','張耒','宋','宋诗','song-poetry','','[]','陰雨何可處，樂事頼尊中。',96,'全唐诗/poet.song.66000.json','["陰雨何可處，樂事頼尊中。", "泥濘不可出，潔掃一畝宮。", "氣平憂患失，目凈塵滓空。", "誰知環堵間，樂事殊未窮。", "老人飽諳事，未易勤其胸。", "兒曹方蜩螗，幾見弄伎工。", "惟有尊中物，於人差有功。", "不解作悲秋，吾師柴桑翁。"]'),
('63b3372e-6c2f-43a4-aadc-d4543122d1ec','三月十三日本約潘郎同游安園以雨不果因飲於家爲說宛丘木芍藥之盛作此篇','張耒','宋','宋诗','song-poetry','','[]','衝泥看花亦不惡，泥深三尺馬苦臞。',64,'全唐诗/poet.song.66000.json','["衝泥看花亦不惡，泥深三尺馬苦臞。", "閉門且復與君飲，吟詩寫字樂有餘。", "姚黄一枝說不盡，天姬帝子非世姝。", "念君東坡守寂寞，春深窮巷堆枯榆。"]'),
('f98809a1-4526-4433-8e60-7ada2d59d0e8','春陰','張耒','宋','宋诗','song-poetry','','[]','春山苦多昏，陰靄晝長暝。',96,'全唐诗/poet.song.66000.json','["春山苦多昏，陰靄晝長暝。", "鳥鳴欲成巢，冰泮魚已泳。", "薄寒方未已，慘切有餘勁。", "霏霏晚雨飄，黯黯夕氤凝。", "高鴻戢南翮，布穀謹新令。", "班班農在耕，冉冉麥將盛。", "官閑倦無侶，覽物偶乘興。", "無辭數携酒，溪柳黄欲映。"]'),
('40b499d6-c80a-4bd3-9eda-11b6f2759f83','寒食','張耒','宋','宋诗','song-poetry','','[]','風雲雖不定，日雨亦易乾。',60,'全唐诗/poet.song.66000.json','["風雲雖不定，日雨亦易乾。", "殘春猶凜凜，助我朝食寒。", "想見芳野田，士女游班班。", "去者日以疏，更爲來者歡。", "青紅間車馬，日暮醉牆間。"]'),
('5b112ed4-c3e5-4b76-8725-e5bb6ecac22a','麗春','張耒','宋','宋诗','song-poetry','','[]','蓬蒿眼已熟，收拾到阿麗。',48,'全唐诗/poet.song.66000.json','["蓬蒿眼已熟，收拾到阿麗。", "徒分色黄白，未害格妾婢。", "爭妍知不足，出刺以自衛。", "上有寒梅枝，春霜一憔悴。"]'),
('eabf6381-9957-432d-9542-d6df86748864','秋懷','張耒','宋','宋诗','song-poetry','','[]','秋雲晦清曉，密雨散迴風。',96,'全唐诗/poet.song.66000.json','["秋雲晦清曉，密雨散迴風。", "修然有嘉思，盥櫛臨青銅。", "掃地靜如眼，妙香散浮空。", "黄葵麗不驕，幽菊靜有容。", "無車驚門雀，幽巷連蒿蓬。", "老知飲無益，靜覺書有功。", "晚木多美實，凉風驚候蟲。", "問津竟何效，真愧圃與農。"]'),
('dcd0a534-a27e-4be6-bcbe-ec70c1a3c054','離泗州冒大雪','張耒','宋','宋诗','song-poetry','','[]','陰風駕長淮，鐵馬一百萬。',96,'全唐诗/poet.song.66000.json','["陰風駕長淮，鐵馬一百萬。", "孤舟犯其壘，白羽一揮散。", "崩騰中夜雪，千里照組練。", "乾坤合冥蒙，遠色辨波面。", "雲端數寸塔，僅若簪出弁。", "寒飛不遠林，瘦植凍依岸。", "龜山晚沽酒，旅食烹野雁。", "惜哉吾里豐，一畝不素辦。"]'),
('5230328c-47ac-4260-aa65-6326d75ef22f','雪後贈徐仲車','張耒','宋','宋诗','song-poetry','','[]','平明呼童汲井華，童歸告我門有雪。',160,'全唐诗/poet.song.66000.json','["平明呼童汲井華，童歸告我門有雪。", "披衣疾走出戶看，正見風毛萬夫獵。", "冷欺病骨不敢前，縮頭蟄戶如寒鼈。", "樓臺得勢互照映，松竹無風自騷屑。", "念昔兒童逢雪喜，摶捧嘴吞如沃渴。", "如今欲啗老不禁，何異愛屨而遭刖。", "高門有酒不愛詩，我愛吟詩尊屢闕。", "東鄰徐子與我同，愛詩過我衣百結。", "藏頭敗被口吟呵，文似鏘金身似鐵。", "人生豈合長賤貧，二百青銅直須輟。"]'),
('c2075b9b-aca9-4217-a3ec-85b69a47c916','題吳熙老古銅榼','張耒','宋','宋诗','song-poetry','','[]','子雲鴟夷如大壺，日醉自不妨著書。',64,'全唐诗/poet.song.66000.json','["子雲鴟夷如大壺，日醉自不妨著書。", "盛酒借沽太勤劬，鑄銅爲榼計未疏。", "古人制器儉復真，不似後世鏤金銀。", "一罌湛湛致坐側，時與周旋真可人。"]'),
('fd9e3582-2033-4583-bf75-5b3f03225090','農婦','張耒','宋','宋诗','song-poetry','','[]','耕田衣食苦不足，悠悠送子長河曲。',64,'全唐诗/poet.song.66000.json','["耕田衣食苦不足，悠悠送子長河曲。", "同行不可別未忍，日暮河邊仰天哭。", "男兒從軍薄妻子，婦人隨夫誓生死。", "封侯佩印未可知，不道沙場即爲鬼。"]'),
('560d278e-bfd1-4705-b221-e9c6a0e59ad6','山雪','張耒','宋','宋诗','song-poetry','','[]','空中莽落索，曉雪遍平郊。',48,'全唐诗/poet.song.66000.json','["空中莽落索，曉雪遍平郊。", "霰急松鳴葉，聲繁竹戰梢。", "暮鳶饑啄屋，寒雉濕依茅。", "誰上梁王賦，淹留感鬢毛。"]'),
('a89e1bf4-a124-497e-a186-8d73cac6856e','戲二潘','張耒','宋','宋诗','song-poetry','','[]','眊矂柯山客，還家只醉眠。',48,'全唐诗/poet.song.66000.json','["眊矂柯山客，還家只醉眠。", "桂堂渾忘却，蟬室故依然。", "未用臨書卷，聊須辦酒錢。", "所欣家有弟，鄉校首稱賢。"]'),
('c718af74-37ba-4539-88b6-0be5b54ee190','寄陳履常二首  其一','張耒','宋','宋诗','song-poetry','','[]','近聞彭澤令，旅飯寄招提。',48,'全唐诗/poet.song.66000.json','["近聞彭澤令，旅飯寄招提。", "杜老不厭賦，韋郎猶愧妻。", "得州慚牧養，懷友負招携。", "祇學新詩好，高吟獨醉泥。"]'),
('7ba1c5ef-3715-4d17-ba0b-632373093572','寄陳履常二首  其二','張耒','宋','宋诗','song-poetry','','[]','故人猶念我，一笑向何人。',48,'全唐诗/poet.song.66000.json','["故人猶念我，一笑向何人。", "老去唯佛祖，州閑如隠淪。", "殘年河朔雪，近臘水鄉春。", "何日相逢笑，天邊白髮新。"]'),
('31adf4f5-3eda-47de-adc1-ddfc6d1ce91b','聞邠老下第作詩迎之','張耒','宋','宋诗','song-poetry','','[]','淡墨高張動禁城，風馳電落走寰瀛。',64,'全唐诗/poet.song.66000.json','["淡墨高張動禁城，風馳電落走寰瀛。", "從來萬卷貯便腹，可得千人無一名。", "且向江邊伴逐客，會須天上冠羣英。", "遙思匹馬千山里，孤店村深聽晚鶯。"]'),
('b169379f-c746-4e11-8894-8d1a54598f42','次韵邠老見貽','張耒','宋','宋诗','song-poetry','','[]','已嗟骯髒倚門邊，況復歸來竈不烟。',64,'全唐诗/poet.song.66000.json','["已嗟骯髒倚門邊，況復歸來竈不烟。", "觀國未書攀桂籍，還家却上過淮船。", "瑰奇難售真當爾，鑿枘相遭亦偶然。", "未死此生誰料得，且將見在鬭尊前。"]'),
('75f9c682-1c17-49b0-9c71-224322fb9be3','久不見潘十作詩戲之聞其別墅晚稻稍收','張耒','宋','宋诗','song-poetry','','[]','誰云世不容吾道，自是窮常逐我曹。',64,'全唐诗/poet.song.66000.json','["誰云世不容吾道，自是窮常逐我曹。", "未能下帷授老子，且復痛飲讀離騷。", "雨多園圃一慘淡，秋霽山川開泬寥。", "裹飯送君吾豈敢，黄雲𥝧稏連東皋。"]'),
('5ee06491-4011-4874-8585-fd5c7aae9314','效白體贈晁无咎  其一','張耒','宋','宋诗','song-poetry','','[]','過去生中作弟兄，依然骨肉有餘情。',64,'全唐诗/poet.song.66000.json','["過去生中作弟兄，依然骨肉有餘情。", "青衫校正同三館，白髮東南各一城。", "君比酈生多事業，我方謝朓欠詩名。", "想當把酒笙歌裏，亦記長安痛飲生。"]'),
('96004973-aee6-4985-911d-3aeb6a6b4ca6','效白體贈晁无咎  其二','張耒','宋','宋诗','song-poetry','','[]','江南歲晚水風寒，鈴閣無人晝掩關。',64,'全唐诗/poet.song.66000.json','["江南歲晚水風寒，鈴閣無人晝掩關。", "過雨樓臺宛溪市，新霜松竹敬亭山。", "不悲仕宦從來拙，所喜形骸絕得閑。", "山妓村醪君莫笑，亦勝苜蓿滿朝盤。"]'),
('c35f309e-1013-449c-87ed-0fd107197d0f','效白體贈晁无咎  其三','張耒','宋','宋诗','song-poetry','','[]','關河戰國東秦地，風月南朝小謝城。',64,'全唐诗/poet.song.66000.json','["關河戰國東秦地，風月南朝小謝城。", "妓樂比君拈不出，溪山許我賭來贏。", "真珠金綫真無比，疊嶺雙溪亦有聲。", "一事與君霄壤別，板輿時從老人行。"]'),
('9d84e46a-92a8-4817-bbb4-ea0ad4edbbeb','山光寺','張耒','宋','宋诗','song-poetry','','[]','寺古丹青暗，地幽花木春。',72,'全唐诗/poet.song.66000.json','["寺古丹青暗，地幽花木春。", "垣牆兵火後，臺殿棟梁新。", "繞屋松聲合，鋪庭草色勻。", "春耕迷古壘，野水灧通津。", "落魄閑來客，蕭條禁火晨。", "重尋舊游地，俯仰十年身。"]'),
('3e1a78f6-7484-4a2c-ad0c-c87b056ef4a9','三月晦日與客小酌','張耒','宋','宋诗','song-poetry','','[]','天教老景變芳菲，晨起衰翁換裌衣。',64,'全唐诗/poet.song.66000.json','["天教老景變芳菲，晨起衰翁換裌衣。", "盡日綠陰鶯懶囀，有時芳草蝶爭飛。", "最憐永日身無事，所歎佳時客未歸。", "雖老清狂猶未減，憑春說與故園知。"]'),
('658a2c6d-e7cb-44d0-a7a8-d45c3a8a578a','野望','張耒','宋','宋诗','song-poetry','','[]','野寬秋望閣，浩蕩雨初還。',48,'全唐诗/poet.song.66000.json','["野寬秋望閣，浩蕩雨初還。", "寒樹爭標嶺，歸雲各占山。", "歲窮風物慘，地闊井閭閑。", "飽食端無補，微官亦愧顔。"]'),
('4f3c37f2-340b-4384-a808-5941ee12cbfd','他鄉','張耒','宋','宋诗','song-poetry','','[]','身寄他鄉遠，心驚土俗殊。',48,'全唐诗/poet.song.66000.json','["身寄他鄉遠，心驚土俗殊。", "閭閻諱冠带，子弟笑詩書。", "韓國縱橫後，商頑習尚餘。", "幾時東去棹，笑膾楚鄉魚。"]'),
('7f7cee19-0a94-48d7-9656-10dfd0c3e3b6','晨起眺望','張耒','宋','宋诗','song-poetry','','[]','衆木交陰園逕荒，獨尋細徑上東岡。',64,'全唐诗/poet.song.66000.json','["衆木交陰園逕荒，獨尋細徑上東岡。", "山頭秀插垂雲處，江面平分浴日光。", "沙際離離橫水鳥，林端歷歷過風檣。", "登臨每到消憂處，不覺三年客異鄉。"]'),
('0858092f-9087-4a5f-bdcb-af18476e5e8b','有感二絕  其一','張耒','宋','宋诗','song-poetry','','[]','殘雪微風冷透衣，柳黄梅破欲春時。',32,'全唐诗/poet.song.66000.json','["殘雪微風冷透衣，柳黄梅破欲春時。", "年年景物常相似，滿眼相思只自知。"]'),
('212c76f9-80c6-4e09-ae95-a44cb22d3d24','有感二絕  其二','張耒','宋','宋诗','song-poetry','','[]','日暇凝雲去復還，晚風不動自清寒。',32,'全唐诗/poet.song.66000.json','["日暇凝雲去復還，晚風不動自清寒。", "可憐庭雪無人掃，斜占牆陰獨未殘。"]'),
('9d0bd38e-89c1-4dd9-98c8-b8e07404bccc','贈別儀上人','張耒','宋','宋诗','song-poetry','','[]','師似浮雲觸處閑，倦飛知我未能還。',32,'全唐诗/poet.song.66000.json','["師似浮雲觸處閑，倦飛知我未能還。", "林泉會有相逢日，風月應須乞半山。"]'),
('fa578512-b475-4384-b6c0-66d458dab637','宿文殊院呈孫子和二絕  其一','張耒','宋','宋诗','song-poetry','','[]','天河初沒空明星，四聽雞號人欲興。',32,'全唐诗/poet.song.66000.json','["天河初沒空明星，四聽雞號人欲興。", "高林有露乍蹄馬，佛屋無人到曉燈。"]'),
('7e47d806-b621-4540-af96-c0f4f1a86e06','宿文殊院呈孫子和二絕  其二','張耒','宋','宋诗','song-poetry','','[]','朱樓簾捲見天涯，倦客倚欄何所思。',32,'全唐诗/poet.song.66000.json','["朱樓簾捲見天涯，倦客倚欄何所思。", "新月無情明復落，清簫有恨歇還吹。"]'),
('8b38c1f3-772e-4e49-b791-41327f9fe48d','晚鶯二首  其一','張耒','宋','宋诗','song-poetry','','[]','庭樹知秋彫晚枝，春鶯一去幾時歸。',32,'全唐诗/poet.song.66000.json','["庭樹知秋彫晚枝，春鶯一去幾時歸。", "晚來何事枝頭見，啞咤數聲還復飛。"]'),
('5ff5a1c9-3d06-4fb5-b79b-30f5f342251f','晚鶯二首  其二','張耒','宋','宋诗','song-poetry','','[]','青竹萬葉一霜摧，何事流鶯去復迴。',32,'全唐诗/poet.song.66000.json','["青竹萬葉一霜摧，何事流鶯去復迴。", "啼鵊已摧芳草歇，春風安肯爲君來。"]'),
('fc3e2bd2-dad7-4610-8ef3-db2aeff4d81d','魚蝦','張耒','宋','宋诗','song-poetry','','[]','一尺盆池數種荷，魚蝦亦解起風波。',32,'全唐诗/poet.song.66000.json','["一尺盆池數種荷，魚蝦亦解起風波。", "爾來未識天池樂，更有鯨鵬奈爾何。"]'),
('fdf61fe3-c588-43a7-b56f-e6227f1c96ad','直廬聯句','張耒','宋','宋诗','song-poetry','','[]','上閤井泉甘若醴，蓬山點茶竹陰底。',64,'全唐诗/poet.song.66000.json','["上閤井泉甘若醴，蓬山點茶竹陰底。", "庚伏恩容午課休，宮殿初凉朝雨洗。", "身閑出飲官不嗔，日長睡足長精神。", "未慚便作蠹魚老，拔毛濟世知何人。"]'),
('de0eed94-feaf-48cd-9669-f6237533f2f1','秋夜西崗聯句','張耒','宋','宋诗','song-poetry','','[]','城南遠人跡，蟲響最先秋。',144,'全唐诗/poet.song.66000.json','["城南遠人跡，蟲響最先秋。", "河漢橫疑近，星辰爛不收。", "露濃枝上月，風駛苑中籌。", "下直身田野，相忘世馬牛。", "市聲城郭夜，遙色草茅幽。", "寂莫容還往，文章得獻酬。", "天依閶闔轉，斗直未央留。", "清洛東輸海，夷門北拱州。", "寒燈知苦織，濁酒識窮愁。", "飽食容高議，蒼顔愧薄遊。", "黑貂寒事早，青史素心遒。", "附驥容吾鈍，黄金試絡頭。"]'),
('52636088-b921-4276-88a5-abb58dc99130','凝祥池上聯句','張耒','宋','宋诗','song-poetry','','[]','粉垣周十里，丹碧煥神宮。',48,'全唐诗/poet.song.66000.json','["粉垣周十里，丹碧煥神宮。", "樓閣晚多雨，梧桐天早風。", "人來夕照外，鳥起白蘋中。", "何用厭城郭，滄洲佳興同。"]'),
('933418f0-d434-4579-b2a4-0cd07da545b0','戲作雪獅絕句','張耒','宋','宋诗','song-poetry','','[]','六出裝來百獸王，日頭出後便郎當。',32,'全唐诗/poet.song.66000.json','["六出裝來百獸王，日頭出後便郎當。", "爭眉霍眼人誰怕，想你應無熟肺腸。"]'),
('cf3aa14d-2d63-4299-b6ff-7e661aea4f37','倉前村民輸麥行','張耒','宋','宋诗','song-poetry','','[]','場頭雨乾場地白，老穉相呼打新麥。',128,'全唐诗/poet.song.66000.json','["場頭雨乾場地白，老穉相呼打新麥。", "半歸倉廩半輸官，免教縣吏相催迫。", "羊頭車子毛巾囊，淺泥易涉登前岡。", "倉頭買券槐陰凉，清嚴官吏兩平量。", "出倉掉臂呼同伴，旗亭酒美單衣換。", "半醉扶車歸路凉，月出到家妻具飯。", "一年從此皆閒日，風雨閉門公事畢。", "射狐罝兔歲蹉跎，百壺社酒相經過。"]'),
('7c72c3df-b7e4-4ecf-9758-4f593bc8ac3c','春暮','張耒','宋','宋诗','song-poetry','','[]','春盡空餘白日長，枝頭青杏已堪嘗。',64,'全唐诗/poet.song.66000.json','["春盡空餘白日長，枝頭青杏已堪嘗。", "人閒簾幕燕相語，風暖園林柳半黄。", "病裏不知時節換，老來都減少年狂。", "殘風濁酒應堪在，更遣流鶯送幾觴。"]'),
('a4cbc9fe-f3e8-4361-9023-a3c1d7f4b7b6','睡香花','張耒','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曾向廬山睡裏聞，香風六斷世間春。',32,'全唐诗/poet.song.66000.json','["曾向廬山睡裏聞，香風六斷世間春。", "竊花莫撲枝頭蝶，驚覺南窗半夢人。"]'),
('a59fa892-980a-4e80-8b6f-cf9fe187f101','荷花','張耒','宋','宋诗','song-poetry','','[]','芙蓉花開秋水冷，水面無風見花影。',32,'全唐诗/poet.song.66000.json','["芙蓉花開秋水冷，水面無風見花影。", "飄香上下兩嬋娟，雲在巫山月在天。"]'),
('92ceeea3-f296-4250-aee3-4f14d26f7d50','寒食離白沙','張耒','宋','宋诗','song-poetry','','[]','花枝裊裊水溶溶，楊柳輕明二月風。',32,'全唐诗/poet.song.66000.json','["花枝裊裊水溶溶，楊柳輕明二月風。", "景物可憐人寂寞，年年寒食醉眠中。"]'),
('335dcd5c-24df-450a-be9b-4b7fb14e35f3','七月六日二首  其一','張耒','宋','宋诗','song-poetry','','[]','雨洗秋城碧玉天，暮雲吹盡月娟娟。',32,'全唐诗/poet.song.66000.json','["雨洗秋城碧玉天，暮雲吹盡月娟娟。", "寂寥誰是清宵伴，只有姮娥最可憐。"]'),
('1fed469e-4fd5-45eb-b774-050b31d7ceed','七月六日二首  其二','張耒','宋','宋诗','song-poetry','','[]','山川摇落雁南飛，想見橫汾鼓吹時。',32,'全唐诗/poet.song.66000.json','["山川摇落雁南飛，想見橫汾鼓吹時。", "得意劉郎猶歎老，蕭條宋玉故應悲。"]'),
('faf8912a-80c1-43ba-a791-591f73821a30','絕句','張耒','宋','宋诗','song-poetry','','["\u53cb\u60c5", "\u67f3\u6811", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u9001\u522b"]','亭亭畫舸繫春潭，直待行人酒半酣。',32,'全唐诗/poet.song.66000.json','["亭亭畫舸繫春潭，直待行人酒半酣。", "不管烟波與風雨，載將離恨過江南。"]'),
('a4ab6679-ddb1-4d7c-89c5-36e80708598f','句  其一','張耒','宋','宋诗','song-poetry','','[]','須看遠山相對蹙，莫欺病齒惱衰翁。',16,'全唐诗/poet.song.66000.json','["須看遠山相對蹙，莫欺病齒惱衰翁。"]'),
('548b439e-6cf9-4616-8772-178686504a54','句  其二','張耒','宋','宋诗','song-poetry','','[]','梅生紅粟初迎臘，魚躍銀刀正出淮。',16,'全唐诗/poet.song.66000.json','["梅生紅粟初迎臘，魚躍銀刀正出淮。"]'),
('47af641b-9714-4fd6-88a4-0c16aa9ce347','句  其三','張耒','宋','宋诗','song-poetry','','[]','飛蚊繞枕細而輕。',8,'全唐诗/poet.song.66000.json','["飛蚊繞枕細而輕。"]'),
('7bdd7c30-2c86-468d-99f3-455572847d8d','句  其四','張耒','宋','宋诗','song-poetry','','[]','淮山二十里，秀色已在戶。',24,'全唐诗/poet.song.66000.json','["淮山二十里，秀色已在戶。", "舟車走梁宋，烟樹引吳楚。"]'),
('44479ebb-420c-42d8-8e0b-6864cdf3f6fa','句  其五','張耒','宋','宋诗','song-poetry','','[]','靈橘無根井有泉。',8,'全唐诗/poet.song.66000.json','["靈橘無根井有泉。"]'),
('e74cc5cc-4a57-47d3-8a5a-ba09add52456','句  其六','張耒','宋','宋诗','song-poetry','','[]','昔日陶公宅，今爲釋子居。',12,'全唐诗/poet.song.66000.json','["昔日陶公宅，今爲釋子居。"]'),
('1af5696c-ab80-428a-89d8-4e3906f7a87c','句  其七','張耒','宋','宋诗','song-poetry','','[]','逢君金華宴，正味百花先。',12,'全唐诗/poet.song.66000.json','["逢君金華宴，正味百花先。"]'),
('9f10bdf9-ce2d-4001-b029-fe864ad91519','句  其八','張耒','宋','宋诗','song-poetry','','[]','霜橙共我鄉。',6,'全唐诗/poet.song.66000.json','["霜橙共我鄉。"]'),
('ccf7d834-4164-4c8e-a0f5-635b8963fad2','句  其九','張耒','宋','宋诗','song-poetry','','[]','清霜夜漠漠，佳食曉纍纍。',12,'全唐诗/poet.song.66000.json','["清霜夜漠漠，佳食曉纍纍。"]'),
('71e66042-17b8-4cef-9d4d-ef9f1d2bc381','句  其一○','張耒','宋','宋诗','song-poetry','','[]','鵠殻攢修幹，金華耀暖曦。',12,'全唐诗/poet.song.66000.json','["鵠殻攢修幹，金華耀暖曦。"]'),
('5aecc18e-fbcc-4e7d-b7db-fdb110fcef0c','句  其一一','張耒','宋','宋诗','song-poetry','','[]','玉立春深雪不如，生香透骨雪應無。',16,'全唐诗/poet.song.66000.json','["玉立春深雪不如，生香透骨雪應無。"]'),
('4907d720-aabf-456e-afb4-d84a77fe123c','句  其一二','張耒','宋','宋诗','song-poetry','','[]','風光處處同。',6,'全唐诗/poet.song.66000.json','["風光處處同。"]'),
('7c1be5ee-98b7-4781-ae24-50fa747fffa6','句  其一三','張耒','宋','宋诗','song-poetry','','[]','譌邪自不關。',6,'全唐诗/poet.song.66000.json','["譌邪自不關。"]'),
('0e141ebf-c32f-4675-a01c-72967a26f04c','句  其一四','張耒','宋','宋诗','song-poetry','','[]','空林掛夕陽。',6,'全唐诗/poet.song.66000.json','["空林掛夕陽。"]'),
('50b60798-0b71-4497-8023-535972857669','句  其一五','張耒','宋','宋诗','song-poetry','','[]','沙邊微雨濕孤蓬。',8,'全唐诗/poet.song.66000.json','["沙邊微雨濕孤蓬。"]'),
('59369df2-ebad-412a-bae1-36abdc8b8784','句  其一六','張耒','宋','宋诗','song-poetry','','[]','小葺茅茨紫翠閒。',8,'全唐诗/poet.song.66000.json','["小葺茅茨紫翠閒。"]'),
('cec225b0-a157-43dd-855f-d78c9ee4ad54','句  其一七','張耒','宋','宋诗','song-poetry','','[]','亭亭古柏不知年，天寶以前耆舊傳。',16,'全唐诗/poet.song.66000.json','["亭亭古柏不知年，天寶以前耆舊傳。"]'),
('38926673-81b6-45f2-898d-f4e19ef9f312','句  其一八','張耒','宋','宋诗','song-poetry','','[]','饑鳶跕跕下林隈，猜意鵷鶵奪鼠來。',32,'全唐诗/poet.song.66000.json','["饑鳶跕跕下林隈，猜意鵷鶵奪鼠來。", "瞥映斜陽上茅棟，塊如眠草坐毰毸。"]'),
('b208a90c-f01c-4543-8310-3bbd01ee00a7','春帖子','周邦彥','宋','宋诗','song-poetry','','[]','鸞輅青旂殿閣寬，祠官奠璧下春壇。',32,'全唐诗/poet.song.66000.json','["鸞輅青旂殿閣寬，祠官奠璧下春壇。", "曉開魚鑰朝衣集，綵勝飄揚百辟冠。"]'),
('7e533233-217d-4be3-bad7-d6b64de7fc8e','春雨','周邦彥','宋','宋诗','song-poetry','','[]','耕人扶耒語林丘，花外時時落一鷗。',32,'全唐诗/poet.song.66000.json','["耕人扶耒語林丘，花外時時落一鷗。", "欲驗春來多少雨，野塘漫水可回舟。"]'),
('80f04e06-654b-46ce-a440-10c344dd6886','投子山','周邦彥','宋','宋诗','song-poetry','','[]','緬懷魯將軍，兵敗携部曲。',36,'全唐诗/poet.song.66000.json','["緬懷魯將軍，兵敗携部曲。", "來投衲子衣，解甲飯戎菽。", "誰令名此山，異代有餘辱。"]'),
('2f38790e-a300-4e84-a58b-c0f573dc622b','贈常熟賀公叔隠士','周邦彥','宋','宋诗','song-poetry','','[]','懷珠崖不枯，韞玉山有輝。',132,'全唐诗/poet.song.66000.json','["懷珠崖不枯，韞玉山有輝。", "隠翳不言德，人自知神奇。", "公叔季貞後，不爲世網縻。", "浮沉里閭間，身晦道同違。", "弓旌搜俊良，圭衡略無遺。", "難偕集雍鷺，寧作曳尾龜。", "慈仁蓋天性，惠澤施鰥嫠。", "倒囷食流冗，死葬病有醫。", "人今泣遺愛，若見峴首碑。", "肯構有材子，修德亦庶幾。", "高風自茲顯，豈病知者希。"]'),
('11a064c3-5642-4886-8eb2-4ae7df1e0f23','仙杏山','周邦彥','宋','宋诗','song-poetry','','[]','仙人藥光明夜燭，種杏碧山如種玉。',176,'全唐诗/poet.song.66000.json','["仙人藥光明夜燭，種杏碧山如種玉。", "春風裂石鳳收花，赤頰離離照山谷。", "卿雲承日作陰潤，猛虎守山防採斸。", "高真筐篚入時貢，拜望通明薦新熟。", "珠旒頷首一破顔，氣壓蟠桃羞若木。", "自從移植近星榆，山水無光靈鬼哭。", "長松枯倒流液盡，櫂頼牽藤多樸樕。", "我思百年訪靈異，羽褐雖存言語俗。", "本非民土宰官身，欲斷人間烟火穀。", "行尋幽洞覓丹砂，儻見臞仙騎白鹿。", "便應執箒洗仙壇，不用纖纖掃塵竹。"]'),
('f1709f6e-a80e-4d39-8297-a24415871f1b','鳳凰臺','周邦彥','宋','宋诗','song-poetry','','[]','危臺飄盡碧梧花，勝地凄凉屬梵家。',32,'全唐诗/poet.song.66000.json','["危臺飄盡碧梧花，勝地凄凉屬梵家。", "鳳入紫雲招不得，木魚堂殿下饑鴉。"]'),
('63aa1fae-2f4c-4208-996e-fdca3a6291fa','過左伯桃羊角哀墓','周邦彥','宋','宋诗','song-poetry','','[]','古交久淪喪，末世尤反覆。',156,'全唐诗/poet.song.66000.json','["古交久淪喪，末世尤反覆。", "谷風歌焚輪，黄鳥譬伐木。", "永懷羊與左，重義踰血屬。", "客行干楚王，冬雪無斗粟。", "傾糧活一士，誓不俱死辱。", "風雲爲慘變，鳥獸同躑躅。", "角哀哭前途，伯桃槁空谷。", "終乘大夫車，千騎下棺櫝。", "子長何所疑，舊史刊不錄。", "獨行貴苟難，義俠輕殺戮。", "雖云匪中制，要可興薄俗。", "荒墳鄰萬鬼，溘死皆碌碌。", "何事荆將軍，操戈相窘逐。"]'),
('34375965-e749-48b2-938f-87307d38cf20','薛侯馬','周邦彥','宋','宋诗','song-poetry','','[]','薛侯俊健如生猱，不識中原生土豪。',192,'全唐诗/poet.song.66000.json','["薛侯俊健如生猱，不識中原生土豪。", "蛇矛丈八常在手，駱馬蕃鞍雲錦袍。", "往屬嫖姚探虎穴，狐鳴蕭蕭風立髮。", "短韉淋血斬將歸，夜斲堅冰濡馬渴。", "中都久住武城坊，屋頭養駱如養羊。", "枯萁不飽籬壁盡，狹巷怒蹄盆盎傷。", "只今栖栖守環堵，五月樵風吹宿莽。", "千金夜出酬市兒，客帳晝眠聽戲鼓。", "邊人視死亦尋常，笑裏辭家登戰場。", "銓勞定次屈壯士，兩眼熒熒收淚光。", "齒堅食肉何曾老，騎馬身輕飛一鳥。", "焉知不將萬人行，橫槊秋風賀蘭道。"]'),
('40d3bed8-ff47-4677-98bc-b248013e5a12','天賜白','周邦彥','宋','宋诗','song-poetry','','[]','君不見書生鎸羌勒兵入，羌來薄城束縛急。',195,'全唐诗/poet.song.66000.json','["君不見書生鎸羌勒兵入，羌來薄城束縛急。", "蠟丸飛出辭大家，帳下健兒紛雨泣。", "鑿沙到石終無水，擾擾萬人如渴蟻。", "挽絙竊出兩將軍，敵箭隨來風掠耳。", "道傍神馬白雪毛，噤口不嘶深夜逃。", "忽聞漢語米脂下，黑霧壓城風怒號。", "脫身歸來對刀筆，短衣射虎朝朝出。", "自椎雜寶塗箭創，心折骨驚如昨日。", "穀城魯公天下雄，陰陵一跌兵力窮。", "檥舟不渡謝亭長，有何面目歸江東。", "將軍偶生名已弱，鐵花暗澀龍文鍔。", "縞帳肥芻酬馬恩，閒望旄頭向西落。"]'),
('9539d965-2933-4fa4-953e-35f73027497e','曝日','周邦彥','宋','宋诗','song-poetry','','[]','冬曦如村釀，奇溫止須臾。',24,'全唐诗/poet.song.66000.json','["冬曦如村釀，奇溫止須臾。", "行行正須此，戀戀忽已無。"]'),
('12e8df7d-a126-43fe-8e81-440e7d27112f','越臺曲','周邦彥','宋','宋诗','song-poetry','','[]','玉顔如花越王女，自小矯癡不歌舞。',124,'全唐诗/poet.song.66000.json','["玉顔如花越王女，自小矯癡不歌舞。", "嫁作江南國主妃，日日思歸淚如雨。", "江南江北梅子黄，潮頭夜漲秦淮江。", "江邊雨多地卑濕，旋築高臺勻曉粧。", "千艘命載越中土，喜見越人仍越語。", "人生脚踏鄉土難，無復歸心越中去。", "高臺何易傾，曲池亦復平。", "越姬一去向千載，不見此臺空有名。"]'),
('4c1f8edc-38cd-495a-ae4b-3264c0660ef4','芝朮歌','周邦彥','宋','宋诗','song-poetry','','[]','華陽之天諸洞府，阿穴便門迷處所。',192,'全唐诗/poet.song.66000.json','["華陽之天諸洞府，阿穴便門迷處所。", "三君謁帝不知還，帳冷祠空遺鶴羽。", "玉津寶氣久成腴，靈朮神芝時出土。", "日精潜燭山自明，人力窮搜神不與。", "前年棟撓作新宮，坎坎空巖響斤斧。", "君來胎禽舞海雪，君去山雲雜川雨。", "是生朱草示塵寰，故遣樵青入林莽。", "蘗膏紫漆自堅栗，下附天蘇蟠石塢。", "肉人但恐奇禍作，藥籠復憂神物取。", "廬陵太守藴仙風，健骨清姿欲飛舉。", "陰功除瘼民已悅，靈藥引年天亦許。", "願因服餌斷膏粱，未讓南華養生主。"]'),
('d8b28964-7922-409b-916f-0901702a2c9b','楚平王廟','周邦彥','宋','宋诗','song-poetry','','[]','姦臣亂國紀，伍奢思結纓。',168,'全唐诗/poet.song.66000.json','["姦臣亂國紀，伍奢思結纓。", "殺賢恐遺種，巢卵同時傾。", "健雛脫身去，口血流吳庭。", "達士見幾微，楚郊憂苦兵。", "十年軍入郢，勢如波捲萍。", "賢亡國嬰難，王死屍受刑。", "將隳七世廟，先壞百里城。", "子胥雖捐江，素車駕長鯨。", "驚濤寄怒餘，遺廟羅千楹。", "王祠何其微，破屋風泠泠。", "蟄蟲陷香案，饑鼠懸燈檠。", "淫俗敬魑魅，何人顧威靈。", "臣冤不讎主，況乃鋤丘塋。", "報應苦不直，吾將問冥冥。"]'),
('fcdd4895-00b6-4186-af61-3636eb0b9ec2','竹城','周邦彥','宋','宋诗','song-poetry','','[]','竹城何檀欒，屬翠分雉堞。',24,'全唐诗/poet.song.66000.json','["竹城何檀欒，屬翠分雉堞。", "王封盡四塹，同有歲寒節。"]'),
('d0b43651-c825-4a96-bab5-2760653107d3','謾成  其一','周邦彥','宋','宋诗','song-poetry','','[]','舉頭萬籟號，彈指萬籟寂。',60,'全唐诗/poet.song.66000.json','["舉頭萬籟號，彈指萬籟寂。", "欲尋所歸方，變滅了無迹。", "古今何足云，浩劫同一息。", "曾聞不遷義，貞定非木石。", "至樂諒難名，所恨羅縠隔。"]'),
('ca9b9a34-887f-43bb-9abc-9960ba2a53d3','謾成  其二','周邦彥','宋','宋诗','song-poetry','','[]','河聲連底卷黄沙，回首方驚去國賒。',32,'全唐诗/poet.song.66000.json','["河聲連底卷黄沙，回首方驚去國賒。", "唯有客情無盡處，暗隨春水漲桃花。"]'),
('b6b15ceb-7d4a-419a-b692-adb24d409b4f','無題','周邦彥','宋','宋诗','song-poetry','','[]','石瀨光洄洄，沙步平侹侹。',96,'全唐诗/poet.song.66000.json','["石瀨光洄洄，沙步平侹侹。", "楓林名一社，舂汲共寒影。", "藩籬曲相通，窈窕花竹靜。", "茲焉自足樂，未覺丘園迥。", "令尹雖無恩，黠吏幸先屏。", "唯當謹時候，田廬日三省。", "驕兒休馬足，高廩付牛領。", "無人橫催租，烹鮮會同井。"]'),
('1d1c430a-292d-4961-8bcc-39090b68caba','謾書  其一','周邦彥','宋','宋诗','song-poetry','','[]','窗影蠅飛見，簾花日照成。',48,'全唐诗/poet.song.66000.json','["窗影蠅飛見，簾花日照成。", "汗餘胡粉薄，香度越羅輕。", "書葉蠶頭密，調笙鳳咮鳴。", "情來愁不語，極目雁南征。"]'),
('07c0ab12-2374-4f64-8349-00f6c2e66037','謾書  其二','周邦彥','宋','宋诗','song-poetry','','[]','舊識回文譜，新諧遠調謳。',48,'全唐诗/poet.song.66000.json','["舊識回文譜，新諧遠調謳。", "望歸朝對鏡，合飲夜藏鈎。", "融蠟粘花蔕，燒檀暖麝油。", "雙眉誰與畫，張敞自風流。"]'),
('376730cc-fbae-4aa8-b438-c3de4a2cb92d','謾書  其三','周邦彥','宋','宋诗','song-poetry','','[]','麗日烘簾幔影斜，酒餘春思托韶華。',32,'全唐诗/poet.song.66000.json','["麗日烘簾幔影斜，酒餘春思托韶華。", "高樓不隔東南望，苦霧游雲莫謾遮。"]'),
('183a1a91-3f7a-425c-88f0-29519c33f666','偶成','周邦彥','宋','宋诗','song-poetry','','[]','窗風獵獵舉綃衣，睡美唯應枕簟知。',32,'全唐诗/poet.song.66000.json','["窗風獵獵舉綃衣，睡美唯應枕簟知。", "忽有黄鸝深樹語，宛如春盡綠陰時。"]'),
('04fda446-a942-4c6e-90b1-563daaba8db4','天啟惠酥  其一','周邦彥','宋','宋诗','song-poetry','','[]','金城良牸不當車，特爲人間作好酥。',64,'全唐诗/poet.song.66000.json','["金城良牸不當車，特爲人間作好酥。", "餘湩尚供肥犢子，小匳先入太官厨。", "鄴中鹿尾空名目，吳地蓴羹謾僻迂。", "欲比君家好兄弟，不知誰可作醍醐。"]'),
('329a0ff6-61bd-44a0-b5d9-a8567f0cb458','天啟惠酥  其二','周邦彥','宋','宋诗','song-poetry','','[]','淺黄拂拂小鵝雛，色好從來說雍酥。',64,'全唐诗/poet.song.66000.json','["淺黄拂拂小鵝雛，色好從來說雍酥。", "花草偏宜女兒手，緘封枉入野人厨。", "細塗麥餠珍無敵，雜煉豬肪術最迂。", "臠肉便知全鼎味，它時不用識醍醐。"]'),
('0e6f85b2-212b-4ad0-a96b-4ca6e51da309','天啟惠酥  其三','周邦彥','宋','宋诗','song-poetry','','[]','南朝珍饌一時無，尚見休文謝北酥。',64,'全唐诗/poet.song.66000.json','["南朝珍饌一時無，尚見休文謝北酥。", "陶罋解湯香出屋，銅鐺掠面乳供厨。", "中都價重無錢買，京兆書遲怪路迂。", "聞道加餐最肥澤，異時煩與致醍醐。"]'),
('c6d6bdf6-969d-442c-9c6f-e629b39d99c7','天啟惠酥  其四','周邦彥','宋','宋诗','song-poetry','','[]','高陽太守有遺書，親教齊民煉玉酥。',64,'全唐诗/poet.song.66000.json','["高陽太守有遺書，親教齊民煉玉酥。", "欲出浮膏先卧酪，爲防饞鼠更薰厨。", "絕知意重分餘棄，漸見詩多入怪迂。", "猶恐傖人笑風土，預從貝葉檢醍醐。"]'),
('a62d225d-66fe-4063-ba8c-791e98c787b8','下帷齋','周邦彥','宋','宋诗','song-poetry','','[]','官事如拔毛，小稀還復稠。',132,'全唐诗/poet.song.66000.json','["官事如拔毛，小稀還復稠。", "一鼠未易盡，況欲禿九牛。", "唯應理籤軸，偷暇尋孔周。", "維南有頹構，疇昔賓射侯。", "扶傾與丹雘，外好中實不。", "弦歌廢决拾，休王良有由。", "書生本不武，誰言負薪憂。", "古云不執弓，防患術已媮。", "詩書主六藝，中有捍敵謀。", "至勝不刃血，吾將執其柔。", "當有中的士，爲辨劣與優。"]'),
('5cff3a57-1a56-43c3-a4d0-72f9b1450ce6','楚村道中  其一','周邦彥','宋','宋诗','song-poetry','','[]','林棲野啄散鴉群，極目風霾亂日曛。',64,'全唐诗/poet.song.66000.json','["林棲野啄散鴉群，極目風霾亂日曛。", "短麥離離乾憶雨，遠峰黯黯細輸雲。", "愁逢雜路尋車轍，頼有高林出酒巾。", "輒得問津凡父老，不應看客廢鋤耘。"]'),
('a1103b97-391b-43c2-9160-2e1761be3160','楚村道中  其二','周邦彥','宋','宋诗','song-poetry','','[]','族雲行太虛，布置初狼籍。',192,'全唐诗/poet.song.66000.json','["族雲行太虛，布置初狼籍。", "彌縫天四維，俄頃同一色。", "雨形如別淚，含惡未忍滴。", "泥塗頗翻車，行者自朝夕。", "中央成白道，裊裊踏蛇脊。", "潺湲冒田水，去作澗底碧。", "高林蔭清快，渴烏時一擲。", "晚休張莊聚，涇草蒙古驛。", "往時解鞍地，醉墨棲壞壁。", "孤星探先出，天鏡小摩拭。", "比鄰忽喧呼，夜磔魯津伯。", "夢歸萱草堂，再拜悲喜劇。", "問言勞如何，嗟我子行役。", "平明看屋霤，兩鵲聲嘖嘖。", "果逢南使還，馮寄好消息。", "誰秣百里駒，肯稅不論直。"]'),
('3a3d8f4f-d4ec-4a60-abf5-d4e12c7144b4','懷隠堂','周邦彥','宋','宋诗','song-poetry','','[]','昔賢抱奇識，閱世猶鼠肝。',180,'全唐诗/poet.song.66000.json','["昔賢抱奇識，閱世猶鼠肝。", "深顰畏軒冕，自謂山林寬。", "至今仰高躅，凜若冰雪寒。", "我侯坐少孤，久著聚鶡冠。", "辛勤取微鷃，屢費黄金丸。", "歸來長太息，依舊一瓢簞。", "偶逢隠者谷，愛此高巑岏。", "結廬面絕壁，所幸一枝安。", "侯今未全老，每據伏波鞍。", "曷不持長纓，取虜報縣官。", "功名事不磨，未可樂丘墦。", "嗟我如鷦鷯，盡室寄葦萑。", "謀居轉幽邃，欲把嚴陵竿。", "歸乏環堵室，始覺生理難。", "因侯有華構，彌起百憂端。"]'),
('f1f68e46-f043-46fc-ab97-929cdff07cc7','夙興','周邦彥','宋','宋诗','song-poetry','','[]','曈曈海底日，赤輝射東方。',132,'全唐诗/poet.song.66000.json','["曈曈海底日，赤輝射東方。", "先驅斂群翳，微露不成霜。", "早寤厭床笫，起步東西廂。", "引手視掌紋，黯黯未可祥。", "念此閱人傳，三年得跧藏。", "弛擔曾幾時，茲焉忽騰裝。", "問今何所之，意行本無鄉。", "晨鐘神慘悲，夜鼓思飛揚。", "與俗同一科，何異犬與羊。", "平明催放鑰，利害紛相攘。", "顛倒走群愚，豈但渠可傷。"]'),
('ea8a6bf3-0666-4e2b-979c-a279ddc01bac','開元夜遊圖','周邦彥','宋','宋诗','song-poetry','','[]','潞州別駕年十八，彎弓射鹿無虛發。',321,'全唐诗/poet.song.66000.json','["潞州別駕年十八，彎弓射鹿無虛發。", "真龍絕水魚鼈散，參軍後騎鳬鷗沒。", "咸原瑞氣映壺關，城南書生知阿瞞。", "解鞍下馬日向夕，炙馿行酒天爲歡。", "坐上何人識天意，擫帽破靴朝邑尉。", "旄頭夜轉紫垣開，太白光芒黄鉞利。", "萬騎齊呼左右分，將軍夜披玄武門。", "鏖兵三窟盡妖黨，問寢五門朝至尊。", "羽林蕭蕭參旗折，太極瑶光浄烟雪。", "殺身志在攀龍鱗，唾手成功探虎穴。", "麾下且侯李與王，輕形玉带持箙房。", "晉文賞功從悉錄，漢光道舊情無忘。", "與宴宮中張秘戲，複道晴樓過李騎。", "連催羯鼓汝陽來，一抹鯤弦薛王醉。", "玉階凄凄微有霜，天雞喚仗參差光。", "宜春列炬散行馬，長樂疏鍾嚴曉妝。", "清絲急管歡未畢，瑶池八馬西南出。", "捫參歷井行道難，失水回風永相失。", "君不見當時韋杜間，呼鷹走狗去不還。", "坐間年少莫大語，臨淄郡王天子父。"]'),
('48c29f54-9737-4a7c-a24e-6cd090d1ab50','遠游','周邦彥','宋','宋诗','song-poetry','','[]','淮西渡兩槳，江左隨一鷗。',120,'全唐诗/poet.song.66000.json','["淮西渡兩槳，江左隨一鷗。", "苦嗟波濤窄，所至膠吾舟。", "借問舟中人，流轉何時休。", "帆高風色利，欲止不自由。", "傳聞弱水外，鼎立三神丘。", "鼓枻未可到，載行有潜虯。", "扶桑睹浴日，陽精熱東流。", "萬族呈秘怪，九土皆飄浮。", "送者安在哉，吾往不可求。", "豈比鴟夷子，並湖名遠游。"]'),
('cc3d7ad4-9c8d-4f59-a6f3-18c4379e2423','晚憩杜橋館','周邦彥','宋','宋诗','song-poetry','','[]','寒茅愔愔雞啄場，兒啼索衣天隕霜。',128,'全唐诗/poet.song.66000.json','["寒茅愔愔雞啄場，兒啼索衣天隕霜。", "密林漸放山色入，楓枯振槁聲琅琅。", "清漿白羽棄已久，黄菊紫萸看欲香。", "歲行及此去愈疾，若决積水難隄防。", "嗟予齒髮非故物，念此內熱如涫湯。", "願見唐朝呂墨客，膝行問道求神方。", "齋心千日百事畢，消我頷雪還韶光。", "豈饒蒿目憂世事，黄金綰腰埋土囊。"]'),
('32065c5c-2161-4389-ab24-f1fb360217f7','游定夫見過晡飯既去燭下目昏不能閱書感而賦之','周邦彥','宋','宋诗','song-poetry','','[]','烟草里門秋，暮氣幽人宅。',204,'全唐诗/poet.song.66000.json','["烟草里門秋，暮氣幽人宅。", "遙知金輪升，戶牖粲虛白。", "風驅雲將來，市聲落几格。", "連曹屬解鞚，一飯已掃迹。", "餘羶未潔鼎，傲鼠已出額。", "銅英洗病眼，烏舄畏斷冊。", "已爲兒輩翁，茲事豈不迫。", "昔見羨門生，童子身三尺。", "捐家問道要，顓聲不好劇。", "頗觀鳥跡書，保氣如保璧。", "貪餌投禍羅，煎絲廢前績。", "上慚玄元教，溘死有餘責。", "濁鏡在兩眸，看朱忽成碧。", "當時方瞳叟，變滅雲霧隔。", "肝勞憂久痼，瞑坐救昏幕。", "尚須文字間，侵盡百年客。", "非圖矚秋毫，所要分菽麥。"]'),
('470b9c2b-afe3-48d3-a940-31d49b094ac1','元夕','周邦彥','宋','宋诗','song-poetry','','[]','翠華臨闕巷無人，曼衍魚龍觸眼新。',64,'全唐诗/poet.song.66000.json','["翠華臨闕巷無人，曼衍魚龍觸眼新。", "羽蝶低昂萬人醉，木山綵錯九城春。", "閑坊厭聽粻䊗鼓，曉漏猶飛轣轆塵。", "誰解招邀狂處士，摻撾驚倒坐中賓。"]'),
('3935651d-82c7-4fe5-9aa2-c48d9ed0e40a','壽宋守  其一','周邦彥','宋','宋诗','song-poetry','','[]','康鼎談經世少雙，一時文物動虞庠。',64,'全唐诗/poet.song.66000.json','["康鼎談經世少雙，一時文物動虞庠。", "江湖雖隔金閨籍，衣袖仍間玉案香。", "墨客幾年陪畫隼，板輿平日到萱堂。", "時清身健堪行樂，未見荆榛尤鳳凰。"]'),
('5d3178ed-6031-4fc8-a0d7-10c849fa93f0','壽宋守  其二','周邦彥','宋','宋诗','song-poetry','','[]','珥筆曾趨殿兩間，冰姿清徹照朝班。',64,'全唐诗/poet.song.66000.json','["珥筆曾趨殿兩間，冰姿清徹照朝班。", "民謳在處思廉范，諫疏何人憶賈山。", "竹簡繙經秋閉閣，玉棋歡客夜留關。", "直須剩飲邦人壽，天上如今欲賜環。"]'),
('4d3b8008-dad6-42a6-8356-6d809b92cb1d','壽陳運幹','周邦彥','宋','宋诗','song-poetry','','[]','節過中和日有三，台星一點下江南。',64,'全唐诗/poet.song.66000.json','["節過中和日有三，台星一點下江南。", "因仍睿算疏恩寵，多少春風在笑談。", "頌祝椒花隨以栢，恩袍欺草綠於藍。", "兒孫更祝無窮壽，齊指莊椿願與參。"]'),
('7e8c92fe-a11d-4016-a4eb-d57423f31e8d','宿靈仙觀','周邦彥','宋','宋诗','song-poetry','','[]','靈宮耽耽虎守谷，羽褐出山邀客宿。',64,'全唐诗/poet.song.66000.json','["靈宮耽耽虎守谷，羽褐出山邀客宿。", "稽首中茅司命君，四葉秉符調玉燭。", "鳴金擊石天相聞，游飆倒影聲磷磷。", "戲上雲崖撼瓊樹，脫葉出溪驚世人。"]'),
('edfeb71c-f300-4d2f-b8fe-8f025e2f53f9','次韵周朝宗六月十日泛湖  其一','周邦彥','宋','宋诗','song-poetry','','[]','霖潦合支流，洲浦迷片段。',48,'全唐诗/poet.song.66000.json','["霖潦合支流，洲浦迷片段。", "兩槳入菰蒲，鳬鷗欻驚散。", "疏林直炊烟，落日斜酒幔。", "王事得淹留，公私各相半。"]'),
('45c73f3f-f2d7-43f5-b2a2-de7260210ce6','次韵周朝宗六月十日泛湖  其二','周邦彥','宋','宋诗','song-poetry','','[]','風舟挽猶遲，兀若乘款段。',48,'全唐诗/poet.song.66000.json','["風舟挽猶遲，兀若乘款段。", "深行蛟龍國，颭蕩光炯散。", "洲凉扇荷箑，山晚垂雲幔。", "眷言江海期，百年行欲半。"]'),
('3c78438a-b9c4-48e6-8aa4-fa3a636c3972','次韵周朝宗六月十日泛湖  其三','周邦彥','宋','宋诗','song-poetry','','[]','溝塍繞湖干，瑣細分頃段。',48,'全唐诗/poet.song.66000.json','["溝塍繞湖干，瑣細分頃段。", "湖洄晚漁集，山靜村樵散。", "衝風偃萑菼，獵獵如捲幔。", "何當飲清光，乘月行夜半。"]'),
('86ab015f-f1c9-4b0b-a590-f0f885d2af07','次韵周朝宗六月十日泛湖  其四','周邦彥','宋','宋诗','song-poetry','','[]','維舟瞰層波，未忍分練段。',48,'全唐诗/poet.song.66000.json','["維舟瞰層波，未忍分練段。", "人間好風味，魚鳥同聚散。", "儒生長窘束，書燈守幽幔。", "逐樂嗟已遲，蚤還猶及半。"]'),
('400f3a5c-2dd9-4887-84da-871d956924b7','次韵周朝宗六月十日泛湖  其五','周邦彥','宋','宋诗','song-poetry','','[]','君才切玉刀，一舉成兩段。',48,'全唐诗/poet.song.66000.json','["君才切玉刀，一舉成兩段。", "我如摶沙礫，放手輒星散。", "傳聞紫貝闕，薜荔充帷幔。", "楚吟尚多亡，君詩補其半。"]'),
('07672f6e-c4d3-4c91-8087-2e8bb818e4e1','二月十四日至越州置酒泛湖欲往諸剎風作不能前','周邦彥','宋','宋诗','song-poetry','','[]','青山定厭俗人遊，蘿帳雲屏到即收。',32,'全唐诗/poet.song.66000.json','["青山定厭俗人遊，蘿帳雲屏到即收。", "更欲凌波訪幽剎，疾風已戒早回舟。"]'),
('21532a32-7301-4dd9-8ccd-cba222b7726c','句  其一','周邦彥','宋','宋诗','song-poetry','','[]','化行禹貢山川外，人在周公禮樂中。',16,'全唐诗/poet.song.66000.json','["化行禹貢山川外，人在周公禮樂中。"]'),
('4a58df9e-8b7f-4cb1-b1dd-6bfb4d859fa8','句  其二','周邦彥','宋','宋诗','song-poetry','','[]','明朝春仗當行樂，刻燕催花擲萬金。',16,'全唐诗/poet.song.66000.json','["明朝春仗當行樂，刻燕催花擲萬金。"]'),
('08906116-acc5-4bdd-b57f-82f9e77a3272','句  其三','周邦彥','宋','宋诗','song-poetry','','[]','夾輦司花百士人，繡楣瓊璧寫宜春。',16,'全唐诗/poet.song.66000.json','["夾輦司花百士人，繡楣瓊璧寫宜春。"]'),
('f62fe379-b444-44b4-8b4f-783036a93876','句  其四','周邦彥','宋','宋诗','song-poetry','','[]','裁幡小廢藏鈎戲，生菜仍□宿歲□。',16,'全唐诗/poet.song.66000.json','["裁幡小廢藏鈎戲，生菜仍□宿歲□。"]'),
('5f91a3cd-0620-4365-a46d-c884ec0785ff','句  其五','周邦彥','宋','宋诗','song-poetry','','[]','對花今日柰天涯。',8,'全唐诗/poet.song.66000.json','["對花今日柰天涯。"]'),
('6f1884ed-afbb-4b4d-b521-0458d9ce8c89','句  其六','周邦彥','宋','宋诗','song-poetry','','[]','人從生處樂，誰向死前休。',12,'全唐诗/poet.song.66000.json','["人從生處樂，誰向死前休。"]'),
('c003e22c-7d25-46c8-b479-fb2f5d9f40b8','吳熙老所藏風雨圖','潘大臨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我遊匡山夏將杪，赤日青天萬山繞。',176,'全唐诗/poet.song.66000.json','["我遊匡山夏將杪，赤日青天萬山繞。", "忽然風雨動地來，震氣果雷離電遶。", "一川烟靄失東西，萬里乾坤錯昏曉。", "香罏高峰危欲墮，石門細路人心剿。", "江翻那聞得計魚，木拔豈有安巢鳥。", "須臾雲過雨脚收，依舊晴暉著叢篠。", "羣山歷歷在眼前，恰似憑高日方曉。", "誰將此景入畫圖，數幅生綃盤礴了。", "吳丞此畫絕代無，張公此詩古來少。", "讀詩觀畫興未窮，北窗風凉退自公。", "使君意消三伏中，未可鞭箠催青銅。"]'),
('c783ee14-8843-474c-9d1a-fdee1fa2f6a4','贈張聖言畫柯山圖','潘大臨','宋','宋诗','song-poetry','','[]','我昔騎鯨游九州，上扣天關望冕旒。',192,'全唐诗/poet.song.66000.json','["我昔騎鯨游九州，上扣天關望冕旒。", "羣公侍旁好顔色，將順帝旨成剛柔。", "抱持日月不自獻，蒙茸塵土歸家丘。", "結茅竹間今休已，炎暑避舍清飆留。", "屋頭清溪鳴晝夜，當戶古木蔽馬牛。", "蒼頭盧兒從高蓋，傳呼不到門巷幽。", "兩公忘言兒袖手，驅除睡魔須茶甌。", "誰傳此意到旁郡，解衣槃礴煩張侯。", "張侯落筆妙天下，未墜學士之風流。", "欲見柯山入畫圖，丹青知君百不憂。", "黄公不肯直南省，一麾已具東南舟。", "請君援筆待公至，畫我迎公竹陰裏。"]'),
('31a2c863-0bf2-4bb0-8a59-f631fa7c90de','題張聖言畫四時景物  其一','潘大臨','宋','宋诗','song-poetry','','[]','我到淮南幾見春，一身蓑笠蔽烟雨。',32,'全唐诗/poet.song.66000.json','["我到淮南幾見春，一身蓑笠蔽烟雨。", "桃花林裏有人家，疑是柯山最深處。"]'),
('e12343f9-77f9-4eb2-a71d-76c72b687dab','題張聖言畫四時景物  其二','潘大臨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','成陰衆木與天參，日暮風雨地軸翻。',32,'全唐诗/poet.song.66000.json','["成陰衆木與天參，日暮風雨地軸翻。", "曾向廬山問行李，石門西路接僧垣。"]'),
('cd160b5d-c4ee-42b3-ac32-71071588eacc','題張聖言畫四時景物  其三','潘大臨','宋','宋诗','song-poetry','','[]','荻花索索水津津，日落空山開霽新。',32,'全唐诗/poet.song.66000.json','["荻花索索水津津，日落空山開霽新。", "松下有人摩詰似，與渠烟火作比鄰。"]'),
('81184358-c8fb-4b6b-893d-45acd81431a7','題張聖言畫四時景物  其四','潘大臨','宋','宋诗','song-poetry','','[]','雲蒙山頭雪翻空，飛鳥繞樹困號風。',32,'全唐诗/poet.song.66000.json','["雲蒙山頭雪翻空，飛鳥繞樹困號風。", "關山淮水失微路，酒爐曾借衰顔紅。"]'),
('a3c31bd2-628f-4f95-a8f3-37af334ece90','題陳德秀畫四季枕屏圖五首  其一','潘大臨','宋','宋诗','song-poetry','','[]','亂山深處碧波流，隔岸垂楊繫小舟。',32,'全唐诗/poet.song.66000.json','["亂山深處碧波流，隔岸垂楊繫小舟。", "無數桃花伴春夢，夢中還作武陵遊。"]'),
('62517a51-3e8b-462e-8d80-425151cc576b','題陳德秀畫四季枕屏圖五首  其二','潘大臨','宋','宋诗','song-poetry','','[]','茅簷竹閣枕迴溪，柳外平橋拍水低。',32,'全唐诗/poet.song.66000.json','["茅簷竹閣枕迴溪，柳外平橋拍水低。", "在藻白魚知鷺下，穿林黄雀覺蟬嘶。"]'),
('bf7221c0-fa73-4da5-9519-ad8d51e711c3','題陳德秀畫四季枕屏圖五首  其三','潘大臨','宋','宋诗','song-poetry','','[]','錦樹連雲爛不收，山河風景一番秋。',32,'全唐诗/poet.song.66000.json','["錦樹連雲爛不收，山河風景一番秋。", "老夫枕簟便凉夜，不比新亭去國愁。"]'),
('0684580b-a6dd-45c4-ba1e-3a75be7ce320','題陳德秀畫四季枕屏圖五首  其四','潘大臨','宋','宋诗','song-poetry','','[]','江樹溟濛雪暗天，似聞寒雁破昏烟。',32,'全唐诗/poet.song.66000.json','["江樹溟濛雪暗天，似聞寒雁破昏烟。", "相思此夜堪乘興，試問漁翁覓釣船。"]'),
('34420659-795d-46ca-b52d-85010d9d30e2','題陳德秀畫四季枕屏圖五首  其五','潘大臨','宋','宋诗','song-poetry','','[]','好景入詩皆可畫，未知陳子畫中詩。',32,'全唐诗/poet.song.66000.json','["好景入詩皆可畫，未知陳子畫中詩。", "疑公便是褚季野，正爾不言行四時。"]'),
('a6f529bb-b0b9-41ad-af2a-dcbbd9ae554a','題趙承遠所藏大年畫平遠二首  其一','潘大臨','宋','宋诗','song-poetry','','[]','吳頭楚尾散花洲，天闊波雲恰下鷗。',32,'全唐诗/poet.song.66000.json','["吳頭楚尾散花洲，天闊波雲恰下鷗。", "帝子胸中有江漢，故能風露筆端秋。"]'),
('68236915-c367-438f-966c-c53d32683290','題趙承遠所藏大年畫平遠二首  其二','潘大臨','宋','宋诗','song-poetry','','[]','將軍心眼到滄洲，木脫波生一夜秋。',32,'全唐诗/poet.song.66000.json','["將軍心眼到滄洲，木脫波生一夜秋。", "想得筆端鳬雁足，又添鸂鶒起沙頭。"]'),
('a4629b6e-2db6-4662-9391-9bc9ebc29182','江夏別魯直送之宜州','潘大臨','宋','宋诗','song-poetry','','[]','翰墨精神全魏漢，文章波瀾似春秋。',32,'全唐诗/poet.song.66000.json','["翰墨精神全魏漢，文章波瀾似春秋。", "可是中州著不得，江南已遠更宜州。"]'),
('a0af54ea-1e7b-48b0-b1c2-40560b7b907a','詩一首','潘大臨','宋','宋诗','song-poetry','','[]','胡子雲中白鶴，林生初發芙蓉。',112,'全唐诗/poet.song.66000.json','["胡子雲中白鶴，林生初發芙蓉。", "吳十九成雅奏，饒三百煉奇鋒。", "南州復見高士，東山行起謝公。", "信祖真成德祖，立之無愧行中。", "吳生可共南郡，老夫寧附石崇。", "聞雅已傾重客，說談仍得王戎。", "冠蓋城南高會，山陰未掃餘風。", "客散日銜西壁，主人不道尊空。"]'),
('3783bed3-2ac4-407b-b290-38871fa95f05','張文潜齊安行解嘲','潘大臨','宋','宋诗','song-poetry','','[]','爲邦雖陋勿雌黄，我曾侍立蘇公旁。',48,'全唐诗/poet.song.66000.json','["爲邦雖陋勿雌黄，我曾侍立蘇公旁。", "見公顔色不憔悴，不似賈誼來江湘。", "它州雖粗勝吾州，無此兩公相繼游。"]'),
('b3a0c7ba-0afd-4cfa-97be-c09f02adbe91','哭東坡  其一','潘大臨','宋','宋诗','song-poetry','','[]','元祐絲綸兩漢前，典刑意得龍光宣。',32,'全唐诗/poet.song.66000.json','["元祐絲綸兩漢前，典刑意得龍光宣。", "裕陵聖德如天大，誰道微臣敢議天。"]'),
('39b2eaa9-c8f6-4e8a-a175-2e8d933583e6','哭東坡  其二','潘大臨','宋','宋诗','song-poetry','','[]','公與文忠總遇讒，讒人有口直須緘。',32,'全唐诗/poet.song.66000.json','["公與文忠總遇讒，讒人有口直須緘。", "聲名百世誰常在，公與文忠北斗南。"]'),
('cec61d64-a27b-49d1-ae51-9be4f8dc84a8','寄德操均父','潘大臨','宋','宋诗','song-poetry','','[]','文如二稚徒懷璧，武似三明却韔弓。',32,'全唐诗/poet.song.66000.json','["文如二稚徒懷璧，武似三明却韔弓。", "松檜參天西邑路，時時騎馬訪龐公。"]'),
('44ff04be-e8bd-47f3-b7c1-c93b8fa1d641','江間作  其一','潘大臨','宋','宋诗','song-poetry','','[]','白鳥沒飛烟，微風逆上舡。',48,'全唐诗/poet.song.66000.json','["白鳥沒飛烟，微風逆上舡。", "江從樊口轉，山自武昌連。", "日月懸終古，乾坤別逝川。", "羅浮南斗外，黔府古河邊。"]'),
('ec14b3d9-a618-49f2-ad05-386cbdb1b738','江間作  其二','潘大臨','宋','宋诗','song-poetry','','[]','波浪三江口，風雲八字山。',48,'全唐诗/poet.song.66000.json','["波浪三江口，風雲八字山。", "斷崖東北際，虛艇有無間。", "卧柳堆生岸，跳魚水擣彎。", "悠然小軒冕，幽興滿鄉關。"]'),
('ab97d2c5-9af9-4895-85b7-e80ca7771f2c','江間作  其三','潘大臨','宋','宋诗','song-poetry','','["\u6292\u6000", "\u5199\u666f", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143", "\u548f\u53f2\u6000\u53e4"]','西山連虎穴，赤壁隠龍宮。',48,'全唐诗/poet.song.66000.json','["西山連虎穴，赤壁隠龍宮。", "形勝三分國，波流萬世功。", "沙明拳宿鷺，天闊退飛鴻。", "最羨魚竿客，歸舡雨打篷。"]'),
('c09abde1-ad7d-49b8-9410-c8b7e663c49e','江間作  其四','潘大臨','宋','宋诗','song-poetry','','[]','落日春江上，無人倚杖時。',48,'全唐诗/poet.song.66000.json','["落日春江上，無人倚杖時。", "私蛙鳴鼓吹，官柳舞腰支。", "獵遠頻翻臂，漁深數治絲。", "我猶無彼是，風豈有雄雌。"]'),
('72d9f105-dc41-4e18-b92c-74cdd5cadfa2','洪氏倦殻軒','潘大臨','宋','宋诗','song-poetry','','[]','封胡羯末謝，龜駒玉鴻洪。',24,'全唐诗/poet.song.66000.json','["封胡羯末謝，龜駒玉鴻洪。", "千載望四謝，四洪天壤同。"]'),
('33c8aee1-605d-4039-99df-5c0134b2cf7d','和張文潜痛字韵','潘大臨','宋','宋诗','song-poetry','','[]','文章邇來氣燄低，聖經頗遭餘子弄。',32,'全唐诗/poet.song.66000.json','["文章邇來氣燄低，聖經頗遭餘子弄。", "公歸除□□□□，荆舒之說懲應痛。"]'),
('67c78986-4632-46d9-98a8-ccad13f5d85a','浯溪','潘大臨','宋','宋诗','song-poetry','','[]','公泛浯溪春水船，繫帆啼鳥青崖邊。',192,'全唐诗/poet.song.66000.json','["公泛浯溪春水船，繫帆啼鳥青崖邊。", "次山作頌今幾年，當時治亂春風前。", "明皇聰明真晚謬，乾坤付與哥奴手。", "骨肉何傷九廟焚，蜀山騎馿不回首。", "天下寧知再有唐，皇帝紫袍迎上皇。", "神器蒼忙吾敢惜，兒不終孝聽五郎。", "父子幾何不豺虎，君臣寧能責胡虜。", "南內凄凉誰得知，人間稱家作端午。", "平生不識顔真卿，去年不答高將軍。", "老來讀碑淚橫臆，公詩與碑當共行。", "不賞邊功寧有許，不殺奉皇猶敢語。", "雨淋日炙字未訛，千秋萬歲所鑒多。"]'),
('b2f457a1-0a6b-4cf0-880b-4beacaf6332d','春日書懷','潘大臨','宋','宋诗','song-poetry','','[]','舟楫凌漳水，風濤接蠡湖。',240,'全唐诗/poet.song.66000.json','["舟楫凌漳水，風濤接蠡湖。", "龍媒成跬步，驪頷脫微軀。", "樂土供遊戲，深文苦縶拘。", "胸中雖磈磊，牆外或歌呼。", "老去嵇康懶，歸來甯子愚。", "千鍾真臭腐，十畮借膏腴。", "春雨何曾密，園花竟自都。", "小橋藏細柳，方沼出新蒲。", "酒熟拈巾漉，經傳带雨鋤。", "行盤隨所有，坐客幾時無。", "日轉淮陰暮，門通鳥逕迂。", "仰頭看哺鷇，引手亦將雛。", "撫事盆繅繭，勞生戶轉樞。", "形骸浮大塊，毛髮燎紅爐。", "借問青宮犢，何如濁水鳬。", "士衡甘食酪，張翰合思鱸。", "世論幾膠柱，人心盡好竽。", "屠龍非至計，射雉屈良圖。", "借箸方隆漢，推枰已滅吳。", "從渠畫麟閣，吾自著潜夫。"]'),
('183c7cc2-7a99-4be2-8dfa-b77ccb99a93e','答王立之惠書','潘大臨','宋','宋诗','song-poetry','','[]','歸自江南即定居，漫勞親友問何如。',64,'全唐诗/poet.song.66000.json','["歸自江南即定居，漫勞親友問何如。", "剛腸肯爲藜羹轉，病骨聊憑竹杖扶。", "南圃土腴千樹橘，東湖春水百金魚。", "明年生計應堪說，待倩君侯買異書。"]'),
('6238569b-f5cd-4cf8-a912-a562021f428e','梅','潘大臨','宋','宋诗','song-poetry','','[]','非雲非雪月初浮，疑是佳人狐白裘。',32,'全唐诗/poet.song.66000.json','["非雲非雪月初浮，疑是佳人狐白裘。", "細雨狂風莫欺折，冰肌玉骨未禁愁。"]'),
('aef6f66f-f641-446a-a06b-4c71efee31ef','登大別眺望','潘大臨','宋','宋诗','song-poetry','','[]','人爭漢口渡，日落陽臺坂。',24,'全唐诗/poet.song.66000.json','["人爭漢口渡，日落陽臺坂。", "鼓吹隔岸聞，樓觀排雲見。"]'),
('36361d63-368a-480a-b9c3-f4885dcbd6af','次韵黄澤簡亭','潘大臨','宋','宋诗','song-poetry','','[]','使者旌麾開晝陰，幽亭萬个竹竿深。',64,'全唐诗/poet.song.66000.json','["使者旌麾開晝陰，幽亭萬个竹竿深。", "月乘佛界生清影，風入僧垣作好音。", "活國五年持節手，補天三尺轉圜心。", "召還有命方乘傳，莫遣幽人氣象侵。"]'),
('2c6d0423-bb42-4c47-8e6a-c8785b4f74c7','句  其一','潘大臨','宋','宋诗','song-poetry','','[]','滿城風雨近重陽。',8,'全唐诗/poet.song.66000.json','["滿城風雨近重陽。"]'),
('fabdd733-3266-4658-bbdd-dfaa4033491b','句  其二','潘大臨','宋','宋诗','song-poetry','','[]','兩屐上層樓，一目略千里。',12,'全唐诗/poet.song.66000.json','["兩屐上層樓，一目略千里。"]'),
('592e6b46-0b2a-41aa-b5c3-1034d5d6a622','句  其三','潘大臨','宋','宋诗','song-poetry','','[]','歸來陶隠居，拄頰西山雲。',12,'全唐诗/poet.song.66000.json','["歸來陶隠居，拄頰西山雲。"]'),
('e4d672a0-67da-431c-8d54-a072f162f203','句  其四','潘大臨','宋','宋诗','song-poetry','','[]','思君带孔移。',6,'全唐诗/poet.song.66000.json','["思君带孔移。"]'),
('9423d224-d539-4dfb-bd9b-fac6a54a277d','句  其五','潘大臨','宋','宋诗','song-poetry','','[]','詩束牛腰藏舊稿，書訛馬尾辨新讎。',16,'全唐诗/poet.song.66000.json','["詩束牛腰藏舊稿，書訛馬尾辨新讎。"]'),
('217dd77e-4f9c-41d1-96af-212a8a540fcb','句  其六','潘大臨','宋','宋诗','song-poetry','','[]','無酒到愁邊。',6,'全唐诗/poet.song.66000.json','["無酒到愁邊。"]'),
('d202b6d1-8083-4487-ab74-f3738a6590f3','句  其七','潘大臨','宋','宋诗','song-poetry','','[]','八字山頭雁，武昌江上魚。',12,'全唐诗/poet.song.66000.json','["八字山頭雁，武昌江上魚。"]'),
('f52a41cf-937f-4cd8-9613-10205d8ab36b','與葛洪','張璹','宋','宋诗','song-poetry','','[]','提司坑冶是新差，職比催綱勝一階。',32,'全唐诗/poet.song.66000.json','["提司坑冶是新差，職比催綱勝一階。", "若發薦章求脚色，下官蹤跡轉沉埋。"]'),
('3d92be1f-2b49-49b8-9f90-bd5b6e84d220','題萬竹山','薛昂','宋','宋诗','song-poetry','','[]','萬竹山中數十家，重重流水遶桑麻。',32,'全唐诗/poet.song.66000.json','["萬竹山中數十家，重重流水遶桑麻。", "飽餐鼓腹成何事，桃李春來任自花。"]'),
('87d8e049-9227-486f-92ad-ec7f807d0ae8','湖堂','薛昂','宋','宋诗','song-poetry','','[]','一段風烟不可關，出門滿目是湖山。',64,'全唐诗/poet.song.66000.json','["一段風烟不可關，出門滿目是湖山。", "昔人華厦今何在，此日漁舟任自閒。", "風觀斬新霄漢上，龍洲依舊水雲間。", "歸來丘壑多幽趣，願與諸賢約往還。"]'),
('eb1cd1d5-229b-4699-bd95-6342400e74fc','太清軒','薛昂','宋','宋诗','song-poetry','','[]','雨餘山色千螺翠，風定湖光一鑑明。',32,'全唐诗/poet.song.66000.json','["雨餘山色千螺翠，風定湖光一鑑明。", "我是水晶宮裏客，暫來猶愛此軒清。"]'),
('5cf8c207-4e7d-4b3e-bd35-7a81a146a74c','題回山人畫像','薛昂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','道骨仙風一偉人，相逢東老最情親。',64,'全唐诗/poet.song.66000.json','["道骨仙風一偉人，相逢東老最情親。", "榴皮幻化人間世，藤葉牢籠物外身。", "璚蟻滿壺方丈曉，青蛇銜袖洞庭春。", "高名不朽垂千古，笑指西鄰幾劫塵。"]'),
('6f4c39a5-cfe8-4a2b-aed3-287f15275955','句  其一','薛昂','宋','宋诗','song-poetry','','[]','逢時可謂真千載，拜賜應須更萬回。',16,'全唐诗/poet.song.66000.json','["逢時可謂真千載，拜賜應須更萬回。"]'),
('29543569-7477-4ea0-8356-f52806e7a01d','句  其二','薛昂','宋','宋诗','song-poetry','','[]','歡聲如鳳來啣詔，喜氣如雞去揭竿。',16,'全唐诗/poet.song.66000.json','["歡聲如鳳來啣詔，喜氣如雞去揭竿。"]'),
('1af1310e-3057-4738-9f7a-5c3bac5ffe73','句','吳申李','宋','宋诗','song-poetry','','[]','潮頭高捲岸，雨脚半吞山。',12,'全唐诗/poet.song.66000.json','["潮頭高捲岸，雨脚半吞山。"]'),
('07d277ca-7530-4ab2-8d77-6ddc08ba2351','句  其一','張順之','宋','宋诗','song-poetry','','[]','憑誰爲寫無聲詩，清標不減淵明輩。',16,'全唐诗/poet.song.66000.json','["憑誰爲寫無聲詩，清標不減淵明輩。"]'),
('4c848e9d-4f6e-4b82-9d7a-1344525bdc0e','句  其二','張順之','宋','宋诗','song-poetry','','[]','簷鵲數聲清夢斷，出門一笑遇詩仙。',16,'全唐诗/poet.song.66000.json','["簷鵲數聲清夢斷，出門一笑遇詩仙。"]'),
('e1855878-0330-4e61-b613-ca31d13ff02b','句  其三','張順之','宋','宋诗','song-poetry','','[]','聊將遮日手，松下弄清泉。',12,'全唐诗/poet.song.66000.json','["聊將遮日手，松下弄清泉。"]'),
('dd28770b-65c1-40e0-9754-d5ef8fd6c539','句  其四','張順之','宋','宋诗','song-poetry','','[]','暗綠不遮春去路，亂紅翻作雨來天。',16,'全唐诗/poet.song.66000.json','["暗綠不遮春去路，亂紅翻作雨來天。"]'),
('be2392bb-1634-491c-9bb2-a81932a2a16a','句  其五','張順之','宋','宋诗','song-poetry','','[]','白水一泓澄，茲山定玉骨。',12,'全唐诗/poet.song.66000.json','["白水一泓澄，茲山定玉骨。"]'),
('89aa33a1-fe1d-4549-a476-a8c2cd95388a','句  其六','張順之','宋','宋诗','song-poetry','','[]','金衣數公子，端是賢友生。',24,'全唐诗/poet.song.66000.json','["金衣數公子，端是賢友生。", "羽毛元自好，喉舌向來清。"]'),
('5ce85ff2-68f6-467f-b33c-705d02ba96e9','句  其七','張順之','宋','宋诗','song-poetry','','[]','照我胸中筆，吐出江淹文。',12,'全唐诗/poet.song.66000.json','["照我胸中筆，吐出江淹文。"]'),
('73dc816f-5f3e-4c1d-8f64-6eb3a59617f6','偶作','釋日益','宋','宋诗','song-poetry','','[]','金谷春光長滿眼，紅藥花梢香爛漫。',48,'全唐诗/poet.song.66000.json','["金谷春光長滿眼，紅藥花梢香爛漫。", "昨夜西風一陳寒，徧地殘芳落何限。", "王孫醉倒不知歸，猶向欄邊索金盞。"]'),
('9c55ecfe-b12d-432c-8cfb-70aa5df7a33e','作風伯新廟','楊四太尉','宋','宋诗','song-poetry','','[]','周官大宗伯，槱燎祀風師。',120,'全唐诗/poet.song.66000.json','["周官大宗伯，槱燎祀風師。", "祀典既已載，有廟非淫祠。", "吾鄉風伯廟，不知始何時。", "廟當浮玉嶼，鄉人同祭之。", "會席有煩言，社保成分離。", "爰來作新廟，奕奕東河涯。", "柱石若虎踞，簷桷如翬飛。", "香火既已分，牲牷交祝釐。", "神保降嘉福，四境風雨時。", "百穀總成熟，報祀千萬期。"]'),
('911152d0-776d-4b52-b973-d84f56103476','石橋','張康國','宋','宋诗','song-poetry','','[]','路轉下層崖，亂石通微徑。',48,'全唐诗/poet.song.66000.json','["路轉下層崖，亂石通微徑。", "山深萬象虛，葉脫千林靜。", "連苔蒼欲橫，衮雪飛泉迸。", "有睹那可言，寒烟日向暝。"]'),
('59efeff8-aff2-4274-96cd-5dd0d652cb8d','句','張康國','宋','宋诗','song-poetry','','[]','銀簷不雨溜常滴，玉樹無風花自開。',16,'全唐诗/poet.song.66000.json','["銀簷不雨溜常滴，玉樹無風花自開。"]'),
('251429d0-fe96-4591-965a-02aea4095bed','句','陳廓','宋','宋诗','song-poetry','','[]','滄江練遶清暉閣，古榭苔封燕喜碑。',16,'全唐诗/poet.song.66000.json','["滄江練遶清暉閣，古榭苔封燕喜碑。"]'),
('e2b4bbcc-14cc-44d0-9895-608666a6f3c9','題韓幹馬','高翔','宋','宋诗','song-poetry','','[]','渴烏項領紫駝峰，跑地求泉鬣上衝。',32,'全唐诗/poet.song.66000.json','["渴烏項領紫駝峰，跑地求泉鬣上衝。", "不敢牽來向江水，預防踴躍學蛟龍。"]'),
('aca903da-648b-4ff6-a1dc-e3d560a65e71','瓊林宴罷作','徐遹','宋','宋诗','song-poetry','','[]','白髮青衫晚得官，瓊林宴罷酒腸寬。',32,'全唐诗/poet.song.66000.json','["白髮青衫晚得官，瓊林宴罷酒腸寬。", "平康過盡無人問，留得宮花醒後看。"]'),
('dbb87e4b-d27f-44dc-b95c-7b938936e230','賦六人同舟赴省舉','徐遹','宋','宋诗','song-poetry','','[]','陳李張黄蘇與周，更添徐子分相投。',64,'全唐诗/poet.song.66000.json','["陳李張黄蘇與周，更添徐子分相投。", "竹林風月連三郡，北宿光芒聚一舟。", "作者定知同議論，爭臣頓是合謀猷。", "胸中各有平津策，此去知誰作狀頭。"]'),
('56cad504-caef-409e-8eac-cd2f0ce67fb0','句','吳羽','宋','宋诗','song-poetry','','[]','滁陽自昔稱名壘，舊有東園枕滁水。',16,'全唐诗/poet.song.66000.json','["滁陽自昔稱名壘，舊有東園枕滁水。"]'),
('912a0eb0-d7a5-4e4c-adcf-a03c692eb67b','古意','王實','宋','宋诗','song-poetry','','[]','少年紅顔女，敷芬對芳樹。',84,'全唐诗/poet.song.66000.json','["少年紅顔女，敷芬對芳樹。", "盈盈淡艷粧，清歌雜妙舞。", "凝睇倚高樓，桐絲試一譜。", "世間知音稀，誰識姱節素。", "清貞守幽閨，不作凡子婦。", "容華委西山，良人來何暮。", "空床思悠悠，明月正當戶。"]'),
('02457c4e-a3f5-41ff-9d0e-b336ceb99d36','和孫公索酒','劉延世','宋','宋诗','song-poetry','','[]','紫貂寒擁鼻，綠螘細侵唇。',24,'全唐诗/poet.song.66000.json','["紫貂寒擁鼻，綠螘細侵唇。", "蓮燭當時事，壺頭此日春。"]'),
('9f4eb7c0-75b6-473b-bde7-8a59f2d6a7ee','種竹','劉延世','宋','宋诗','song-poetry','','[]','梅蒸方過有餘潤，竹醉由來自古云。',32,'全唐诗/poet.song.66000.json','["梅蒸方過有餘潤，竹醉由來自古云。", "掘地聊栽數竿竹，開簾還當一溪雲。"]'),
('2b6d7c2a-fc1f-466a-bbfb-a9337ca7a506','自題墨竹','劉延世','宋','宋诗','song-poetry','','[]','酷愛此君心，常將墨點真。',24,'全唐诗/poet.song.66000.json','["酷愛此君心，常將墨點真。", "毫端雖在手，難寫淡精神。"]'),
('95578f9f-ac0c-47f6-9f34-44d75ada1d55','鷓鴣','劉延世','宋','宋诗','song-poetry','','[]','冥冥花朵隔遙山，脈脈風烟暗百蠻。',32,'全唐诗/poet.song.66000.json','["冥冥花朵隔遙山，脈脈風烟暗百蠻。", "曾向黄陵嘲竹裏，羽毛猶带淚痕斑。"]'),
('f664b621-a1a3-42aa-8930-727f185a47ca','翡翠','劉延世','宋','宋诗','song-poetry','','[]','避人忽起鳴衣桁，掠水飛來立釣磯。',32,'全唐诗/poet.song.66000.json','["避人忽起鳴衣桁，掠水飛來立釣磯。", "靜處欲留看不足，翠光點破夕陽歸。"]'),
('3912bb04-a7cc-4bb4-9da1-3b6080d7bd41','子規','劉延世','宋','宋诗','song-poetry','','[]','一聲迸裂青山竹，半夜沾殘病客衣。',32,'全唐诗/poet.song.66000.json','["一聲迸裂青山竹，半夜沾殘病客衣。", "還道離於天上去，不知何苦只思歸。"]'),
('6a816851-7176-47fc-b030-c56d7cbc2c28','水簾','劉延世','宋','宋诗','song-poetry','','[]','冷篩千嶂雨，寒□一鈎□。',24,'全唐诗/poet.song.66000.json','["冷篩千嶂雨，寒□一鈎□。", "不放香烟出，長教隔畫簷。"]'),
('653574a0-56fb-456e-969e-a6810a07c7ea','句  其一','劉延世','宋','宋诗','song-poetry','','[]','靜室焚香盤膝坐，長廊看畫散衣行。',16,'全唐诗/poet.song.66000.json','["靜室焚香盤膝坐，長廊看畫散衣行。"]'),
('e6b525f2-7995-4baf-b9ba-14ec7d8cbd8a','句  其二','劉延世','宋','宋诗','song-poetry','','[]','舟行明鑑裏。',6,'全唐诗/poet.song.66000.json','["舟行明鑑裏。"]'),
('9503877f-f85d-4660-be30-28d87a074bf2','藤溪懷古','鮑若虛','宋','宋诗','song-poetry','','[]','小橋流水去茫茫，隔岸何人在一方。',32,'全唐诗/poet.song.66000.json','["小橋流水去茫茫，隔岸何人在一方。", "傳道荆公曾曉渡，天風吹落五更霜。"]'),
('3266c38d-5029-443e-9c88-6de929fc7f7c','三峽堂  其一','宋肇','宋','宋诗','song-poetry','','[]','林巒十里上巉巖，飛檻初憑縹緲間。',64,'全唐诗/poet.song.66000.json','["林巒十里上巉巖，飛檻初憑縹緲間。", "夔子風烟依白帝，夜郎耕稼接烏蠻。", "砌橫亂石遙臨澗，門對高峰近带山。", "咫尺驚湍吁莫測，每來登此念鄉關。"]'),
('bef79eaa-2f79-44c5-995e-92fdeffe41b2','三峽堂  其二','宋肇','宋','宋诗','song-poetry','','[]','初尋磴道踏雪烟，漸引茅簷屋數椽。',64,'全唐诗/poet.song.66000.json','["初尋磴道踏雪烟，漸引茅簷屋數椽。", "江影動摇波面日，山光隠見峽中天。", "放懷罇酒憑欄客，回首弦歌趁市船。", "要與舟人同此樂，移花種竹滿簷前。"]'),
('55c17d28-e4cc-40be-96a0-4977374bc37b','白帝城','宋肇','宋','宋诗','song-poetry','','[]','江雨霏霏白帝城，秋草未枯春草生。',64,'全唐诗/poet.song.66000.json','["江雨霏霏白帝城，秋草未枯春草生。", "古來戰壘如雲橫，萬里瞿塘斷人行。", "至今三峽路崢嶸，時清不見更屯兵。", "荒凉廢堞沒春耕，但見牛羊日西平。"]'),
('1a6d20a0-e4e8-4bfa-b76f-3309deecaec9','峽口','宋肇','宋','宋诗','song-poetry','','[]','萬里西南路，瞿唐據上游。',48,'全唐诗/poet.song.66000.json','["萬里西南路，瞿唐據上游。", "峽分山對立，江合水爭流。", "蛟鰐從來患，風波自古愁。", "幾時飛兩槳，歸去幔帆秋。"]'),
('ebfc1032-7796-449d-9bcf-9b910be502f0','夔冬暖雪不到地唯山高處盡白它皆霏雨而已','宋肇','宋','宋诗','song-poetry','','[]','密下斜飛片片愁，不堪飄泊向西州。',32,'全唐诗/poet.song.66000.json','["密下斜飛片片愁，不堪飄泊向西州。", "思家對雪誠何味，只與羣山鬭白頭。"]'),
('d6154b1f-b103-4922-8df0-7abcdabf5eb3','晚晴','宋肇','宋','宋诗','song-poetry','','[]','古道遙臨水，荒城早閉門。',48,'全唐诗/poet.song.66000.json','["古道遙臨水，荒城早閉門。", "亂山啣落照，歸鳥下空園。", "江口漁人舫，崖腰桑樹村。", "客愁何可奈，有酒莫空樽。"]'),
('b2dfae91-c620-4cf0-941b-1af972fc0005','中秋對月用昌黎先生贈張功曹韵','宋肇','宋','宋诗','song-poetry','','[]','水精爲鑑金爲波，挂空影寫山與河。',235,'全唐诗/poet.song.66000.json','["水精爲鑑金爲波，挂空影寫山與河。", "清光此夜十分好，有酒有客宜高歌。", "去年今日行役苦，若宿溪邊宿逢雨。", "傳聞蜀道如天高，崖縣壁絕哀猿號。", "波橫劍戟不易上，陸有虎豹何由逃。", "江山舊恃白帝險，風俗猶带烏蠻操。", "驅馳兩月到西塞，夢寐萬里還東皋。", "嗅梅踏雪巴子里，路入鬼門欣不死。", "飛飛倦鳥惟思還，玉筍豈是鹿官班。", "餘生但願閒及酒，虛名寧顧觸與蠻。", "良宵佳客十有五，雲放月入樽罍間。", "頹然老子興不淺，韓詩坡句聊追攀。", "君不見天寶霓裳羽衣歌，人間樂舞難同科。", "遺音猶在悲凉多，有酒且歌遑恤他。", "不飲如此良夜何。"]'),
('9152053f-76e3-41f4-b0d6-7da97f00710b','杜鵑','宋肇','宋','宋诗','song-poetry','','[]','暖雲無定半陰晴，茅屋紙窗深復明。',64,'全唐诗/poet.song.66000.json','["暖雲無定半陰晴，茅屋紙窗深復明。", "喬木參天竹千莖，巴山欲曉風露清。", "杜鵑飛鳴遶江城，魚復四月江水生。", "林花落盡空含情，瀼東瀼西朝暮聲。"]'),
('8d4eb41c-0c59-4466-9f05-63db48792e5a','句','宋肇','宋','宋诗','song-poetry','','[]','知君也厭雕肝腎，分我江南數斛愁。',16,'全唐诗/poet.song.66000.json','["知君也厭雕肝腎，分我江南數斛愁。"]'),
('876db599-9bc4-4404-a90b-6b9eb0dca089','集趣軒','陳聿','宋','宋诗','song-poetry','','[]','宇宙同無窮，景物各有趣。',108,'全唐诗/poet.song.66000.json','["宇宙同無窮，景物各有趣。", "心目要領略，未始爲細故。", "山僧徹障蔽，便得江山助。", "遠邇入盼睞，左右供指顧。", "千容與萬態，不約相與遇。", "何須更登眺，便可休杖屨。", "一覽既無餘，懷抱良以悟。", "欲圖無妙筆，欲詠無奇句。", "聊爲揭佳名，於焉賞心寓。"]'),
('2d5a080f-bd8c-4f37-8fce-212574b01ee3','句','呂由庚','宋','宋诗','song-poetry','','[]','地下若逢中執法，爲言今日再昇平。',16,'全唐诗/poet.song.66000.json','["地下若逢中執法，爲言今日再昇平。"]'),
('f021a8e7-8b76-42ef-a480-8ae1cd0852ff','妙峰寺','王古','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','修徑轉巖阿，危亭臨木杪。',96,'全唐诗/poet.song.66000.json','["修徑轉巖阿，危亭臨木杪。", "清明江練直，紫翠山屏繞。", "林巒獻奇秀，圖畫極天巧。", "松杉韵輕風，笙簫奏雲表。", "心知游魚樂，目送飛鴻杳。", "浮生黄粱夢，幻事何時了。", "惟應觀勝妙，坐可清紛擾。", "豈須登泰山，閒看諸峰小。"]'),
('442f576e-732c-4403-ae13-fd2f9ed501dc','偈十六首  其一','釋行瑛','宋','宋诗','song-poetry','','[]','大千沙界是吾家，隠顯何曾有等差。',32,'全唐诗/poet.song.66000.json','["大千沙界是吾家，隠顯何曾有等差。", "爲報人天高著眼，優曇花異世間花。"]'),
('83e63bad-bc84-4295-bc35-d1780802d659','偈十六首  其二','釋行瑛','宋','宋诗','song-poetry','','[]','烏長飛，兔不住，暑往寒來朝復暮。',76,'全唐诗/poet.song.66000.json','["烏長飛，兔不住，暑往寒來朝復暮。", "朱顔未改白髮生，三界茫茫何處去。", "本源自性無凋變，千聖皆從影中現。", "不離當處常湛然，覓則知君不可見。", "忽然見，倒騎牛兮入佛殿。"]'),
('fac7480b-3141-465a-9f2a-257bafb261aa','偈十六首  其三','釋行瑛','宋','宋诗','song-poetry','','[]','去年逢青春，朱顔映桃李。',48,'全唐诗/poet.song.66000.json','["去年逢青春，朱顔映桃李。", "今年逢青春，白髮壓雙耳。", "人生七十年，疾若東流水。", "不了本來心，生死何由離。"]'),
('180661a5-bc3d-416d-8716-29a28c825498','偈十六首  其四','釋行瑛','宋','宋诗','song-poetry','','[]','明眼底人被眼礙，悟心底人被心礙。',64,'全唐诗/poet.song.66000.json','["明眼底人被眼礙，悟心底人被心礙。", "證道底人被道礙，達法底人被法礙。", "何謂如此不見道，金屑雖貴，落根成翳。", "要得高步大方，直須去此四礙。"]'),
('2133169e-4e01-4f24-a9b6-883c0d16c854','偈十六首  其五','釋行瑛','宋','宋诗','song-poetry','','[]','煉鐵圍山作釣鈎，餌懸八萬四千牛。',32,'全唐诗/poet.song.66000.json','["煉鐵圍山作釣鈎，餌懸八萬四千牛。", "毗盧海內閒拋下，蝦蟹魚龍盡縮頭。"]'),
('337a7370-8f59-4eb4-a0e5-7b85495e400b','偈十六首  其六','釋行瑛','宋','宋诗','song-poetry','','[]','湛露重重灑紺園，衰殘何以報君恩。',32,'全唐诗/poet.song.66000.json','["湛露重重灑紺園，衰殘何以報君恩。", "白雲堆裏焚香坐，耀古騰今不二門。"]'),
('d68ae94f-8cb9-4558-9811-7d04fc26a80d','偈十六首  其七','釋行瑛','宋','宋诗','song-poetry','','[]','朔風如刀，痛刮人骨。',48,'全唐诗/poet.song.66000.json','["朔風如刀，痛刮人骨。", "千山萬山，雪映寒日。", "心知春氣來，目睹梅花發。", "遊子南方歸不歸，曉堂閒却龜毛拂。"]'),
('8c037692-c34d-40c1-b4b8-6abeabcb74b2','偈十六首  其八','釋行瑛','宋','宋诗','song-poetry','','[]','鏤水求紋，謾勞心力。',56,'全唐诗/poet.song.66000.json','["鏤水求紋，謾勞心力。", "陶空作器，枉費工夫。", "游溟渤始測淺深，登須彌迺知高遠。", "太陽門下，爝火何施。", "鏌鎁匣邊，鉛刀可棄。"]'),
('a25d8f95-ccd4-4f20-9557-759d20264cbc','偈十六首  其九','釋行瑛','宋','宋诗','song-poetry','','[]','踏破化城，來至寶所。',48,'全唐诗/poet.song.66000.json','["踏破化城，來至寶所。", "不採輝山之璧，不探驪頷之珠。", "壞衲堆肩，擁爐閒坐。", "喚作無事道人，堪受人天供養。"]'),
('e502de7f-f4ee-49d4-b7d8-3fe48cb851f3','偈十六首  其一○','釋行瑛','宋','宋诗','song-poetry','','[]','德山棒如雨點，臨濟喝似雷鳴。',92,'全唐诗/poet.song.66000.json','["德山棒如雨點，臨濟喝似雷鳴。", "雖然聲振一時風流萬世，檢點得來還是强生節目。", "華藏則不與麽，三間茆屋。", "十里松門，健則縱步閒遊，困則倒頭酣寢。", "身如槁木，心若死灰。", "有人笑我愚癡，正爬著儂家痒處。"]'),
('c8c0fca3-5588-4b6e-9d8d-55aff1f04234','偈十六首  其一一','釋行瑛','宋','宋诗','song-poetry','','[]','豎不窮三際，橫不亙十方。',86,'全唐诗/poet.song.66000.json','["豎不窮三際，橫不亙十方。", "大不偪塞虛空，細不入於芥子。", "三世諸佛，如覺如夢。", "諸大祖師，若存若亡。", "與麽境界，從上諸聖。", "尚迷昧如斯，方今學人，且作麽生湊泊。", "但得雪消去，自然春到來。"]'),
('fbf61465-1098-4fb3-af7d-affb2d730272','偈十六首  其一二','釋行瑛','宋','宋诗','song-poetry','','[]','上不見天，下不見地。',76,'全唐诗/poet.song.66000.json','["上不見天，下不見地。", "把定咽喉，何處出氣。", "江南江北，絕毫絕釐。", "東土西天，成團成塊。", "釋迦彌勒，尚自瞞盱。", "臨濟德山，如何擬議。", "衲僧家，沒巴鼻，却喚六雙爲十二。"]'),
('02ca5a44-dc2c-4fd9-abf6-7cac30f297cf','偈十六首  其一三','釋行瑛','宋','宋诗','song-poetry','','[]','奇怪諸禪德，文殊普賢，化作寒山拾得。',115,'全唐诗/poet.song.66000.json','["奇怪諸禪德，文殊普賢，化作寒山拾得。", "頭戴炙脂帽子，脚踏無底麻鞋。", "身著鶻臭布衫，腰繫斷鞓腰带。", "手持拍板，口唱高歌。", "吾心似秋月，碧潭清皎潔。", "無物堪比倫，教我如何說。", "華藏當時若見，每人痛與一頓何爲如此。", "且教伊不敢掣風掣顛，免使後人疑著。"]'),
('3fb78991-4f0f-47ce-9ed2-67efcc3cb394','偈十六首  其一四','釋行瑛','宋','宋诗','song-poetry','','[]','提智慧劍，破煩惱網。',74,'全唐诗/poet.song.66000.json','["提智慧劍，破煩惱網。", "拔生死類，置涅槃宅。", "空却魔王窟穴，埽蕩惡趣關防。", "開拓般若封疆，滋長菩提種性。", "與麽作用，與麽建立。", "象駕崢嶸謾進途，誰見螳蜋能拒轍。"]'),
('6cd82046-bb8e-47a3-8736-34dcd5f12b9d','偈十六首  其一五','釋行瑛','宋','宋诗','song-poetry','','[]','一大藏教，諸大祖師。',43,'全唐诗/poet.song.66000.json','["一大藏教，諸大祖師。", "天下老和尚言句，總在這裏。", "明明向道，尚且不知。", "蓋覆將來，如何會得。"]'),
('1bf57435-4979-4c5b-9b38-91e0b86437e2','偈十六首  其一六','釋行瑛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','持長竿，摇短艇。',46,'全唐诗/poet.song.66000.json','["持長竿，摇短艇。", "篛笠只一箇，簑衣無兩領。", "洞庭秋水風不吹，涵虛恰似新磨鏡。", "末後句，留與謝三郎。"]'),
('5a3e6563-1a3d-44d1-8b33-b17e567d6204','東溪閑居示衆偈','釋行瑛','宋','宋诗','song-poetry','','[]','聯絡藤蘿一徑，行窮始到松門。',112,'全唐诗/poet.song.66000.json','["聯絡藤蘿一徑，行窮始到松門。", "籬畔野華不艷，堂前流水非喧。", "午飯龍離鐵鉢，夜深月落金盆。", "此是真修行處，何人得意忘言。", "靈山河沙聖衆，黄梅七百高僧。", "悟華曉稱迦葉，傳衣夜喚盧能。", "心自本來不有，法道得了何曾。", "齋後釅茶三盞，叢林一任喧騰。"]'),
('20cb0a2e-833f-4a08-a625-5e588ba484b2','偈','釋行瑛','宋','宋诗','song-poetry','','[]','登山須到頂，入海須到底，學道須到佛祖道不得處。',47,'全唐诗/poet.song.66000.json','["登山須到頂，入海須到底，學道須到佛祖道不得處。", "若不如是，盡是依草附木底精靈，吃野狐涕唾底鬼子。"]'),
('95e721e9-3507-4089-91d6-e738be874e84','偈','釋梵卿','宋','宋诗','song-poetry','','[]','春已暮，落花紛紛下紅雨。',60,'全唐诗/poet.song.66000.json','["春已暮，落花紛紛下紅雨。", "南北行人歸不歸，千林萬林鳴杜宇。", "我無家兮何處歸，十方剎土奚相依。", "老夫有箇真消息，昨夜三更月在池。"]'),
('13b9149e-e0c3-4645-af26-fde5e24d429f','臨終偈','釋梵卿','宋','宋诗','song-poetry','','[]','五陰山頭乘駿馬，一鞭策起疾如飛。',32,'全唐诗/poet.song.66000.json','["五陰山頭乘駿馬，一鞭策起疾如飛。", "臨行莫問棲真處，南北東西隨處歸。"]'),
('da6b9400-0841-4708-b0a8-dd4e6be8a245','陶隠居丹室','許景亮','宋','宋诗','song-poetry','','[]','金鸞亂舊直，鶴駕脫塵氛。',48,'全唐诗/poet.song.66000.json','["金鸞亂舊直，鶴駕脫塵氛。", "真隠雖高世，嘉謀亦相君。", "石壇移曉月，丹竈覆寒雲。", "瑟瑟松風在，時人自不聞。"]'),
('1c12bf4e-2aec-47f2-932f-3746e68a6a86','偈二首  其一','釋禧誧','宋','宋诗','song-poetry','','[]','韶山近日沒巴鼻，眼裏聞聲鼻嘗味。',48,'全唐诗/poet.song.66000.json','["韶山近日沒巴鼻，眼裏聞聲鼻嘗味。", "有時一覺到天明，不在床上不落地。", "三級浪高魚化龍，癡人猶戽夜塘水。"]'),
('7633153e-e28a-4381-b8db-95d24751d945','偈二首  其二','釋禧誧','宋','宋诗','song-poetry','','[]','丹霞有箇公案，從來推倒扶起。',28,'全唐诗/poet.song.66000.json','["丹霞有箇公案，從來推倒扶起。", "今朝普示諸人，且道是箇甚底。"]'),
('5b77840f-7012-488b-bc85-fd6de420b235','偈二首  其一','釋宗賾','宋','宋诗','song-poetry','','[]','近日身心頑頓，恰似一片鐵板。',82,'全唐诗/poet.song.66000.json','["近日身心頑頓，恰似一片鐵板。", "內無玲瓏機智，外無華藻文章。", "誰能打作鄆州針，笑殺秦時𨍏輅鑽。", "四楞著地，萬事無心。", "雖然看不入，畢竟撲不破。", "大都好物不堅牢，彩雲易散瑠璃脆。"]'),
('572463d5-80ab-4c92-849f-c6e80bc9dd83','偈二首  其二','釋宗賾','宋','宋诗','song-poetry','','[]','金屑雖貴，落眼成翳。',21,'全唐诗/poet.song.66000.json','["金屑雖貴，落眼成翳。", "金屑既除，眼在甚麽處。"]'),
('80fe6e70-e42a-4287-aa5d-c2923061696a','偈三首  其一','釋宗賾','宋','宋诗','song-poetry','','[]','冬去寒食，一百單五。',56,'全唐诗/poet.song.66000.json','["冬去寒食，一百單五。", "活人路上，死人無數。", "頭鑽荆棘林，將謂衆生苦。", "拜掃事如何，骨堆上添土。", "唯有出家人，不踏無生路。"]'),
('66b60d32-fca7-42f7-b530-c1c61d940169','偈三首  其二','釋宗賾','宋','宋诗','song-poetry','','[]','新羅別無妙訣，當言不避截舌。',28,'全唐诗/poet.song.66000.json','["新羅別無妙訣，當言不避截舌。", "但能心口相應，一生受用不徹。"]'),
('2b665552-6368-4cc0-9b2b-1cc85b954f34','偈三首  其三','釋宗賾','宋','宋诗','song-poetry','','[]','樓外紫金山色秀，門前甘露水聲寒。',32,'全唐诗/poet.song.66000.json','["樓外紫金山色秀，門前甘露水聲寒。", "古槐陰下清風裏，試爲諸人再指看。"]'),
('6d74729f-8499-48a4-b5f1-1072294d0e4b','偈','釋廣燈','宋','宋诗','song-poetry','','[]','休休休，徒悠悠。',20,'全唐诗/poet.song.66000.json','["休休休，徒悠悠。", "釣竿長在手，魚冷不吞鈎。"]'),
('9623d5cf-6246-4c2c-931d-b0dc02bd8e6c','臨終偈','釋廣燈','宋','宋诗','song-poetry','','[]','南北無寸影，東西絕四鄰。',24,'全唐诗/poet.song.66000.json','["南北無寸影，東西絕四鄰。", "一息故鄉信，曉風吹宿雲。"]'),
('687995c2-a7bd-4e00-91f2-62c8a5f9d316','偈','釋慧懃','宋','宋诗','song-poetry','','[]','八月二十五，有賓兼有主。',64,'全唐诗/poet.song.66000.json','["八月二十五，有賓兼有主。", "輥出雪峰毬，打動禾山鼓。", "天帝釋摇頭，大梵王作舞。", "不透上林關，未敢輕相許。", "空生不解此家風，惹得岩前華似雨。"]'),
('bee4d2a5-a65a-4728-a36e-db5cacdbf97f','頌古七首 達磨見武帝','釋慧懃','宋','宋诗','song-poetry','','[]','始聞阿閣一聲鐘，日暖蒼龍睡正濃。',64,'全唐诗/poet.song.66000.json','["始聞阿閣一聲鐘，日暖蒼龍睡正濃。", "再擊鳳凰臺上鼓，夜半祥鸞未飛舞。", "帝基永固如磐石，胡僧枉費平生力。", "回指少林歸去來，春風一陣華狼藉。"]'),
('a74d68ab-1ede-4c8d-b939-14ddda573618','頌古七首 日面佛月面佛','釋慧懃','宋','宋诗','song-poetry','','[]','東街柳色拖烟雨，西巷桃華相映紅。',32,'全唐诗/poet.song.66000.json','["東街柳色拖烟雨，西巷桃華相映紅。", "左顧右盼看不足，一時分付與春風。"]'),
('48289c01-c31d-4f2c-9eb8-83a94af3c6e3','頌古七首 世尊陞座','釋慧懃','宋','宋诗','song-poetry','','[]','一輪明月挂天心，四海生靈荷照臨。',32,'全唐诗/poet.song.66000.json','["一輪明月挂天心，四海生靈荷照臨。", "何必西風撼丹桂，碧霄重送九秋音。"]'),
('38078f9a-4199-48b9-9984-3cc0c4b5f9a2','頌古七首 離四句絕百非','釋慧懃','宋','宋诗','song-poetry','','[]','美如西子離金閣，嬌似楊妃倚玉樓。',32,'全唐诗/poet.song.66000.json','["美如西子離金閣，嬌似楊妃倚玉樓。", "猶把琵琶半遮面，不令人見轉風流。"]'),
('0c972ab6-1594-456c-a4be-5b7a8d13208b','頌古七首 十身調御','釋慧懃','宋','宋诗','song-poetry','','[]','捉賊分明要見贓，十身調御下禪床。',32,'全唐诗/poet.song.66000.json','["捉賊分明要見贓，十身調御下禪床。", "曾經巴峽猿啼處，鐵作心肝也斷腸。"]'),
('766c3412-a065-4fbf-b686-117ed5acfb21','頌古七首 三聖逢人即出','釋慧懃','宋','宋诗','song-poetry','','[]','城南措大騎馿子，市北郎君跨馬兒。',32,'全唐诗/poet.song.66000.json','["城南措大騎馿子，市北郎君跨馬兒。", "各各四蹄俱著地，三春同到月明池。"]'),
('b1b931b4-2eae-4dc0-8808-0a740f8344a5','頌古七首 南泉示衆云文殊起佛見法見貶向二鐵圍山','釋慧懃','宋','宋诗','song-poetry','','[]','彩雲影裏仙人現，手把紅羅扇遮面。',32,'全唐诗/poet.song.66000.json','["彩雲影裏仙人現，手把紅羅扇遮面。", "無人著眼看仙人，却看隨後紅羅扇。"]'),
('89086158-e520-4dfa-9ec0-ce121ea609fe','偈六首  其一','釋慧懃','宋','宋诗','song-poetry','','[]','至道無難，唯嫌選擇。',58,'全唐诗/poet.song.66000.json','["至道無難，唯嫌選擇。", "桃華紅，李花白，誰道融融只一色。", "燕子語，黄鶯鳴，誰道關關只一聲。", "不透祖師關捩子，空認山河作眼睛。"]'),
('dae8e504-ed97-455d-9c4e-312bbe227bb2','偈六首  其二','釋慧懃','宋','宋诗','song-poetry','','[]','日日日西沉，日日日東上。',24,'全唐诗/poet.song.66000.json','["日日日西沉，日日日東上。", "若欲學菩提，但看此模樣。"]'),
('41b7dcc1-8873-47ab-a114-928531629fda','偈六首  其三','釋慧懃','宋','宋诗','song-poetry','','[]','去年今日時，紅爐片雪飛。',72,'全唐诗/poet.song.66000.json','["去年今日時，紅爐片雪飛。", "今日去年時，曹娥讀夜碑。", "末後一句子，佛眼莫能窺。", "白蓮峰頂上，紅日繞須彌。", "鳥啄珊瑚樹，鯨吞離水犀。", "太平家業在，千古襲楊歧。"]'),
('9538d24c-c32f-4cb5-afaf-4999c3bb4948','偈六首  其四','釋慧懃','宋','宋诗','song-poetry','','[]','金烏急，玉兔速，急急流光七月十。',72,'全唐诗/poet.song.66000.json','["金烏急，玉兔速，急急流光七月十。", "無窮遊子不歸家，縱歸只在門前立。", "門前立，把手牽伊不肯入。", "萬里看看寸草無，殘花落地無人拾。", "無人拾，一回雨過一回濕。"]'),
('996bc1d1-f7f3-4159-b228-e9d1b8cc91c0','偈六首  其五','釋慧懃','宋','宋诗','song-poetry','','[]','世尊有密語，冬到寒食一百五。',44,'全唐诗/poet.song.66000.json','["世尊有密語，冬到寒食一百五。", "迦葉不覆藏，水泄不通已露贓。", "靈利衲僧如會得，一重雪上一重霜。"]'),
('3c41964e-ae05-4dc5-b0a7-ba3db5dc5602','偈六首  其六','釋慧懃','宋','宋诗','song-poetry','','[]','天左旋，地右轉，古往今來經幾遍。',56,'全唐诗/poet.song.66000.json','["天左旋，地右轉，古往今來經幾遍。", "金烏飛，玉兔走。", "纔方出海門，又落青山後。", "江河波渺渺，淮濟浪悠悠，直入滄溟晝夜流。"]'),
('d9f64b11-1c33-456b-a395-4f77efacaa40','砂鑼盛油','釋慧懃','宋','宋诗','song-poetry','','[]','銅砂鑼裏落盛油，生菜還他蘿蔔頭。',32,'全唐诗/poet.song.66000.json','["銅砂鑼裏落盛油，生菜還他蘿蔔頭。", "但看來年正月半，家家門首掛燈毬。"]'),
('e4e5559f-b85b-4502-915e-c4df87cfb4d4','偈','釋道初','宋','宋诗','song-poetry','','[]','雞見便鬭，犬見便齩。',20,'全唐诗/poet.song.66000.json','["雞見便鬭，犬見便齩。", "殿上鴟吻，終日相對。"]'),
('6f818902-26dc-41a2-ad8a-7830fad8d7ea','辭衆偈','釋道初','宋','宋诗','song-poetry','','[]','昨日離城市，白雲空往還。',24,'全唐诗/poet.song.66000.json','["昨日離城市，白雲空往還。", "松風清耳目，端的勝人間。"]'),
('af02cbfa-eed7-4bac-91cc-cea2e2b4a396','偈','釋普融','宋','宋诗','song-poetry','','[]','二女合爲一媳婦，機輪截斷難回互。',32,'全唐诗/poet.song.66000.json','["二女合爲一媳婦，機輪截斷難回互。", "從來往返絕蹤由，行人莫問老時路。"]'),
('43afbce4-056f-4e2f-a9ce-fc3522c29e94','偈三首  其一','釋自賢','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物。',36,'全唐诗/poet.song.66000.json','["不是心，不是佛，不是物。", "與君打破精靈窟，簸土飛揚無處尋，千山萬山突突兀。"]'),
('95635f2a-69c2-4d50-81ad-53df657afcca','偈三首  其二','釋自賢','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一身高隠惟南嶽，自笑孤雲未是閑。',32,'全唐诗/poet.song.66000.json','["一身高隠惟南嶽，自笑孤雲未是閑。", "松下水邊端坐者，也應隨倒說居山。"]'),
('a3b36e9c-a73f-4ff9-9ddb-749f64184fee','偈三首  其三','釋自賢','宋','宋诗','song-poetry','','[]','五更殘月落，天曉白雲飛。',36,'全唐诗/poet.song.66000.json','["五更殘月落，天曉白雲飛。", "分明目前事，不是目前機。", "欲言言不及，林下却商量。"]'),
('c5bfc15d-a3dc-45c3-866c-197a380bfae1','偈三首  其一','釋道和','宋','宋诗','song-poetry','','[]','一二三，四五六，碧眼胡僧數不足。',64,'全唐诗/poet.song.66000.json','["一二三，四五六，碧眼胡僧數不足。", "泥牛入海過新羅，木馬追風到天竺。", "天竺茫茫何處尋，補陀巖上問觀音。", "普賢拍手呵呵笑，歸去來兮秋水深。"]'),
('2c2a5de5-b615-4368-b872-65e45d6d1d97','偈三首  其二','釋道和','宋','宋诗','song-poetry','','[]','觀身實相，觀佛亦然。',40,'全唐诗/poet.song.66000.json','["觀身實相，觀佛亦然。", "這裏見得，黄面瞿曇。", "隠身無地，其或渺漫。", "不分照顧，眉毛鼻孔。"]'),
('aa0db679-3c12-46ed-80d2-31f1144d33de','偈三首  其三','釋道和','宋','宋诗','song-poetry','','[]','欲渡巨海，必假方舟。',56,'全唐诗/poet.song.66000.json','["欲渡巨海，必假方舟。", "櫓棹俱全，風帆兩便。", "夜觀星月，晝視雲山。", "萬里之遙，一瞬可到。", "人心盡畏波濤險，未必被濤險似心。"]'),
('931f7379-f52a-4783-8085-7287755b8949','題永明智覺壽禪師頂相','釋道和','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','慧日峰高秋色冷，錢塘江靜月華明。',32,'全唐诗/poet.song.66000.json','["慧日峰高秋色冷，錢塘江靜月華明。", "寒光一爍周沙界，筆下看來未十成。"]'),
('90e0e408-41c1-4ddf-a69d-e1e9dc744aa4','偈','湡禪師','宋','宋诗','song-poetry','','[]','優游實際妙明家，轉步移身指落霞。',32,'全唐诗/poet.song.66000.json','["優游實際妙明家，轉步移身指落霞。", "無限白雲猶不見，夜乘明月出蘆花。"]'),
('4eb6ee5a-a65c-49a9-a09d-9d4ae59c2f2e','偈五首  其一','釋志璿','宋','宋诗','song-poetry','','[]','休去，歇去，一切萬年去。',31,'全唐诗/poet.song.66000.json','["休去，歇去，一切萬年去。", "寒灰枯木去，古廟裏香爐去，一條白練去。"]'),
('abfb23e3-c5ea-40b1-a300-1c4f3af62ba1','偈五首  其二','釋志璿','宋','宋诗','song-poetry','','[]','不休去，不歇去，業識忙忙去。',68,'全唐诗/poet.song.66000.json','["不休去，不歇去，業識忙忙去。", "七顛八倒去，十字街頭鬧浩浩地聲色裏坐卧去。", "三家村裏盈衢寒路荆棘裏游戲去，刀山劍樹劈腹剜心鑊湯爐炭皮穿骨爛去。"]'),
('0d5e88b3-c83f-42c5-9a4a-385d3c2de899','偈五首  其三','釋志璿','宋','宋诗','song-poetry','','[]','瘦竹長松滴翠香，流風疏月度炎凉。',32,'全唐诗/poet.song.66000.json','["瘦竹長松滴翠香，流風疏月度炎凉。", "不知誰住原西寺，每日鐘聲送夕陽。"]'),
('eb5bb3dc-2b2f-4d4f-93b4-6029d2c277d3','偈五首  其四','釋志璿','宋','宋诗','song-poetry','','[]','聲色頭上睡眠，虎狼羣裏安禪。',44,'全唐诗/poet.song.66000.json','["聲色頭上睡眠，虎狼羣裏安禪。", "荆棘林內翻身，雪刃叢中游戲。", "竹影掃階塵不動，月穿潭底水無痕。"]'),
('890150d1-c5bf-4944-93a3-bf91bfb7d3a2','偈五首  其五','釋志璿','宋','宋诗','song-poetry','','[]','不是風動，不是幡動，衲僧失却鼻孔。',54,'全唐诗/poet.song.66000.json','["不是風動，不是幡動，衲僧失却鼻孔。", "是風動，是幡動，分明是箇漆桶。", "兩段不同，眼暗耳聾。", "澗水如藍碧，山花似火紅。"]'),
('477b9086-0bbd-4178-85f2-95efb6043ba2','臨寂偈','尼法海','宋','宋诗','song-poetry','','[]','霜天雲霧結，山月冷涵輝。',24,'全唐诗/poet.song.66000.json','["霜天雲霧結，山月冷涵輝。", "夜接故鄉信，曉行人不知。"]'),
('72cd7326-65f0-4287-983d-373f4b07c2d4','偈','釋智月','宋','宋诗','song-poetry','','[]','祝聖紹，續祖燈，只如祖燈作麽生。',55,'全唐诗/poet.song.66000.json','["祝聖紹，續祖燈，只如祖燈作麽生。", "續不見古者道，六街鐘鼓響鼕鼕，即處鋪金世界中。", "池長芰荷庭長柏，更將何法演真宗。"]'),
('7b71fc2d-11cb-44a0-a0a6-05e0742fdd3e','偈','釋智月','宋','宋诗','song-poetry','','[]','吾家寶藏不慳惜，覿面相呈人罕識。',64,'全唐诗/poet.song.66000.json','["吾家寶藏不慳惜，覿面相呈人罕識。", "輝金耀古體圓時，照地照天光赫赤。", "荆山美玉奚爲貴，合浦明珠比不得。", "借問誰人敢酬價，波斯鼻孔長三尺。"]'),
('ef1f6048-38cd-492e-a3c2-c933ea248d18','呈雲蓋智禪師','齊禪師','宋','宋诗','song-poetry','','[]','說法無如這個親，十方剎海一微塵。',32,'全唐诗/poet.song.66000.json','["說法無如這個親，十方剎海一微塵。", "若能於此明真理，大地何曾見一人。"]'),
('e5b5cd19-9fbc-42a5-afe1-0d150a4a08e0','臨寂偈','齊禪師','宋','宋诗','song-poetry','','[]','昨夜三更過急灘，灘頭雲霧黑漫漫。',32,'全唐诗/poet.song.66000.json','["昨夜三更過急灘，灘頭雲霧黑漫漫。", "一條拄杖爲知己，擊碎千關與萬關。"]'),
('0e705ca4-f601-4ad8-9d23-79845f42df00','偈','釋法聰','宋','宋诗','song-poetry','','[]','幽室寒燈不假挑，虛空明月徹雲霄。',32,'全唐诗/poet.song.66000.json','["幽室寒燈不假挑，虛空明月徹雲霄。", "要知日用常無間，烈焰光中發異苗。"]'),
('ae2f40fb-a45e-4961-a917-9f2f64665dba','偈','釋寶覺','宋','宋诗','song-poetry','','[]','一即一，二即二，嗅著直是無香氣。',32,'全唐诗/poet.song.66000.json','["一即一，二即二，嗅著直是無香氣。", "識得山僧榔栗條，莫向南山尋鼈鼻。"]'),
('0a191438-973c-43d6-bb11-15a980b991c6','偈','釋法明','宋','宋诗','song-poetry','','[]','資福別無所補，五日一參擊鼓。',54,'全唐诗/poet.song.66000.json','["資福別無所補，五日一參擊鼓。", "何曾說妙談玄，祇是粗言直語。", "甘草自來甜，黄連依舊苦。", "忽若鼻孔遼天，逢人切忌錯舉。"]'),
('93c13ed5-b68b-4be8-a39d-7e6b21e61a31','偈','釋可復','宋','宋诗','song-poetry','','[]','苦痛深，苦痛深。',20,'全唐诗/poet.song.66000.json','["苦痛深，苦痛深。", "碧潭千萬丈，那箇是知音。"]'),
('4662e70d-a694-49d6-8c74-7fbd6003f95f','了齋自警六首  其一','陳瓘','宋','宋诗','song-poetry','','[]','本無一字堯夫易，八十一篇揚子玄。',32,'全唐诗/poet.song.66000.json','["本無一字堯夫易，八十一篇揚子玄。", "今古是非那復辨，仲尼尤不廢韋編。"]'),
('3fdc3bf9-ec4d-4d02-8ba9-a121ebe23193','了齋自警六首  其二','陳瓘','宋','宋诗','song-poetry','','[]','文書難寫伏羲書，字外成篇始見渠。',32,'全唐诗/poet.song.66000.json','["文書難寫伏羲書，字外成篇始見渠。", "賜也能分可不可，一瓢居士只如愚。"]'),
('0259aee7-d44f-44e4-b5cd-e0f4ffb5bbb3','了齋自警六首  其三','陳瓘','宋','宋诗','song-poetry','','[]','過時不易始爲難，執處那知是變遷。',32,'全唐诗/poet.song.66000.json','["過時不易始爲難，執處那知是變遷。", "度盡千山無鳥迹，不勞傳語報平安。"]'),
('66465ba6-4621-4f65-bcb5-c0b1a2c4e152','了齋自警六首  其四','陳瓘','宋','宋诗','song-poetry','','[]','手在何憂弓力强，巧窮那得必穿楊。',32,'全唐诗/poet.song.66000.json','["手在何憂弓力强，巧窮那得必穿楊。", "太和有味人人飲，誰識醒時是醉鄉。"]'),
('78393fbc-ddf6-4275-bc04-f3dc729ebd65','了齋自警六首  其五','陳瓘','宋','宋诗','song-poetry','','[]','仲由行行終身誦，師也堂堂带上書。',32,'全唐诗/poet.song.66000.json','["仲由行行終身誦，師也堂堂带上書。", "五柳却能知此意，無弦琴上賦歸與。"]'),
('0c5b23a3-c784-4b60-bf5c-b5c177414897','了齋自警六首  其六','陳瓘','宋','宋诗','song-poetry','','[]','只說爲山不說休，山成日夜水橫流。',32,'全唐诗/poet.song.66000.json','["只說爲山不說休，山成日夜水橫流。", "惜哉覆簣成迷復，只欠當初一掉頭。"]'),
('6731b95e-d28a-41fb-b250-378ab0708b92','自合浦還清湘寄虛中弟  其一','陳瓘','宋','宋诗','song-poetry','','[]','三年已絕生還望，一日天恩到海涯。',32,'全唐诗/poet.song.66000.json','["三年已絕生還望，一日天恩到海涯。", "路過清湘猶間闊，當時何不住長沙。"]'),
('1ad51f2f-e6ea-43ee-8c2e-747eee78c13f','自合浦還清湘寄虛中弟  其二','陳瓘','宋','宋诗','song-poetry','','[]','行徹天涯萬里山，月明方照海珠還。',32,'全唐诗/poet.song.66000.json','["行徹天涯萬里山，月明方照海珠還。", "瘴鄉來往渾閒事，聊爲清湘一破顔。"]'),
('f2938951-8157-4a28-b08d-736fba9e4108','自合浦還清湘寄虛中弟  其三','陳瓘','宋','宋诗','song-poetry','','[]','曾近滄溟看颶風，波濤有盡海無窮。',32,'全唐诗/poet.song.66000.json','["曾近滄溟看颶風，波濤有盡海無窮。", "四年陳迹今何在，坐對湘雲豁晚空。"]'),
('cf1a12e8-6a26-43bb-9797-28a0b9d6565a','自合浦還清湘寄虛中弟  其四','陳瓘','宋','宋诗','song-poetry','','[]','瘴海只將梅作雪，湘山今見麥爲春。',32,'全唐诗/poet.song.66000.json','["瘴海只將梅作雪，湘山今見麥爲春。", "晴空有月當如舊，嶺北山南總照人。"]'),
('3ff7fbf9-a045-434e-9d42-1d5a402e274e','與全州崇寧斷臂和尚','陳瓘','宋','宋诗','song-poetry','','[]','少年得髓幾人知，想見當年斷臂時。',32,'全唐诗/poet.song.66000.json','["少年得髓幾人知，想見當年斷臂時。", "此是湘山大知識，衡門堪繼會昌師。"]'),
('d5b69c86-9691-496e-8e42-e254fe56592e','和劉太守十洲詩 花嶼','陳瓘','宋','宋诗','song-poetry','','[]','紅紫商量欲滿枝，持春觴豆好携持。',32,'全唐诗/poet.song.66000.json','["紅紫商量欲滿枝，持春觴豆好携持。", "便須載酒凌波去，底事黄堂獨賦詩。"]'),
('47b841a5-1f70-46f6-a84a-8499f6138060','和劉太守十洲詩 芳草洲','陳瓘','宋','宋诗','song-poetry','','[]','綠色映波千古恨，至今南浦兩依依。',32,'全唐诗/poet.song.66000.json','["綠色映波千古恨，至今南浦兩依依。", "我今又出江東去，多少行人宦未歸。"]'),
('9c49e97c-e5af-48be-9bbf-f71f1528bddb','和劉太守十洲詩 柳汀','陳瓘','宋','宋诗','song-poetry','','[]','密幹參差籠月影，輕波蕩漾蘸烟條。',32,'全唐诗/poet.song.66000.json','["密幹參差籠月影，輕波蕩漾蘸烟條。", "暑天要此清凉地，欲往何辭度小橋。"]'),
('d975ed89-7b9a-4d1b-8b7e-62ccfb0c97e4','和劉太守十洲詩 竹嶼','陳瓘','宋','宋诗','song-poetry','','[]','霜姿迥出紅塵外，只有鵷雛傍水來。',32,'全唐诗/poet.song.66000.json','["霜姿迥出紅塵外，只有鵷雛傍水來。", "別岸若尋棲隠處，軒窗須爲此君開。"]'),
('a4031a5b-b9be-47d4-8b66-aa19fc517050','和劉太守十洲詩 烟嶼','陳瓘','宋','宋诗','song-poetry','','[]','靄靄紛紛緣底事，故來波上罩晴沙。',32,'全唐诗/poet.song.66000.json','["靄靄紛紛緣底事，故來波上罩晴沙。", "莫教散入滄溟去，却恐能迷上漢槎。"]'),
('e974228e-af49-42c1-9117-0ca80fdd493e','和劉太守十洲詩 芙蓉洲','陳瓘','宋','宋诗','song-poetry','','[]','紅雲可覓無蜂去，渺渺寒波映晚芳。',32,'全唐诗/poet.song.66000.json','["紅雲可覓無蜂去，渺渺寒波映晚芳。", "未必孤根能耐雪，且看秋艷已經霜。"]'),
('484f1e35-29a6-4d00-9324-e7f1763331b4','和劉太守十洲詩 菊花洲','陳瓘','宋','宋诗','song-poetry','','[]','光景不留人易老，恨無羽翼出塵埃。',32,'全唐诗/poet.song.66000.json','["光景不留人易老，恨無羽翼出塵埃。", "世間那有飛昇藥，且傍汀洲采菊來。"]'),
('f8560ade-68ae-48bb-9d9b-40328af8c738','和劉太守十洲詩 月島','陳瓘','宋','宋诗','song-poetry','','[]','月明偏照海邊洲，綠水迴環漾素秋。',32,'全唐诗/poet.song.66000.json','["月明偏照海邊洲，綠水迴環漾素秋。", "斗轉參橫羣動息，桂花零落遣誰收。"]'),
('9af5bd40-3669-4f29-b864-442a5b62781b','和劉太守十洲詩 雪汀','陳瓘','宋','宋诗','song-poetry','','[]','誰把平氈水上開，坐看飛絮撲瓊臺。',32,'全唐诗/poet.song.66000.json','["誰把平氈水上開，坐看飛絮撲瓊臺。", "酒豪耳熱笙歌沸，應怪幽人此地來。"]'),
('a7275284-2fa7-4687-b220-db40fc48744c','和劉太守十洲詩 松島','陳瓘','宋','宋诗','song-poetry','','[]','影參岸栢童童綠，葉蔽汀蘭澹澹香。',32,'全唐诗/poet.song.66000.json','["影參岸栢童童綠，葉蔽汀蘭澹澹香。", "斤斧不來人迹遠，養成千尺勢堂堂。"]'),
('ec8b8a73-c599-4656-83bc-69ad81ec1b13','湖心亭','陳瓘','宋','宋诗','song-poetry','','[]','塵境紛紛俗累增，故尋幽徑訪南能。',64,'全唐诗/poet.song.66000.json','["塵境紛紛俗累增，故尋幽徑訪南能。", "湖波浩渺無窮綠，寺屋高低不計層。", "詩老新吟工惱客，使君餘暇得陪僧。", "棋中得失何時了，一局輸贏未可憑。"]'),
('2c28d7dc-4970-4efe-ac7e-0366388ca27c','寄覺範長沙','陳瓘','宋','宋诗','song-poetry','','[]','大士遊方興盡回，家山風月絕塵埃。',32,'全唐诗/poet.song.66000.json','["大士遊方興盡回，家山風月絕塵埃。", "杖頭多少閑田地，挑取華嚴入嶺來。"]'),
('74f906d6-7a35-4188-b710-77de6cca6092','寄覺範漳水','陳瓘','宋','宋诗','song-poetry','','[]','仁者雖逢思有常，平居慎勿示何妨。',64,'全唐诗/poet.song.66000.json','["仁者雖逢思有常，平居慎勿示何妨。", "爭先世路機關惡，近後語言滋味長。", "可口物多終作疾，快心事過必爲傷。", "與其病後求良藥，不若病前能自防。"]'),
('38adb0a1-e0bc-4ed8-9ed5-f3cdc7175c21','和江民表韵','陳瓘','宋','宋诗','song-poetry','','[]','傳老東山水上浮，玄沙六月雪重裘。',32,'全唐诗/poet.song.66000.json','["傳老東山水上浮，玄沙六月雪重裘。", "舊來消息今何在，千里桐江月滿樓。"]'),
('a182aa13-ea4e-4c58-8aa2-af869bf51914','頌','陳瓘','宋','宋诗','song-poetry','','[]','靜坐一川微雨，未辨雷音起處。',28,'全唐诗/poet.song.66000.json','["靜坐一川微雨，未辨雷音起處。", "夜深風作輕寒，清曉月明歸去。"]'),
('e080932d-3c88-4622-a8e8-5631e15373c9','寄饒德操','陳瓘','宋','宋诗','song-poetry','','[]','舊時饒措大，今日壁頭陀。',24,'全唐诗/poet.song.66000.json','["舊時饒措大，今日壁頭陀。", "爲問安心法，禪儒較幾何。"]'),
('93417966-b556-492e-aff4-f940e98bbc3e','吳江鱸鄉亭','陳瓘','宋','宋诗','song-poetry','','[]','中郎臺榭據江鄉，雅稱詩翁賦卒章。',64,'全唐诗/poet.song.66000.json','["中郎臺榭據江鄉，雅稱詩翁賦卒章。", "蒓菜鱸魚好時節，秋風斜日舊烟光。", "一杯有味功名小，萬事無心歲月長。", "安得便拋塵網去，釣舟閑倚畫欄傍。"]'),
('f0211d37-b734-4045-af30-7e897f746454','接花','陳瓘','宋','宋诗','song-poetry','','[]','色紅可使紫，葉單可使千。',144,'全唐诗/poet.song.66000.json','["色紅可使紫，葉單可使千。", "花小可使大，子少可使繁。", "天賦有定質，我力能使遷。", "自矜接花手，可奪造化權。", "衆聞悉驚詫，遣我屢嘆吁。", "用智固巧矣，天時可易歟。", "我欲春採菊，我欲冬賞桃。", "汝不能栽接，汝巧亦徒勞。", "雨露草必生，雪霜松不死。", "不死有本性，必生亦時爾。", "汝之所變易，是亦時所爲。", "時乎不可違，何物不隨時。"]'),
('c9bf2868-5f8b-4086-992f-e6658e61886b','蘇文饒往昌國意頗憚之送以詩因勉之','陳瓘','宋','宋诗','song-poetry','','[]','已聞舟楫具，那得苦留君。',48,'全唐诗/poet.song.66000.json','["已聞舟楫具，那得苦留君。", "雨過霜風急，帆飛雪浪分。", "長途方策足，暇日正論文。", "功業他年事，風波豈足云。"]'),
('8d236cf8-311c-4a4e-82ee-a53413267760','送周初平','陳瓘','宋','宋诗','song-poetry','','[]','虀鹽雖不飽，心與古人期。',48,'全唐诗/poet.song.66000.json','["虀鹽雖不飽，心與古人期。", "口體非吾養，紛華任爾爲。", "經明逢地芥，穎脫看囊錐。", "兩驥皆宛種，天衢好並馳。"]'),
('03d1bb92-dc63-4245-9d7d-3891d51d0473','文饒自昌國以詩見寄次韵二首  其一','陳瓘','宋','宋诗','song-poetry','','[]','百川滾滾到來休，此是人間第一流。',32,'全唐诗/poet.song.66000.json','["百川滾滾到來休，此是人間第一流。", "鯨鬣爲君翻駭浪，蘭苕空自滿汀洲。"]'),
('517f9b03-751a-47ab-b35e-110ce1305abd','文饒自昌國以詩見寄次韵二首  其二','陳瓘','宋','宋诗','song-poetry','','[]','海邦渺渺知何在，風入高帆頃刻過。',32,'全唐诗/poet.song.66000.json','["海邦渺渺知何在，風入高帆頃刻過。", "何似一樽湖上酒，月明安穩照寒波。"]'),
('048fa40d-1072-40ca-a9f5-1eeeb09900ef','文饒自京師還欲往昌國而風作不可渡乃爲絕句戲之','陳瓘','宋','宋诗','song-poetry','','[]','欲衝高浪却沈吟，酒近瀛洲懶得斟。',32,'全唐诗/poet.song.66000.json','["欲衝高浪却沈吟，酒近瀛洲懶得斟。", "莫道顛風無好意，爲君吹過遠歸心。"]'),
('ef7234e5-6ecc-4dea-9411-2a73cb5b8a18','歙硯詩','陳瓘','宋','宋诗','song-poetry','','[]','歙溪澄湛千尋碧，中有崎嶔萬年石。',64,'全唐诗/poet.song.66000.json','["歙溪澄湛千尋碧，中有崎嶔萬年石。", "腰粗入水始能鑿，一硯價直千金璧。", "輕絲膩色恍莫分，熟視微見青羅紋。", "乃知金線鴝鵒眼，如玉有瑕安足論。"]'),
('9772e298-75be-4d40-ab33-cb07ccf0c779','海山樓','陳瓘','宋','宋诗','song-poetry','','[]','勝事荒湮久，高城觀閣宜。',24,'全唐诗/poet.song.66000.json','["勝事荒湮久，高城觀閣宜。", "均勞青瑣客，餘事海山詩。"]'),
('699b8ac0-5833-4e61-8b2a-571fc1514404','秦君亭','陳瓘','宋','宋诗','song-poetry','','[]','世梗賢路塞，達人識窮通。',48,'全唐诗/poet.song.66000.json','["世梗賢路塞，達人識窮通。", "欃槍天寶末，士路如飄蓬。", "聘君當此時，卷迹雲霞中。", "能令千載後，嘆息詩人窮。"]'),
('e939f7b6-510d-4186-9d6e-fbb143961269','瑞泉庵','陳瓘','宋','宋诗','song-poetry','','[]','飛棟逼天象，疏櫺逗巖烟。',48,'全唐诗/poet.song.66000.json','["飛棟逼天象，疏櫺逗巖烟。", "烹茶引高士，汲此石罅泉。", "泉深不盈尺，潤物無頗偏。", "百川有盈涸，是坎常泓然。"]'),
('97af8a2c-6df2-4e5b-be6f-d7a0e37204b6','答瑞巖湛老','陳瓘','宋','宋诗','song-poetry','','[]','示我超然句，能令滯念開。',24,'全唐诗/poet.song.66000.json','["示我超然句，能令滯念開。", "盍移瑞巖剎，爲我入城來。"]'),
('4131bc50-cc00-436b-8816-17747cb4ccab','和鄧鯁之韵','陳瓘','宋','宋诗','song-poetry','','[]','十年三謫海邊州，洛口相望阻獻酬。',64,'全唐诗/poet.song.66000.json','["十年三謫海邊州，洛口相望阻獻酬。", "曾寄遠詩來合浦，又傳新句落丹丘。", "身如古柏童童老，心似平江湛湛流。", "歸鳥倦飛雲入岫，一瓢堪樂莫回頭。"]'),
('92ed331d-1c2e-43a4-937e-4ad933c6119b','攬翠軒','陳瓘','宋','宋诗','song-poetry','','[]','地與煩囂隔，登臨翠色中。',48,'全唐诗/poet.song.66000.json','["地與煩囂隔，登臨翠色中。", "雨餘千畝竹，霜過一山松。", "逸興雲無盡，幽懷水不窮。", "絕勝花滿眼，只得片時紅。"]'),
('8ba59765-310d-4b05-aa50-c85eb79d1290','雜詩','陳瓘','宋','宋诗','song-poetry','','[]','床頭史記千番紙，世上興亡一窖塵。',32,'全唐诗/poet.song.66000.json','["床頭史記千番紙，世上興亡一窖塵。", "惟有炳然周孔道，至今餘澤浸生民。"]'),
('0a4654cb-f8dd-4993-b0be-36f306aaa460','雜詩','陳瓘','宋','宋诗','song-poetry','','[]','大抵操心在謹微，謬差千里始毫釐。',64,'全唐诗/poet.song.66000.json','["大抵操心在謹微，謬差千里始毫釐。", "如聞不善須當改，莫謂無人便可欺。", "忠信但當爲己任，行藏終自有天知。", "深冬寒日能多少，已覺東風次第吹。"]'),
('cd2ae87c-b137-44e2-a2d6-1f5a82b19009','超果亮師假還山  其一','陳瓘','宋','宋诗','song-poetry','','[]','□□□□□，流輩推博雅。',72,'全唐诗/poet.song.66000.json','["□□□□□，流輩推博雅。", "春風振客衣，逸棹東南下。", "賦詩臺閣彥，落落珠璣瀉。", "持觴拜親膝，喜色動鄉社。", "都城十二衢，塵土翳車馬。", "一夢逐君行，茲懷已瀟灑。"]'),
('f4c7c682-b5fd-4098-b571-62a9a603b366','超果亮師假還山  其二','陳瓘','宋','宋诗','song-poetry','','[]','路左漿先饋，門前屨幾重。',48,'全唐诗/poet.song.66000.json','["路左漿先饋，門前屨幾重。", "勇歸塵事擲，恬處道心濃。", "弄水知幽谷，觀雲想妙峰。", "深夜孤鶴唳，清露滴高松。"]'),
('d9f1b56a-696b-49a9-9b72-8170ff70d744','代書簡張天覺','陳瓘','宋','宋诗','song-poetry','','[]','辟穀非其道，談空去自然。',24,'全唐诗/poet.song.66000.json','["辟穀非其道，談空去自然。", "何如勳業地，無愧是神仙。"]'),
('0ad0b47d-5332-43ca-a595-e1e0dffbf7e6','送致政郟丈赴張杭州西湖之約','陳瓘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丈人八十身尤健，心似閑雲恣舒卷。',192,'全唐诗/poet.song.66000.json','["丈人八十身尤健，心似閑雲恣舒卷。", "故人邀作武林遊，拏舟不道江湖遠。", "澄波萬頃沖融間，塵埃洗盡光陰閑。", "登臨不倦謝太傅，好與共尋窗外山。", "梵剎琳宮繞飛閣，靄色嵐光日參錯。", "遙岑併入眼中來，却愛清秋有摇落。", "酒價在逐秋風高，一倒百壺詩正豪。", "潮落潮生幾人老，我獨世累如鴻毛。", "興來即是烟波客，興盡欲歸歸便得。", "疏巾藜杖日相隨，不許征途有南北。", "天南天北屢經過，不獨丈人清興多。", "欲棹小舟同一醉，手邊朱墨奈忙何。"]'),
('7900bdc8-004a-44e7-a737-9336632a1b51','寄題正倫姪舫齋詩二首  其一','陳瓘','宋','宋诗','song-poetry','','[]','此道若長川，行藏比泝沿。',48,'全唐诗/poet.song.66000.json','["此道若長川，行藏比泝沿。", "浪恬寧在我，維泛且隨緣。", "野色連幽岸，溪光接遠天。", "欲離平險地，常使意超然。"]'),
('3e666a46-cf0f-40e9-a297-b9931bcd8b98','寄題正倫姪舫齋詩二首  其二','陳瓘','宋','宋诗','song-poetry','','[]','畫舫名齋閣，端居事若何。',48,'全唐诗/poet.song.66000.json','["畫舫名齋閣，端居事若何。", "燕知真酖毒，言即是風波。", "未便乘桴去，惟同載酒過。", "濟川如有意，南去問施羅。"]'),
('e678409c-d755-4869-9814-2c47df98173a','荔枝臺','陳瓘','宋','宋诗','song-poetry','','[]','滿眼春花百鳥肥，絳苞丹艷大纍纍。',64,'全唐诗/poet.song.66000.json','["滿眼春花百鳥肥，絳苞丹艷大纍纍。", "臺前採掇誰堪贈，譜外聲名世不知。", "顆小不堪妃子笑，味酸猶發少陵詩。", "高墳拱木今何在，此品軒昂獨恨遲。"]'),
('722c10f0-cac9-4502-88b2-e859095d0cd8','花光仁禪師以墨戲見寄以小詩致謝','陳瓘','宋','宋诗','song-poetry','','[]','禪心已出包區宇，墨海翻騰作雪梅。',32,'全唐诗/poet.song.66000.json','["禪心已出包區宇，墨海翻騰作雪梅。", "三昧筆端俱戲事，定餘幽室暗香來。"]'),
('b639f826-5300-43cd-9b7c-acd68369d6d0','寄友人','陳瓘','宋','宋诗','song-poetry','','[]','行人征轡路西東，霜葉翩翩舞亂紅。',64,'全唐诗/poet.song.66000.json','["行人征轡路西東，霜葉翩翩舞亂紅。", "曉色冥朦溪浸月，陰容黯澹馬嘶風。", "浮生信若萍隨浪，遠意徒驚鳥在籠。", "萬事欲窮須握手，尺書相問愧匆匆。"]'),
('67ceb4a1-96e6-4247-8a85-af2cf8b4421c','廬山詩二首  其一','陳瓘','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','廬山俯長江，秀色摩青天。',120,'全唐诗/poet.song.66000.json','["廬山俯長江，秀色摩青天。", "招提選勝地，好景相屬連。", "東林最幽曠，殿閣含飛烟。", "馨香滿天下，無如遠公蓮。", "社客方散後，零落七百年。", "之人遠同調，綠綺非絲弦。", "不可傾耳授，但許心相傳。", "迷津苦難渡，人以師爲船。", "法鼓忽雷震，此事非偶然。", "何時穿蠟屐，問法浮雲邊。"]'),
('dbe9aa04-751d-42aa-82d9-7a7080f51553','廬山詩二首  其二','陳瓘','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山景何如，勝迹多已古。',192,'全唐诗/poet.song.66000.json','["廬山景何如，勝迹多已古。", "水石相回旋，天地巧排布。", "我本天涯人，未知有廬阜。", "恨不早經過，西征一何暮。", "香爐在何許，縹緲凌高空。", "却入白蓮沼，令人思遠公。", "高巖草堂在，吏隠居其中。", "至今三尺童，猶能話白公。", "可想不可見，山色空重重。", "水流來何遠，所過生苔蘚。", "自古垂飛簾，至今不能捲。", "此外猶足觀，足力已困竭。", "僧居本靜閒，群鳥爭囀舌。", "恰欲高枕眠，魂夢恐遭聒。", "知是乘雨來，山路泥滑滑。", "陰雲猶未收，明朝又西發。"]'),
('0cd72f3f-8f96-4cb0-9cca-3258880ad692','佚老堂','陳瓘','宋','宋诗','song-poetry','','[]','解組紛華遠，懸車興味長。',48,'全唐诗/poet.song.66000.json','["解組紛華遠，懸車興味長。", "身閑雲去住，心浄月清凉。", "老矣思同隠，歸歟歎異鄉。", "平生高意在，畎畝未應忘。"]'),
('14f8bb30-2214-4f77-be4c-0dbfd5905ef4','呈知府司封二十韵','陳瓘','宋','宋诗','song-poetry','','[]','錦帳含香士，高名壓搢紳。',240,'全唐诗/poet.song.66000.json','["錦帳含香士，高名壓搢紳。", "南昌移皂蓋，東潁憩朱輪。", "孝悌資延壽，耕桑頼信臣。", "優游千里治，談笑六朝均。", "竟日庭無訟，期年俗已淳。", "休誇兩岐秀，未若四時春。", "近遠皆霑澤，施爲固有神。", "歡謳連別壤，美績播嚴宸。", "夙慕冰壺潔，終期驥足伸。", "燕閒成吏隠，蕭灑得湖濱。", "烟柳籠亭檻，雲波盪釣綸。", "微風牽藻荇，小棹送鱸蓴。", "繆作堂中客，慚陪席上珍。", "開樽寧草草，延語每諄諄。", "齷齪才非異，吹噓意獨親。", "摘鞍方邂逅，攬轡又逡巡。", "麗巧裁新詠，緘題及鄙人。", "曹劉風自古，李杜格殊倫。", "拜賜欣愉甚，臨分感歎頻。", "悠悠京國路，重染滿衣塵。"]'),
('5d925e0a-cdc6-494b-9a08-c9c275fbc2a9','寄題黄及之谷神館','陳瓘','宋','宋诗','song-poetry','','[]','昔日傳聞構館新，標名今已幾經春。',64,'全唐诗/poet.song.66000.json','["昔日傳聞構館新，標名今已幾經春。", "心安即是長生路，世樂無過自在身。", "虛室久扃閑歲月，白頭不減舊精神。", "蓬萊未要香山客，且作潜溪百歲人。"]'),
('a22d20cc-b362-4145-9031-ba87ca8342fc','題假面鋪','陳瓘','宋','宋诗','song-poetry','','[]','今年不及去年秋，十頃曾無半畝收。',32,'全唐诗/poet.song.66000.json','["今年不及去年秋，十頃曾無半畝收。", "好雨早隨人意足，即今何地不油油。"]'),
('b5443a71-d7ce-4ffd-a29f-6c6b7d6ea0c4','目昏詩','陳瓘','宋','宋诗','song-poetry','','[]','壯歲漂淪懶讀書，老忘休歇欲何如。',32,'全唐诗/poet.song.66000.json','["壯歲漂淪懶讀書，老忘休歇欲何如。", "夜窗不復留燈火，眼食齁齁一任渠。"]'),
('7902e324-6314-42d3-9ab6-ce3155148a92','垂虹亭','陳瓘','宋','宋诗','song-poetry','','[]','三年爲吏住東濱，重到江頭照病身。',64,'全唐诗/poet.song.66000.json','["三年爲吏住東濱，重到江頭照病身。", "滿眼碧波輸野鳥，一蓑疏雨屬漁人。", "隨船曉月孤輪白，入座群山數點春。", "張翰英靈應笑我，綠袍依舊惹埃塵。"]'),
('5d81d66a-4095-41cd-ab63-3b794d6f7b09','秀聚亭','陳瓘','宋','宋诗','song-poetry','','[]','曉色春風裏，維舟一小亭。',24,'全唐诗/poet.song.66000.json','["曉色春風裏，維舟一小亭。", "看山渾不倦，待得雪峰青。"]'),
('5bed14f7-5030-4875-b577-887d116f9e28','藏春峽四首  其一','陳瓘','宋','宋诗','song-poetry','','[]','主人心地冷如灰，只把園花取次栽。',32,'全唐诗/poet.song.66000.json','["主人心地冷如灰，只把園花取次栽。", "峽外漫多閒雨露，直須併此入山來。"]'),
('9abc0faf-ca17-488f-8134-b8ecdb97023f','藏春峽四首  其二','陳瓘','宋','宋诗','song-poetry','','[]','花落花開蝶自忙，琴閒書札日偏長。',32,'全唐诗/poet.song.66000.json','["花落花開蝶自忙，琴閒書札日偏長。", "我來不爲看桃李，只愛幽蘭靜更香。"]'),
('ff687358-a7de-46d3-9b90-5cb379321260','藏春峽四首  其三','陳瓘','宋','宋诗','song-poetry','','[]','朝廷鵷鷺日振振，不道天涯亦有人。',32,'全唐诗/poet.song.66000.json','["朝廷鵷鷺日振振，不道天涯亦有人。", "弟勸兄酬無可恨，歡然別是一家春。"]'),
('5223cdd6-2fa4-460d-973b-83a8a8b445b3','藏春峽四首  其四','陳瓘','宋','宋诗','song-poetry','','[]','孺子無心作聘君，使君懸榻意何勤。',32,'全唐诗/poet.song.66000.json','["孺子無心作聘君，使君懸榻意何勤。", "世人不道芳蓀好，可是清香不遠聞。"]'),
('a81bae6b-27da-40bd-b485-8719e23adf84','句  其一','陳瓘','宋','宋诗','song-poetry','','[]','哲宗怒常立，時宰駡林自。',12,'全唐诗/poet.song.66000.json','["哲宗怒常立，時宰駡林自。"]'),
('cd6d2749-8ba5-4c37-ac6a-176a0ea0eec5','句  其二','陳瓘','宋','宋诗','song-poetry','','[]','拶破黄龍第四關，世人猶問生緣法。',16,'全唐诗/poet.song.66000.json','["拶破黄龍第四關，世人猶問生緣法。"]'),
('77419cba-dfc8-40dc-95d4-39a6082e1380','句  其三','陳瓘','宋','宋诗','song-poetry','','[]','黑石巴山硯，魚鱗蜀客箋。',12,'全唐诗/poet.song.66000.json','["黑石巴山硯，魚鱗蜀客箋。"]'),
('5f6dcad6-2c19-4bdb-ba09-a126bcb54605','句  其四','陳瓘','宋','宋诗','song-poetry','','[]','浦樹家家異。',6,'全唐诗/poet.song.66000.json','["浦樹家家異。"]'),
('f84d3006-717c-4537-b33d-ddc3895d5c59','句  其五','陳瓘','宋','宋诗','song-poetry','','[]','無金可寄東門傅，有齒能欺柱下蒼。',16,'全唐诗/poet.song.66000.json','["無金可寄東門傅，有齒能欺柱下蒼。"]'),
('1280c9da-ba5a-4989-9754-148eab3201ab','句  其六','陳瓘','宋','宋诗','song-poetry','','[]','歲久漫傳龍變化，潭深誰睹劍鋒鋩。',16,'全唐诗/poet.song.66000.json','["歲久漫傳龍變化，潭深誰睹劍鋒鋩。"]'),
('e60fc2f5-0e76-4009-b6f4-8375f1d582d8','句  其七','陳瓘','宋','宋诗','song-poetry','','[]','看花出約幾時回。',8,'全唐诗/poet.song.66000.json','["看花出約幾時回。"]'),
('8efb26ef-b4e9-4ede-9650-cfb424e2de00','湖上聯句','崔鶠','宋','宋诗','song-poetry','','[]','遙岑艤舟見，野思過橋生。',24,'全唐诗/poet.song.66000.json','["遙岑艤舟見，野思過橋生。", "興盡回蘭棹，歸鞍月正明。"]'),
('2caf3678-573a-4f54-98e6-fa8a09fb9dca','會節園梅花下作','崔鶠','宋','宋诗','song-poetry','','[]','去年白玉花，結子深林間。',48,'全唐诗/poet.song.66000.json','["去年白玉花，結子深林間。", "小憩藉清影，低顰啄微酸。", "故人不復見，春事今已闌。", "繞樹尋履迹，空餘土花斑。"]'),
('8be6372e-38dd-4984-9989-e942a3b59fa9','秋日即事','崔鶠','宋','宋诗','song-poetry','','[]','秋草門前已沒靴，更無人過野人家。',32,'全唐诗/poet.song.66000.json','["秋草門前已沒靴，更無人過野人家。", "離離疏竹時聞雨，淡淡輕烟不隔花。"]'),
('219bc818-22f3-4024-88b9-002941a38d60','黄州道中','崔鶠','宋','宋诗','song-poetry','','[]','莫愁微雨落輕雲，十里長亭未墊巾。',32,'全唐诗/poet.song.66000.json','["莫愁微雨落輕雲，十里長亭未墊巾。", "流水小橋山下路，馬頭無處不逢春。"]'),
('b2b638be-17b7-4273-b2a7-f3457404e283','潜心齋','崔鶠','宋','宋诗','song-poetry','','[]','雙扉掩餘香，一榻下凉幔。',48,'全唐诗/poet.song.66000.json','["雙扉掩餘香，一榻下凉幔。", "前人嗟不死，萬古映黄卷。", "時時擷英華，一一詣微遠。", "鼎食姑置之，此味良不淺。"]'),
('35715e05-9ad8-4910-91aa-8c3831ce06aa','止遽軒','崔鶠','宋','宋诗','song-poetry','','[]','我如萬斛船，歲久腰已懶。',48,'全唐诗/poet.song.66000.json','["我如萬斛船，歲久腰已懶。", "誰能逐相師，終日問手板。", "去謀一寸安，輒被三尺挽。", "憐公謝蠻觸，鼓卧旗亦偃。"]'),
('8b31b53a-0350-4417-902f-f974bb522eaf','丈室','崔鶠','宋','宋诗','song-poetry','','[]','此家英妙姿，玉雪熙冠冕。',36,'全唐诗/poet.song.66000.json','["此家英妙姿，玉雪熙冠冕。", "新詩一何似，鸞鵠見蕭散。", "躡屣往從之，寧復念重趼。"]'),
('6c77dd5b-0c5d-4b7b-ad0c-b049f6b5df6f','詩二首  其一','崔鶠','宋','宋诗','song-poetry','','[]','淚盡空山一病夫，荆榛無路掩樵居。',32,'全唐诗/poet.song.66000.json','["淚盡空山一病夫，荆榛無路掩樵居。", "自憐身是皮公美，茅屋青燈夜著書。"]'),
('017bf1c1-5ea2-4b0f-b43f-8ff36b10c968','詩二首  其二','崔鶠','宋','宋诗','song-poetry','','[]','記得詩狂欲發時，鄱陽湖裏月明知。',32,'全唐诗/poet.song.66000.json','["記得詩狂欲發時，鄱陽湖裏月明知。", "無人爲覓桓伊笛，自捲秋蘆片葉吹。"]'),
('801b5acf-31ab-4e02-8532-8f97e27ed1f0','酴醾依柏引蔓上冒其顛','崔鶠','宋','宋诗','song-poetry','','[]','春風亦已老，自厭丹采媚。',72,'全唐诗/poet.song.66000.json','["春風亦已老，自厭丹采媚。", "獨留白雪花，灑此千尺翠。", "嵯峨珠籠冠，縹緲冒佛髻。", "幽香勿襲人，恐爲真色累。", "但願保明姿，終日奉清對。", "要之萬物夥，汙潔自有類。"]'),
('60cc133c-eac0-47d2-8170-6ae6eb96ff58','江月圖','崔鶠','宋','宋诗','song-poetry','','[]','冥冥一葉輕，不知水與天。',84,'全唐诗/poet.song.66000.json','["冥冥一葉輕，不知水與天。", "獨於顥氣中，仰見素璧圓。", "超然狂道士，起視清夜闌。", "自拈白玉笛，吹此江月寒。", "想當萬籟息，逸響流空烟。", "我從江海來，形留意先還。", "何當買魚篷，追此水墨仙。"]'),
('91c5b97c-ab3f-4ddf-8751-345c5b5d09b6','早春偶題','崔鶠','宋','宋诗','song-poetry','','[]','寒風淅瀝鳴枯葦，小鴨睡殘猶未起。',64,'全唐诗/poet.song.66000.json','["寒風淅瀝鳴枯葦，小鴨睡殘猶未起。", "更教細雨結輕寒，坐聽蕭蕭打窗紙。", "石盆養蒲已抽翠，雕斛栽花先弄紫。", "擁爐閉閤賦幽香，未怕春冰生硯水。"]'),
('eac1ecbd-d52b-48c3-b671-807f6dc6325a','石牛莊閒居','崔鶠','宋','宋诗','song-poetry','','[]','不識春風面，知從底處來。',48,'全唐诗/poet.song.66000.json','["不識春風面，知從底處來。", "紅深桃靨破，綠靜水簾開。", "物外心常掛，人間事不諧。", "從今江海去，無復世推排。"]'),
('47b8fbe4-f5dd-4e20-8d19-6fe1edfc1729','春日','崔鶠','宋','宋诗','song-poetry','','[]','落日不可盡，丹林紫谷開。',24,'全唐诗/poet.song.66000.json','["落日不可盡，丹林紫谷開。", "明明遠色裏，歷歷暝鴉回。"]'),
('57d415e3-d835-4e0e-bf32-19d6ab4c6440','題績溪雪峰樓','崔鶠','宋','宋诗','song-poetry','','[]','題詩最高處，不爲付人看。',24,'全唐诗/poet.song.66000.json','["題詩最高處，不爲付人看。", "記著今朝勝，山明松雪寒。"]'),
('56d486d6-c297-4744-b5da-e052c5b8cdd2','子石硯','崔鶠','宋','宋诗','song-poetry','','[]','石家有兒玉含晶，噓爲雲氣吸爲晴。',48,'全唐诗/poet.song.66000.json','["石家有兒玉含晶，噓爲雲氣吸爲晴。", "純精與之相感并，孕育萬狀流千名。", "黄昏鬼哭不忍聽，且爲白鵝了黄庭。"]'),
('3ac1d390-a78b-44d3-bf85-f3cf6317602d','早秋雨霽圖','崔鶠','宋','宋诗','song-poetry','','[]','我離蜀山來，赤日走東州。',144,'全唐诗/poet.song.66000.json','["我離蜀山來，赤日走東州。", "奇峰作眼想，一過神已留。", "翩翩宋公子，新詩藹風流。", "丹青見新韵，瀟灑出林丘。", "依微萬里遙，曠明一雨收。", "高雲杳褰開，縞日明華秋。", "風裾映山青，眇眇行李幽。", "得非送將歸，色有離別憂。", "念我山海癖，鍼砭不爲瘳。", "目看孤鴻飛，心已麋鹿游。", "吾兒能扶犁，此幘便可投。", "勿言尺寸許，是中有菟裘。"]'),
('5c3b0786-b4ef-4e5c-848c-26b7fedddaa5','與叔易過石佛看宋大夫畫山水','崔鶠','宋','宋诗','song-poetry','','[]','霜落石林江氣清，隔江猶見暮山橫。',32,'全唐诗/poet.song.66000.json','["霜落石林江氣清，隔江猶見暮山橫。", "箇中只欠崔夫子，滿帽秋風信馬行。"]'),
('85a52e7c-13d8-4642-9176-b8ea82f01194','觀黄筌畫花二首  其一','崔鶠','宋','宋诗','song-poetry','','[]','蒼顔白髮我雖陳，見了青紅幾度新。',32,'全唐诗/poet.song.66000.json','["蒼顔白髮我雖陳，見了青紅幾度新。", "更向黄生毫末裏，全家看盡劍南春。"]'),
('ff14e003-b99e-4e21-b710-cddb4f2b77f9','觀黄筌畫花二首  其二','崔鶠','宋','宋诗','song-poetry','','[]','淺淺紅顴與白腮，卧枝斜葉抱新開。',32,'全唐诗/poet.song.66000.json','["淺淺紅顴與白腮，卧枝斜葉抱新開。", "何人與作春風面，誑得蜂兒日日來。"]'),
('3eda2248-bbc3-4049-98f4-d3c08e4894ae','和老人觀牧圖','崔鶠','宋','宋诗','song-poetry','','[]','作官畏人嘲，胡孫騎牧牛。',126,'全唐诗/poet.song.66000.json','["作官畏人嘲，胡孫騎牧牛。", "却離大江水，還家整歸舟。", "還家此計不可移，此樂勿令兒輩知。", "行歌带索拾遺穗，耳靜不復聞征鼙。", "功名亦妄爾，吾生去此將安之。", "趁此青草長，自牧牛與羊。", "不減九十頭，何翅三百强。", "沙平水淺南山下，千角萬蹄如此畫。", "牛腰吹笛遡秋風，不問人間矍鑠翁。"]'),
('4e3ed906-6daa-4c17-84d9-534ddac9c38c','梅花  其一','崔鶠','宋','宋诗','song-poetry','','[]','仙子衣裳雲不染，天人顔色玉無瑕。',32,'全唐诗/poet.song.66000.json','["仙子衣裳雲不染，天人顔色玉無瑕。", "月寒桂樹猶藏魄，海凍珊瑚未放芽。"]'),
('05211926-4fd9-42d3-843a-ceef0a13671e','梅花  其二','崔鶠','宋','宋诗','song-poetry','','[]','壽陽樓畔晴梅落，孝武宮中曉露溥。',48,'全唐诗/poet.song.66000.json','["壽陽樓畔晴梅落，孝武宮中曉露溥。", "越浦爭回乘興棹，洛堤欲駐有情鞍。", "蝶遺粉翼輕難拾，鶴墜霜毛散未摶。"]'),
('eee13c99-5d0f-4db6-94ff-684064a1162d','觀魚','崔鶠','宋','宋诗','song-poetry','','[]','小魚喜親人，可釣亦可網。',48,'全唐诗/poet.song.66000.json','["小魚喜親人，可釣亦可網。", "大魚自有神，隠見誰能量。", "老禪雖無心，施食不肯嘗。", "時於千尋底，隠見如龍章。"]'),
('6334243c-4ba3-4da4-89d7-364d8db5636e','桃花','崔鶠','宋','宋诗','song-poetry','','[]','如何一朽株，孕此千億花。',36,'全唐诗/poet.song.66000.json','["如何一朽株，孕此千億花。", "雖云行且闌，明歲亦再華。", "豈如世上人，一老不復佳。"]'),
('4fb25a81-42dd-44b1-9b48-cf7c8c70bbe0','桃花','崔鶠','宋','宋诗','song-poetry','','[]','殘月迷春曉，桃花怯夜寒。',24,'全唐诗/poet.song.66000.json','["殘月迷春曉，桃花怯夜寒。", "何人未粧洗，先傍玉闌干。"]'),
('d88694df-b5a9-47ba-8b61-e0123f7e57bf','海棠','崔鶠','宋','宋诗','song-poetry','','[]','渾是華清出浴初，碧綃斜掩見紅膚。',32,'全唐诗/poet.song.66000.json','["渾是華清出浴初，碧綃斜掩見紅膚。", "便教桃李能言語，要比嬌妍比得無。"]'),
('574fd3f6-946b-4f59-b220-90f3c96ca6bf','和呂居仁九日詩','崔鶠','宋','宋诗','song-poetry','','[]','街頭未易著清香，折取蕭蕭滿把黄。',32,'全唐诗/poet.song.66000.json','["街頭未易著清香，折取蕭蕭滿把黄。", "歸去乞錢煩里社，買糕沽酒作重陽。"]'),
('4d68a611-2be0-4ba7-8c19-866475fcdca1','詩四首  其一','崔鶠','宋','宋诗','song-poetry','','[]','我如秋蝶未忘情，對此寒花歎此生。',32,'全唐诗/poet.song.66000.json','["我如秋蝶未忘情，對此寒花歎此生。", "常愧老來親拄杖，看花不似蝶身輕。"]'),
('f1a8e0d3-2616-47b0-a9cf-10e6525502ba','詩四首  其二','崔鶠','宋','宋诗','song-poetry','','[]','芙蓉堂下水溟溟，老去難禁此段清。',32,'全唐诗/poet.song.66000.json','["芙蓉堂下水溟溟，老去難禁此段清。", "喚取王郎吹玉笛，愁來要聽水龍聲。"]'),
('027d4499-9812-4902-9c2d-31b57da42cba','詩四首  其三','崔鶠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','荒蒲亂葦簇人烟，指點江州一望間。',32,'全唐诗/poet.song.66000.json','["荒蒲亂葦簇人烟，指點江州一望間。", "惜取看人閑目力，琵琶亭上看廬山。"]'),
('1f48932c-1e5b-43e6-b22a-76c4ae17709b','詩四首  其四','崔鶠','宋','宋诗','song-poetry','','[]','屯雲塞望蔚青林，刻雪停空立皓禽。',32,'全唐诗/poet.song.66000.json','["屯雲塞望蔚青林，刻雪停空立皓禽。", "南渡長淮纔一水，令人便起五湖心。"]'),
('a2617e23-3206-497a-ba7b-132b700a4cbf','詠圓通崇勝院','崔鶠','宋','宋诗','song-poetry','','[]','崢嶸盧山高，下看三江水。',108,'全唐诗/poet.song.66000.json','["崢嶸盧山高，下看三江水。", "青天瀑布飛，白日看烟起。", "人家閑崦口，石道喬松底。", "似窺仙剎麗，翠影亂螭尾。", "亭亭兩金閭，妙擁青雲裏。", "瞻言古堂側，絳幔垂烏几。", "煌煌重瞳君，玉带橫文綺。", "名爲天下笑，身繫降生邸。", "辛苦萬厄功，一戲直童子。"]'),
('e21947ea-cd13-44b7-96ae-c02892b47648','勸忠樓','崔鶠','宋','宋诗','song-poetry','','[]','聞說驪龍睡九淵，覺來頭角去升天。',64,'全唐诗/poet.song.66000.json','["聞說驪龍睡九淵，覺來頭角去升天。", "官封越國三千戶，血食新安五百年。", "錦軸尚標唐歲月，彩樓重見宋山川。", "收藏石匣非無意，留與江南野史傳。"]'),
('35254c4e-37a9-4306-bc04-0828272efc23','新安四詠  其一','崔鶠','宋','宋诗','song-poetry','','[]','我愛新安好，齋房四友全。',48,'全唐诗/poet.song.66000.json','["我愛新安好，齋房四友全。", "斲成千樣玉，掃得萬毬烟。", "雲氣隨銀管，蛟龍入彩箋。", "周旋不能去，何待更論年。"]'),
('ca19f041-68b2-4279-bed9-90bde95de78b','新安四詠  其二','崔鶠','宋','宋诗','song-poetry','','[]','我愛新安好，城西似竹西。',48,'全唐诗/poet.song.66000.json','["我愛新安好，城西似竹西。", "僧扉入黄葉，樵徑下寒溪。", "寶閣花爲網，珍臺玉作梯。", "不愁臨暮雨，白石了無泥。"]'),
('db7d4f02-f2ec-4cf8-bfea-ac756b4445b1','新安四詠  其三','崔鶠','宋','宋诗','song-poetry','','[]','我愛新安好，新安勝事多。',48,'全唐诗/poet.song.66000.json','["我愛新安好，新安勝事多。", "秋容明遠眺，夜響答清歌。", "寺映離離葉，城通瑟瑟波。", "黄山敵嵩阜，三十六嵯峨。"]'),
('c503b3a0-6802-400b-ae67-901c3809079a','新安四詠  其四','崔鶠','宋','宋诗','song-poetry','','[]','我愛新安好，新安度歲華。',48,'全唐诗/poet.song.67000.json','["我愛新安好，新安度歲華。", "風烟迷郡閣，浦溆带人家。", "南畝元多黍，丘中亦種麻。", "更逢飄皂蓋，疆埸視新瓜。"]'),
('b6f9bf0e-93e6-40c6-ae0a-6c5521440ffc','績溪道中三首  其一','崔鶠','宋','宋诗','song-poetry','','[]','䆉稏青衣未剡芒，聯拳荷葉已秋香。',32,'全唐诗/poet.song.67000.json','["䆉稏青衣未剡芒，聯拳荷葉已秋香。", "笋輿十里青松路，高捲蒙紗遡晚凉。"]'),
('a9ccf45b-e0af-4f2e-9369-98989b61c301','績溪道中三首  其二','崔鶠','宋','宋诗','song-poetry','','[]','摐摐名木列千兵，風雨斜來捲旆旌。',32,'全唐诗/poet.song.67000.json','["摐摐名木列千兵，風雨斜來捲旆旌。", "愁倚寺門南下望，水烟不見小橋橫。"]'),
('849e19bc-8639-403e-bf40-3e684a5caaee','績溪道中三首  其三','崔鶠','宋','宋诗','song-poetry','','[]','山口含糊半吐雲，林頭時見綠紛紛。',32,'全唐诗/poet.song.67000.json','["山口含糊半吐雲，林頭時見綠紛紛。", "何人解作孤鸞嘯，呼取凉風入帽裙。"]'),
('da49f1ad-a862-4d4c-8779-4633ea2350d4','婆娑園','崔鶠','宋','宋诗','song-poetry','','[]','晚禽噪竹百千翅，殘菊橫枝三兩花。',32,'全唐诗/poet.song.67000.json','["晚禽噪竹百千翅，殘菊橫枝三兩花。", "好在山園養衰廢，風波不到野人家。"]'),
('0c992731-c974-412d-b2f5-fa7544ac1e6c','句  其一','崔鶠','宋','宋诗','song-poetry','','[]','伯鸞下吳越。',6,'全唐诗/poet.song.67000.json','["伯鸞下吳越。"]'),
('7a4262a5-ca86-453b-9b09-579776d4e19c','句  其二','崔鶠','宋','宋诗','song-poetry','','[]','遙知金剎近，林表颺幡尾。',12,'全唐诗/poet.song.67000.json','["遙知金剎近，林表颺幡尾。"]'),
('88db6140-eb60-42ee-8bd4-287fb358e134','句  其三','崔鶠','宋','宋诗','song-poetry','','[]','小艇元從天上來，白雲自向盃中落。',16,'全唐诗/poet.song.67000.json','["小艇元從天上來，白雲自向盃中落。"]'),
('c34b0301-7047-425a-8566-e8419df7763f','句  其四','崔鶠','宋','宋诗','song-poetry','','[]','翠裘錦帽初相識，魚虎彎環略岸飛。',16,'全唐诗/poet.song.67000.json','["翠裘錦帽初相識，魚虎彎環略岸飛。"]'),
('49953e9b-0175-4b27-8b9e-c88626511a31','句  其五','崔鶠','宋','宋诗','song-poetry','','[]','一從臺傾苑樹死，空餘飄瓦裁紋鴛。',16,'全唐诗/poet.song.67000.json','["一從臺傾苑樹死，空餘飄瓦裁紋鴛。"]'),
('e8f67204-07ba-4c41-b2fb-5697656b3c16','句  其六','崔鶠','宋','宋诗','song-poetry','','[]','團臍紫蟹初欲嘗，染指腥鹽還復輟。',16,'全唐诗/poet.song.67000.json','["團臍紫蟹初欲嘗，染指腥鹽還復輟。"]'),
('02d59458-832a-4fbc-b060-460ce0b37643','句  其七','崔鶠','宋','宋诗','song-poetry','','[]','清明烟火尚闌珊，花信風來第幾番。',16,'全唐诗/poet.song.67000.json','["清明烟火尚闌珊，花信風來第幾番。"]'),
('09eff38b-e6e1-4061-921a-38044383e85c','句  其八','崔鶠','宋','宋诗','song-poetry','','[]','西山橫身映吳甸，意將萬里傾衡霍。',16,'全唐诗/poet.song.67000.json','["西山橫身映吳甸，意將萬里傾衡霍。"]'),
('323a89b1-6a6c-437c-8c28-8b2a615a4df1','句  其九','崔鶠','宋','宋诗','song-poetry','','[]','綽約冰姿絕可憐。',8,'全唐诗/poet.song.67000.json','["綽約冰姿絕可憐。"]'),
('86d85ac3-0ec7-46b9-a624-03d96143e300','句  其一○','崔鶠','宋','宋诗','song-poetry','','[]','老去未覺躋攀難，一表獨立青冥裏。',16,'全唐诗/poet.song.67000.json','["老去未覺躋攀難，一表獨立青冥裏。"]'),
('1c2295b0-9296-441f-8411-054ec8e26bbe','遊香山佛跡','周鍔','宋','宋诗','song-poetry','','[]','靈山名達蓬，香水靄薝蔔。',144,'全唐诗/poet.song.67000.json','["靈山名達蓬，香水靄薝蔔。", "龍祇久覆護，雲物翳深谷。", "拂衣向劫中，神斧斷蒼玉。", "至今天人尊，靈跡印金粟。", "頗聞開士讖，飛錫隠巖麓。", "坐令湖海客，香供走川陸。", "巍巍虔報地，色相儼金屋。", "緬想舊巾瓶，猶能慰心目。", "籃輿訪蓮社，一笑欣自足。", "撫事動幽尋，疇能念榮辱。", "松爐裊如見，餘力付棋局。", "更覺夢中身，翛然百無欲。"]'),
('38027d99-6d6d-4edf-a567-10ae70e5b357','和郡守彭吏部按視湖亭凡二首  其一','周鍔','宋','宋诗','song-poetry','','[]','使君風味壓荆州，每爲吾民樂更憂。',64,'全唐诗/poet.song.67000.json','["使君風味壓荆州，每爲吾民樂更憂。", "錦里篇章推唱首，浣溪光景促遨頭。", "行春預約花欹帽，把酒方欣雪點裘。", "嶽史年來慚吏隠，扳輿時得從公遊。"]'),
('6c5b04eb-5681-4887-b8d1-8449aac6c9a6','和郡守彭吏部按視湖亭凡二首  其二','周鍔','宋','宋诗','song-poetry','','[]','雙虹倒影上簷楹，碧水澄空一鏡明。',64,'全唐诗/poet.song.67000.json','["雙虹倒影上簷楹，碧水澄空一鏡明。", "野草閑花無限趣，短藜幽榜不勝情。", "已知風月隨人意，聊爲湖山載酒行。", "却訝錦囊賡夢草，坐令詩興繞寰瀛。"]'),
('3f43ee40-0e46-4285-bc58-66c26d01d3b1','西湖三首  其一','周鍔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曉鏡初開淑景明，使君風味一般清。',64,'全唐诗/poet.song.67000.json','["曉鏡初開淑景明，使君風味一般清。", "舟從菡萏林中過，人在鯨鯢背上行。", "妙舞屢翻紅藥燕，清詞時囀紫薇鶯。", "賡歌久矣虛前席，肯向樽前戀麴生。"]'),
('32e98cb3-5434-467d-b06c-d510d3aaff86','西湖三首  其二','周鍔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','使君修禊與民遊，十里笙歌水面浮。',64,'全唐诗/poet.song.67000.json','["使君修禊與民遊，十里笙歌水面浮。", "動地雄風雲外起，截天雌霓雨中收。", "登臺已有難并樂，擊壤寧無寡和憂。", "却憶內家新賜火，海棠無數出牆頭。"]'),
('d595b36e-c282-48e4-9611-35bb1072d560','西湖三首  其三','周鍔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','牛鞭初動囀新鶯，夢覺池塘選勝行。',64,'全唐诗/poet.song.67000.json','["牛鞭初動囀新鶯，夢覺池塘選勝行。", "水鏡光中千騎合，山屏影裏萬艘橫。", "雲從布穀原頭過，雨向催詩筆下生。", "藻繪昇平知有待，閣梅先已賦調羹。"]'),
('23a851e1-5d95-4532-b8f9-ae0549b2c5df','澄輝閣','周鍔','宋','宋诗','song-poetry','','[]','雄建俯空闊，下瞻霄漢浮。',48,'全唐诗/poet.song.67000.json','["雄建俯空闊，下瞻霄漢浮。", "眼將雲漠漠，心寄水悠悠。", "日暖鳥飛鏡，月凉魚弄鈎。", "行期分此景，家在甬西頭。"]'),
('8cf763a2-e89d-41a0-b1d0-39d641e73828','馮氏萬金樓','周鍔','宋','宋诗','song-poetry','','[]','幾年江上夢，黄鶴意悠悠。',48,'全唐诗/poet.song.67000.json','["幾年江上夢，黄鶴意悠悠。", "百尺獨臨水，萬金難買秋。", "杵聲喧藥市，欄影枕漁舟。", "應有壺中客，分身向此遊。"]'),
('3c8b2f3a-93a2-4e52-b98a-14d9d157c02c','題清斯堂','周鍔','宋','宋诗','song-poetry','','[]','萬物本空寂，浮生方沼中。',48,'全唐诗/poet.song.67000.json','["萬物本空寂，浮生方沼中。", "鷗輕時出沒，萍散只西東。", "檻外風初息，天邊月正融。", "了無塵可濯，危坐照衰翁。"]'),
('d6f5f68f-8515-4171-ab1f-a757bc6198b2','李氏席上有感','邵伯溫','宋','宋诗','song-poetry','','[]','翻翻繡袖上紅裀，舞姬猶是舊精神。',32,'全唐诗/poet.song.67000.json','["翻翻繡袖上紅裀，舞姬猶是舊精神。", "坐中莫怪無歡意，我與將軍是故人。"]'),
('974c31b7-8399-49d4-96f7-6a24e0c6dde4','元夕','邵伯溫','宋','宋诗','song-poetry','','[]','從昔遨遊盛兩川，充城人物自駢闐。',32,'全唐诗/poet.song.67000.json','["從昔遨遊盛兩川，充城人物自駢闐。", "萬家燈火春風陌，十里綺羅明月天。"]'),
('c563d29f-539d-480e-b83b-fe33e35b5067','郡治五絕','邵伯溫','宋','宋诗','song-poetry','','[]','蜀地春爭一月天，雜花新歲已爭妍。',32,'全唐诗/poet.song.67000.json','["蜀地春爭一月天，雜花新歲已爭妍。", "却愁取次都開盡，辜負清明穀雨天。"]'),
('873ed3c1-ecae-44e6-b4a8-12325e820ac9','充城口號','邵伯溫','宋','宋诗','song-poetry','','[]','山圍翠合水連雲，萬室樓臺照眼明。',32,'全唐诗/poet.song.67000.json','["山圍翠合水連雲，萬室樓臺照眼明。", "勝地風淳真樂國，四川惟說好充城。"]'),
('053c9c6d-a9ce-4801-bba6-e575cdb1b608','觀進黄柑','邵伯溫','宋','宋诗','song-poetry','','[]','果州多黄柑，初比橘柚賤。',36,'全唐诗/poet.song.67000.json','["果州多黄柑，初比橘柚賤。", "一朝貢神州，妙極天下選。", "使者謹共時，頓首乃敢遣。"]'),
('aa3388a5-61df-40e7-8e78-e9629d7c24ef','黄柑','邵伯溫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','果山仙果秀天香，處處圓金樹樹黄。',32,'全唐诗/poet.song.67000.json','["果山仙果秀天香，處處圓金樹樹黄。", "書後欲題三百顆，滿林猶待洞庭霜。"]'),
('20c7e5ad-244b-4779-8434-c6f0e0e22e54','柑園','邵伯溫','宋','宋诗','song-poetry','','[]','守臣方效獻芹心，直擬移根到上林。',32,'全唐诗/poet.song.67000.json','["守臣方效獻芹心，直擬移根到上林。", "充貢先時猶茂綠，置郵須更待黄深。"]'),
