('1b5a180c-503c-403f-ac65-cdbbb3a6dfa1','偈九首  其一','釋惟清','宋','宋诗','song-poetry','','[]','浮雲散盡狂波止，天上玉蟾水底圓。',32,'全唐诗/poet.song.67000.json','["浮雲散盡狂波止，天上玉蟾水底圓。", "皎潔迥然通湛寂，此時消息若爲傳。"]'),
('f64584fe-a517-4f78-8299-a87f06ea4bd2','偈九首  其二','釋惟清','宋','宋诗','song-poetry','','[]','時時是好時，日日是好日。',40,'全唐诗/poet.song.67000.json','["時時是好時，日日是好日。", "烏兔體全身，靈機何處覓。", "今朝看見昨朝人，依舊眼睛光似漆。"]'),
('d01ccf0e-a0b1-4d00-9720-e626f6bd81fe','偈九首  其三','釋惟清','宋','宋诗','song-poetry','','[]','古佛不到處，諸人共用。',54,'全唐诗/poet.song.67000.json','["古佛不到處，諸人共用。", "諸人不到處，古佛同參。", "同參共用如何顯，種田博飯機非淺。", "因思昔日老師言，三界本無何用免。"]'),
('0b85a38b-e9a8-4868-8c03-c859dc488ee7','偈九首  其四','釋惟清','宋','宋诗','song-poetry','','[]','江月照，松風吹，永夜清宵更是誰。',52,'全唐诗/poet.song.67000.json','["江月照，松風吹，永夜清宵更是誰。", "霧露雲霞遮不得，箇中猶道不如歸。", "復何歸，荷葉團團團似鏡，菱角尖尖尖似錐。"]'),
('5cfefc91-d4b3-4465-8b11-f263000c38ac','偈九首  其五','釋惟清','宋','宋诗','song-poetry','','[]','天機藏不得，花笑鳥啼時。',24,'全唐诗/poet.song.67000.json','["天機藏不得，花笑鳥啼時。", "不待重拈出，當人合自知。"]'),
('7a25d97f-0aab-48c2-bb61-0a4ee4b87783','偈九首  其六','釋惟清','宋','宋诗','song-poetry','','[]','山是山，水是水。',32,'全唐诗/poet.song.67000.json','["山是山，水是水。", "僧是僧，俗是俗。", "更將何物演真乘，六六元來三十六。"]'),
('40386f26-15ec-48d1-b974-5710150d71b4','偈九首  其七','釋惟清','宋','宋诗','song-poetry','','[]','一是一，二是二。',34,'全唐诗/poet.song.67000.json','["一是一，二是二。", "頭上是天，脚下是地。", "饑即餐兮困即睡，人人皆受如來記。"]'),
('14a0a08e-abee-4a83-b42e-b8d301de3db2','偈九首  其八','釋惟清','宋','宋诗','song-poetry','','[]','三世諸佛，不知有恩無重報。',66,'全唐诗/poet.song.67000.json','["三世諸佛，不知有恩無重報。", "狸奴白牯，却知有功不浪施。", "明大用，曉全機。", "絕蹤跡，不思議。", "歸去好，無人知。", "衝開碧落松千尺，截斷紅塵水一溪。"]'),
('7bb37941-2476-4469-9ebe-b973a01f0875','偈九首  其九','釋惟清','宋','宋诗','song-poetry','','[]','衲僧照徹千差眼，緇素淺深毫髮分。',32,'全唐诗/poet.song.67000.json','["衲僧照徹千差眼，緇素淺深毫髮分。", "分處莫非全正令，法王那得獨稱尊。"]'),
('54dbdbda-713e-4548-adad-5cd3b1f9026b','辭無盡居士','釋惟清','宋','宋诗','song-poetry','','[]','無地無錐徹骨貧，利生深愧乏餘珍。',32,'全唐诗/poet.song.67000.json','["無地無錐徹骨貧，利生深愧乏餘珍。", "廛中大施門難啟，乞與青山養病身。"]'),
('ef78c288-7a15-4ed7-b2de-2e842d78e119','偈二首  其一','釋惟清','宋','宋诗','song-poetry','','[]','東坡笑說吃龍肉，舌底那知已嚥津。',32,'全唐诗/poet.song.67000.json','["東坡笑說吃龍肉，舌底那知已嚥津。", "能省嚥津真有味，會言龍肉不爲珍。"]'),
('85d148a8-cbbe-43b6-bf46-8eefbb059cba','偈二首  其二','釋惟清','宋','宋诗','song-poetry','','[]','何知龍肉即豬肉，細語粗言盡入神。',32,'全唐诗/poet.song.67000.json','["何知龍肉即豬肉，細語粗言盡入神。", "惜彼當年老居士，大機曾未脫根塵。"]'),
('5ee29ee1-c8b5-4f41-8783-1d3eaa32eb40','偈五首  其一','釋善清','宋','宋诗','song-poetry','','[]','不出三門九十日，大都只要此心休。',32,'全唐诗/poet.song.67000.json','["不出三門九十日，大都只要此心休。", "此心休了全無事，天下名山任意遊。"]'),
('d34f173e-68c2-4762-bb6b-ebe1a8785d41','偈五首  其二','釋善清','宋','宋诗','song-poetry','','[]','掩息茅堂過六冬，心忘境寂萬緣空。',32,'全唐诗/poet.song.67000.json','["掩息茅堂過六冬，心忘境寂萬緣空。", "不知幻業從何起，依舊令教振祖風。"]'),
('041a7852-bc75-4c21-b4f9-7a8027945124','偈五首  其三','釋善清','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬仞嵯峨鳥道難，劍輪揮處骨毛寒。',32,'全唐诗/poet.song.67000.json','["萬仞嵯峨鳥道難，劍輪揮處骨毛寒。", "泥牛昨夜歸滄海，吸得西江水盡乾。"]'),
('77140673-2e31-4fc3-88b0-6234f8d0d7f7','偈五首  其四','釋善清','宋','宋诗','song-poetry','','[]','日入酉，夢幻空花能幾久。',44,'全唐诗/poet.song.67000.json','["日入酉，夢幻空花能幾久。", "百歲光陰二分過，茫茫無限途中走。", "告禪人，早回首，莫待春風動楊柳。"]'),
('b58e7f14-1180-453d-be1c-e6834dd25ca5','偈五首  其五','釋善清','宋','宋诗','song-poetry','','[]','雲從龍，風從虎，冬至寒食一百五。',64,'全唐诗/poet.song.67000.json','["雲從龍，風從虎，冬至寒食一百五。", "自古相傳直至今，南泉不打鹽官鼓。", "參玄人，休莽鹵，甜者甜兮苦者苦。", "直截毗盧向上關，莫教錯却來時路。"]'),
('2c3f3afa-871d-4155-9866-b67ed2facf0f','讀法界觀','釋善清','宋','宋诗','song-poetry','','[]','多中即一一中多，浪裏全提水是波。',32,'全唐诗/poet.song.67000.json','["多中即一一中多，浪裏全提水是波。", "波水滅時多一盡，日輪當午見星河。"]'),
('829557fa-4868-4320-8e0b-99c521f43552','送臨安南蕩崇覺空禪師偈','釋善清','宋','宋诗','song-poetry','','[]','十年聚首龍峰寺，一悟真空萬境閒。',32,'全唐诗/poet.song.67000.json','["十年聚首龍峰寺，一悟真空萬境閒。", "此去隨緣且高隠，莫將名字落人間。"]'),
('b057e012-d199-4fc5-ac97-04e3fa8c68bb','偈','釋善清','宋','宋诗','song-poetry','','[]','隨隨隨，昔昔昔，隨隨隨後無人識。',32,'全唐诗/poet.song.67000.json','["隨隨隨，昔昔昔，隨隨隨後無人識。", "夜來明月上高峰，元來祇是這個賊。"]'),
('a67fc7ee-085a-4450-b277-1ec1c8c3cb12','頌二首  其一','釋善清','宋','宋诗','song-poetry','','[]','銅砂鑼裏油清浄，照見塵中舊主人。',32,'全唐诗/poet.song.67000.json','["銅砂鑼裏油清浄，照見塵中舊主人。", "寄語禪人猛參取，莫教孤負此生身。"]'),
('fbaa713b-dfc8-4d6b-9ada-1b2a3f9ca793','頌二首  其二','釋善清','宋','宋诗','song-poetry','','[]','八萬四千非一一，七金山內海滔滔。',32,'全唐诗/poet.song.67000.json','["八萬四千非一一，七金山內海滔滔。", "妙高峰頂平如掌，誰把長竿釣巨鼇。"]'),
('aa63ffa2-0303-4f80-a280-242a5d7e40be','訪王官谷休休亭二首  其一','仇伯玉','宋','宋诗','song-poetry','','[]','飄香山徑踏殘花，來訪仙鄉隠處家。',32,'全唐诗/poet.song.67000.json','["飄香山徑踏殘花，來訪仙鄉隠處家。", "當日廟堂延至計，未應懷璧老烟霞。"]'),
('48079207-a453-4b7d-9969-2070a8230ba5','訪王官谷休休亭二首  其二','仇伯玉','宋','宋诗','song-poetry','','[]','山鴉營巢欲哺兒，晴杏拆早先離披。',32,'全唐诗/poet.song.67000.json','["山鴉營巢欲哺兒，晴杏拆早先離披。", "盤回一徑穿碧篠，谷口數家耕水湄。"]'),
('392dc33d-f8f9-4547-8952-193d6c50a9d6','題集仙橋','游冠卿','宋','宋诗','song-poetry','','[]','南橋頹廢長官羞，新作川梁代濟舟。',64,'全唐诗/poet.song.67000.json','["南橋頹廢長官羞，新作川梁代濟舟。", "上應星文橫北極，下飛虹影落中流。", "慚無子産乘輿惠，謾絕襄公茀道憂。", "路接蓬山仙世界，品題今爲邑人留。"]'),
('9b612fd9-2136-441d-b274-088d827b95a0','白鶴禪寺','湯乂','宋','宋诗','song-poetry','','[]','舊隠神仙宅，空王殿閣深。',48,'全唐诗/poet.song.67000.json','["舊隠神仙宅，空王殿閣深。", "煉丹烟已冷，入竹路難尋。", "峰迥簫吹玉，溪寒石點金。", "靈源雙瀑布，千古得清音。"]'),
('3bd3d944-c490-4f89-8784-3ef09878b7b3','句','錢世雄','宋','宋诗','song-poetry','','[]','黄泥坂西春欲回，雪堂萬木連雲栽。',16,'全唐诗/poet.song.67000.json','["黄泥坂西春欲回，雪堂萬木連雲栽。"]'),
('27a8542f-f8bd-44cb-b89a-537cc449980c','不預曲宴詩','楊允','宋','宋诗','song-poetry','','[]','聞說宮花滿鬢紅，上林絲管侍重瞳。',32,'全唐诗/poet.song.67000.json','["聞說宮花滿鬢紅，上林絲管侍重瞳。", "蓬萊咫尺無由到，始信仙風迥不同。"]'),
('adb73466-4839-49cf-84fc-37c9078f88f4','戍山晚行','李回','宋','宋诗','song-poetry','','[]','羸馬鞭不行，落日下孤戍。',72,'全唐诗/poet.song.67000.json','["羸馬鞭不行，落日下孤戍。", "旅店隔前村，欲往未能住。", "少年事咿唔，老爲微祿誤。", "匡濟謝菲才，馳驅失故步。", "一笑擁八騶，不療烟霞痼。", "猿鶴驚且恐，吟斷北山樹。"]'),
('58d1e3f1-6cdb-45ed-be9b-6a5744a36503','題妓帕','李回','宋','宋诗','song-poetry','','[]','蜀國佳人號細腰，東臺御史惜妖嬈。',32,'全唐诗/poet.song.67000.json','["蜀國佳人號細腰，東臺御史惜妖嬈。", "從今喚作楊臺柳，舞盡春風萬萬條。"]'),
('4d4e3639-4831-42c7-a909-ce93a2f11777','湯泉','周沔','宋','宋诗','song-poetry','','[]','雁門泉水熱於湯，清凈源從古道場。',32,'全唐诗/poet.song.67000.json','["雁門泉水熱於湯，清凈源從古道場。", "應笑驪山山下水，至今猶带粉脂香。"]'),
('482c1683-3fd4-4aea-9a5b-2f546ccd2b08','句','周沔','宋','宋诗','song-poetry','','[]','螢火不知人已去，夜深猶傍竹窗明。',16,'全唐诗/poet.song.67000.json','["螢火不知人已去，夜深猶傍竹窗明。"]'),
('6d5ede6c-a7ad-4316-96fd-31113c0fc5e4','和韓子蒼游赤壁','何頡之','宋','宋诗','song-poetry','','[]','兒時宗伯寄吾州，諷誦高文至白頭。',64,'全唐诗/poet.song.67000.json','["兒時宗伯寄吾州，諷誦高文至白頭。", "二賦人間真吐鳳，五年溪上不驚鷗。", "蟹嘗見水人猶怒，鶻有危巢孰敢留。", "珍重使君尋故迹，西風悵望古城樓。"]'),
('d3399e6d-48c7-4fdd-a883-5bea55b95a13','觀李伯時題閻立本西域圖','何頡之','宋','宋诗','song-poetry','','[]','窮荒未信子年欺，自笑山林老一枝。',64,'全唐诗/poet.song.67000.json','["窮荒未信子年欺，自笑山林老一枝。", "海上嘗思龜殻卷，天涯欲化鳥工窺。", "丹青閻令如曾到，風俗張騫舊獨知。", "公喜著書尤博雅，山經暇日補殘遺。"]'),
('64ef92ae-86ff-493f-94b9-251c1e87ece5','黄綿襖絕句','何頡之','宋','宋诗','song-poetry','','[]','范叔綿袍暖一身，大裘只蓋洛陽人。',32,'全唐诗/poet.song.67000.json','["范叔綿袍暖一身，大裘只蓋洛陽人。", "九州四海黄綿襖，誰似天公賜予均。"]'),
('7c82d842-dd72-4831-8c7c-1b91062fb4b8','詩一首','何頡之','宋','宋诗','song-poetry','','[]','長安古碑用樂石，蠆尾銀鈎擅精密。',48,'全唐诗/poet.song.67000.json','["長安古碑用樂石，蠆尾銀鈎擅精密。", "缺訛橫道已足哀，况復鎸裁代磚甓。", "有如天吳及紫鳳，顛倒在衣吁可惜。"]'),
('cce3e8bf-0a29-4cfa-8512-21d093aa603a','句  其一','何頡之','宋','宋诗','song-poetry','','[]','秋水因君話河伯，接籬持酒對山公。',16,'全唐诗/poet.song.67000.json','["秋水因君話河伯，接籬持酒對山公。"]'),
('fd7a5b6f-1852-441b-955b-298e1c04ab1c','句  其二','何頡之','宋','宋诗','song-poetry','','[]','碧樹高巖底。',6,'全唐诗/poet.song.67000.json','["碧樹高巖底。"]'),
('3138810a-537e-4aa5-ac1b-954cb168955d','句  其三','何頡之','宋','宋诗','song-poetry','','[]','曉風熏麝馥，秋露染鵝黄。',12,'全唐诗/poet.song.67000.json','["曉風熏麝馥，秋露染鵝黄。"]'),
('612f98f9-703a-43ab-bf0a-661fd554f5d7','句  其四','何頡之','宋','宋诗','song-poetry','','[]','身到瀛洲須命好，官稱庾氏莫言卑。',16,'全唐诗/poet.song.67000.json','["身到瀛洲須命好，官稱庾氏莫言卑。"]'),
('b0eccf54-04ac-4a3f-b9bc-7d5414b49ea3','雪中失白馬','仇博','宋','宋诗','song-poetry','','[]','絲韁誤解白龍飛，滿地瓊瑶襯粉蹄。',32,'全唐诗/poet.song.67000.json','["絲韁誤解白龍飛，滿地瓊瑶襯粉蹄。", "愁殺塞翁尋不見，月明風靜只聞嘶。"]'),
('61be0d59-a10a-4fd1-832f-550c3249d7e8','野狐','釋心道','宋','宋诗','song-poetry','','[]','石崇富貴籛鏗壽，潘岳容儀子建才。',32,'全唐诗/poet.song.67000.json','["石崇富貴籛鏗壽，潘岳容儀子建才。", "但願東風齊著力，一時吹入我門來。"]'),
('7bcb165a-7834-4744-8e77-e26f63cb2a5f','勘婆','釋心道','宋','宋诗','song-poetry','','[]','三月春光上國游，祥雲瑞氣鎖龍樓。',32,'全唐诗/poet.song.67000.json','["三月春光上國游，祥雲瑞氣鎖龍樓。", "親從宣德門前過，更問行人覓汴州。"]'),
('5b7aaf00-576e-4be6-afc2-2bea63beaa5a','狗子無佛性','釋心道','宋','宋诗','song-poetry','','[]','狗子佛性無，老蚌吐明珠。',24,'全唐诗/poet.song.67000.json','["狗子佛性無，老蚌吐明珠。", "西川鳴杜宇，江南啼鷓鴣。"]'),
('b974f076-beae-4683-999b-1f108beb4d41','燒木佛','釋心道','宋','宋诗','song-poetry','','[]','彭祖八百乞延壽，秦皇登位更求仙。',32,'全唐诗/poet.song.67000.json','["彭祖八百乞延壽，秦皇登位更求仙。", "昨向天津橋上過，石崇猶自送窮船。"]'),
('4217e879-917a-4118-82c2-d3e76578d8be','呈佛鑑禪師偈','釋心道','宋','宋诗','song-poetry','','[]','趙州有箇柏樹話，禪客相傳徧天下。',64,'全唐诗/poet.song.67000.json','["趙州有箇柏樹話，禪客相傳徧天下。", "多是摘葉與尋枝，不能直向根源會。", "覺公說道無此語，正是惡言當面駡。", "禪人若具通方眼，好向此中辨真假。"]'),
('daf17f06-ca5c-474d-a49c-f476936353ba','偈','釋心道','宋','宋诗','song-poetry','','[]','師子嚬呻，象王哮吼。',58,'全唐诗/poet.song.67000.json','["師子嚬呻，象王哮吼。", "雲門北斗裏藏身，白雲因何喚作手。", "三世諸佛不能知，狸奴白牯却知有。", "雨打梨花蛺蝶飛，風吹柳絮毛毬走。"]'),
('d43c3754-f3b7-4009-ad07-080ec10ecae2','宣和改元改僧爲德士作偈','釋心道','宋','宋诗','song-poetry','','[]','祖意西來事，今朝特地新。',48,'全唐诗/poet.song.67000.json','["祖意西來事，今朝特地新。", "昔爲比丘相，今作老君形。", "鶴氅披銀褐，頭包蕉葉巾。", "林泉無事客，兩度受君恩。"]'),
('58df9421-7341-4530-9325-1ebcdbeb57af','宣和二年復僧作偈','釋心道','宋','宋诗','song-poetry','','[]','不掛田衣著羽衣，老君形相頗相宜。',32,'全唐诗/poet.song.67000.json','["不掛田衣著羽衣，老君形相頗相宜。", "一年半內閑思想，大底興衰各有時。"]'),
('e2175c37-b1eb-454f-9903-2f04f427fdd2','舉臨濟人滅囑三聖因緣作偈','釋心道','宋','宋诗','song-poetry','','[]','正法眼藏瞎馿滅，臨濟何曾有是說。',32,'全唐诗/poet.song.67000.json','["正法眼藏瞎馿滅，臨濟何曾有是說。", "今古時人皆妄傳，不信但看後三月。"]'),
('d3dd2789-01b2-4c4c-96c5-954586a84762','偈','釋心道','宋','宋诗','song-poetry','','[]','契丹打破波斯寨，奪得寶珠村裏賣。',32,'全唐诗/poet.song.67000.json','["契丹打破波斯寨，奪得寶珠村裏賣。", "十字街頭窮乞兒，腰間挂箇風流袋。"]'),
('c4d42415-c5a0-404e-b312-ce60e2582e4e','夜坐聯句','蘇邁','宋','宋诗','song-poetry','','[]','清風來無邊，明月翳復吐。',96,'全唐诗/poet.song.67000.json','["清風來無邊，明月翳復吐。", "松聲滿虛空，竹影侵半戶。", "暗枝有驚鵲，壞壁鳴饑鼠。", "露葉耿高梧，風螢落空廡。", "微凉感團扇，古意歌白紵。", "樂哉今夕遊，獲此陪杖屨。", "傳家詩律細，已自過宗武。", "短詩膝上成，聊以感懷祖。"]'),
('df0eb442-d99d-4beb-ac90-d9f682265565','句  其一','蘇邁','宋','宋诗','song-poetry','','[]','熟顆無風時自落，半腮迎日鬭鮮紅。',16,'全唐诗/poet.song.67000.json','["熟顆無風時自落，半腮迎日鬭鮮紅。"]'),
('f314c98f-d8bd-4330-891b-79c88c11605a','句  其二','蘇邁','宋','宋诗','song-poetry','','[]','葉隨流水歸何處，牛带寒鴉過晚村。',16,'全唐诗/poet.song.67000.json','["葉隨流水歸何處，牛带寒鴉過晚村。"]'),
('45c4216f-7c18-46db-87ea-e8771816523c','仙都山','胡升','宋','宋诗','song-poetry','','[]','鼎湖不可見，巍然但孤峰。',168,'全唐诗/poet.song.67000.json','["鼎湖不可見，巍然但孤峰。", "特立亙萬古，氣壓諸山雄。", "黄帝久得仙，游行跨飛龍。", "至今世俗傳，尚指輦路通。", "頗如昇天檜，追求白鹿蹤。", "常言貴荒唐，厥見真兒童。", "顧惟此山奇，實宜仙所宮。", "水聲來冷風，和以萬本松。", "客枕久未穩，笙簫滿虛空。", "頗疑九成音，不在二典中。", "但恐蚩尤旗，曄曄舒長虹。", "雖能獨不死，忍視斯民窮。", "君看涿鹿戰，萬古蒙其功。", "鼎湖何足道，帝德彌蒼穹。"]'),
('a800a6a3-fca5-467f-8ed2-6e8163029d36','和高季明玉溪曉步','陳興宗','宋','宋诗','song-poetry','','[]','物外有佳趣，塵中勞苦形。',48,'全唐诗/poet.song.67000.json','["物外有佳趣，塵中勞苦形。", "芒鞋枝短藜，快哉得松扃。", "蘿蔓猿狙懸，石磴苔蘚青。", "龍出正爲雨，碧潭如畫屏。"]'),
('d70071f8-85bf-46a9-9a28-da418c9a1cff','楞嚴經偈','蔡卞','宋','宋诗','song-poetry','','[]','覺海性澄圓，圓澄覺元妙。',288,'全唐诗/poet.song.67000.json','["覺海性澄圓，圓澄覺元妙。", "元明照生所，所立照性亡。", "迷妄有虛空，依空立世界。", "想澄成國士，知覺乃衆生。", "空生大覺中，如海一漚發。", "有漏微塵國，皆依空所生。", "漚滅空本無，況復諸三有。", "歸元性無二，方便有多門。", "聖性無不通，順逆皆方便。", "初心入三昧，遲速不同倫。", "色想結成塵，精了不能徹。", "如何不明徹，於是獲圓通。", "音聲雜語言，但伊名句味。", "一非含一切，云何獲圓通。", "香以合中知，離則元無有。", "不恒其所覺，云何獲圓通。", "味性非本然，要以味時有。", "其覺不恒一，云何獲圓通。", "觸以所觸明，無所不明觸。", "合離性非定，云何獲圓通。", "法稱爲內塵，憑塵如有所。", "能所非徧涉，云何獲圓通。", "見性雖洞然，明前不明後。", "四維虧一半，云何獲圓通。"]'),
('a9dde80e-cded-4c17-8602-cc418e0c709d','詠茅山元符萬寧宮','蔡卞','宋','宋诗','song-poetry','','[]','猗嗟三茅，得自初成。',150,'全唐诗/poet.song.67000.json','["猗嗟三茅，得自初成。", "氣合於無，與形俱昇。", "孰希其風，必靜必清。", "寥寥久哉，迺發先生。", "帝用尊之，載召來廷。", "迺親其人，燕見妙語。", "迺錫命書，迨其儔侶。", "因其故廬，啟此新宇。", "像圖仙真，上肖帝所。", "神筆牓之，龍鳳軒翥。", "天錫皇帝，聰明孝友。", "抱一用中，以綏九有。", "遐邇率從，尊道熙功。", "有欲求之，與在斯宮。", "作爲好歌，以詔無窮。"]'),
('3bdaec1e-e1b9-4aa7-9bed-5bbb5e1d4f61','贈華陽法師','蔡卞','宋','宋诗','song-poetry','','[]','師到華陽洞，山華幾度開。',24,'全唐诗/poet.song.67000.json','["師到華陽洞，山華幾度開。", "祇應常救物，却遣世人來。"]'),
('863c4c50-7ac9-4ef8-8268-292ec3381b40','句  其一','蔡卞','宋','宋诗','song-poetry','','[]','對掌紫樞參大政，同扶赫日上中天。',16,'全唐诗/poet.song.67000.json','["對掌紫樞參大政，同扶赫日上中天。"]'),
('6786a233-f085-4931-b0b3-35c90ff1c1a8','句  其二','蔡卞','宋','宋诗','song-poetry','','[]','莫學饑鷹飽便飛。',8,'全唐诗/poet.song.67000.json','["莫學饑鷹飽便飛。"]'),
('3993c898-de6a-470b-8704-d0825ce35ae2','同石元規講鵾鵬偶書','張繼先','宋','宋诗','song-poetry','','[]','翱翔數仞間，何異九萬里。',108,'全唐诗/poet.song.67000.json','["翱翔數仞間，何異九萬里。", "大道蕩無名，無彼亦無此。", "倬哉元規翁，斯言迨盡矣。", "一物自太極，志士摽高擬。", "鵬乎與蜩鳩，涉辯非至理。", "有形相變化，不出六合裏。", "飛躍涉程途，底用嘲遠邇。", "迺識逍遙游，潀遠發玄旨。", "講罷四窗閑，忘言空隠几。"]'),
('b4e7627c-c06c-46f3-ae85-bcfa693bbebb','運使徐中奉尋李隠者于本部因臨訪上清遂得煮茶款話至夜分乃散明目悅耳信有瑰偉崇高變通之論山川之秀亦有增明日分袂時宣和五年其略於是篇也','張繼先','宋','宋诗','song-poetry','','[]','西風初飄飄，白露仍瀼瀼。',132,'全唐诗/poet.song.67000.json','["西風初飄飄，白露仍瀼瀼。", "有人浮大川，東巡抵饒陽。", "實受九重書，因之訪丹房。", "山氣龍虎明，青林雲表長。", "與予適相值，議論清冰霜。", "已暮更秉燭，坐偶新月凉。", "玉蟾翳烟景，金飈扇天香。", "影落如卿雲，爛然獻奇祥。", "六合無異色，五峰同秋光。", "錦袍謫塵世，騎鯨隔川梁。", "君期踐玄約，緲緲空中翔。"]'),
('9474902d-f2d4-4c98-abea-bfb51e14d571','湯明權挈家入道','張繼先','宋','宋诗','song-poetry','','[]','佳汝久虛淡，有才弗願仕。',84,'全唐诗/poet.song.67000.json','["佳汝久虛淡，有才弗願仕。", "雞犬白雲間，挈家從遊此。", "所藴既超特，玄理可坐致。", "倬哉明主命，不以奪我志。", "一變江海才，總無塵土氣。", "聞之旌陽令，拔宅脫凡世。", "此事在精修，勉旃湯氏子。"]'),
('746482d3-c25d-40ca-8e1e-844af8258a64','書龍變軒事迺成頌白青城道伯','張繼先','宋','宋诗','song-poetry','','[]','一室絕塵埃，和風撼瑶竹。',84,'全唐诗/poet.song.67000.json','["一室絕塵埃，和風撼瑶竹。", "滿几惟琴書，瀟然異塵俗。", "時時操寸毫，節篆數囊籙。", "或同務玄子，楸枰兩三局。", "夜對隔林月，膝上奏神曲。", "更深興未闌，徐徐啟緘軸。", "好來青城君，雲開遠山綠。"]'),
('124d46e7-717f-4415-8f6b-720ad6337a11','和元規拜違','張繼先','宋','宋诗','song-poetry','','[]','纔到巍峨畔，還登翠碧重。',72,'全唐诗/poet.song.67000.json','["纔到巍峨畔，還登翠碧重。", "調青賡白雪，琴靜撫黄鍾。", "履踐古人道，追遊仙者蹤。", "自來多福力，相信各疏慵。", "何處不爲樂，此心知所從。", "還如一片月，掛在萬年松。"]'),
('79f882cf-a14d-4520-9f9d-049b6c9deb51','思青城翁','張繼先','宋','宋诗','song-poetry','','[]','一別青城翁，今經數旬朔。',72,'全唐诗/poet.song.67000.json','["一別青城翁，今經數旬朔。", "天炎春氣闌，山花旋零落。", "時時與攀慕，西眺步瑶閣。", "無乃戀人間，笙歌正酣樂。", "歸來方外儔，踐我綠巖約。", "回照閃餘輝，芙蓉出金削。"]'),
('21e3f106-353f-490b-ba97-7e3d67949421','和元規見勉','張繼先','宋','宋诗','song-poetry','','[]','觀君詞語中，具引先賢事。',216,'全唐诗/poet.song.67000.json','["觀君詞語中，具引先賢事。", "了然道在茲，不行而善至。", "君今真至矣，奏樂求真知。", "一言見吾子，固難盡於辭。", "知君貫老莊，亹亹蹈大荒。", "劇談玄中玄，豁落無邊旁。", "有學必有待，不與諸魔對。", "涉景若與知，何嘗訝譎怪。", "疑論渙已釋，則信爲善士。", "主善以爲師，天真坐可致。", "人間猶論分，仙事宜任運。", "有命終出倫，盍死即待盡。", "大道非罔象，明明萬物上。", "使我一聞知，應是快神爽。", "休更論淺深，斯言盡誠心。", "時哉且落魄，此語吾所欽。", "傍聽亦笑嗤，不責於仁慈。", "所幸異流俗，事物中思惟。"]'),
('b473e395-9405-46ed-b9c6-d6278233aa82','和張知縣省食費韵','張繼先','宋','宋诗','song-poetry','','[]','食饌不須豐，古人貴量腹。',72,'全唐诗/poet.song.67000.json','["食饌不須豐，古人貴量腹。", "一飽尚何求，八珍非所欲。", "犀筯厭未下，但折平生祿。", "造物賦人料，多少有數目。", "更思途中殍，皆緣食不足。", "莊叟重鵓食，此篇時一讀。"]'),
('463a396e-260f-45f5-850c-20c6b6d49819','又省衣','張繼先','宋','宋诗','song-poetry','','[]','衣服貴適宜，冬裘與夏葛。',72,'全唐诗/poet.song.67000.json','["衣服貴適宜，冬裘與夏葛。", "睠茲修行人，初不事精潔。", "輕紗并麗帛，樣新價亦別。", "每縑數千錢，拙工亂裁截。", "些小未稱身，中心已不悅。", "曾知有貧者，冬夏皆皮裂。"]'),
('f9605f56-501e-4680-96ab-1ee47d1d1aa3','大道歌','張繼先','宋','宋诗','song-poetry','','[]','道不遠，在身中，物則皆空性不空。',144,'全唐诗/poet.song.67000.json','["道不遠，在身中，物則皆空性不空。", "性若不空和氣住，氣歸元海壽無窮。", "欲得身中神不出，莫向靈臺留一物。", "物在身中神不清，耗散精神損筋骨。", "神馭氣，氣留形，不須雜術自長生。", "術則易知道難悟，既然悟得不專行。", "所以千人萬人學，畢竟終無一二成。", "神若出，便收來，神返身中氣自回。", "如此朝朝還暮暮，自然赤子産真胎。"]'),
('041404f3-4b7f-455c-bafe-18325536ef4d','虛空歌','張繼先','宋','宋诗','song-poetry','','[]','虛空蕩蕩無邊岸，日月東西互賓餞。',377,'全唐诗/poet.song.67000.json','["虛空蕩蕩無邊岸，日月東西互賓餞。", "東賓西餞幾時休，生死場中如掣電。", "本來真性同虛空，光明朗耀無昏蒙。", "偶因一念落形體，爲他生死迷西東。", "堪嘆世人全不覺，死即哀兮生即樂。", "不知生是死根由，只喜東升怕西落。", "東升西落理當然，休將情識相牽纏。", "不信但看日與月，朝昏上下常周天。", "生非來兮死非去，無有相因隨所寓。", "六道輪迴浪著忙，真人止在虛空住。", "真人住處無室廬，鄰風伴月同清虛。", "莫謂靈光只些子，包羅法界無遺餘。", "法界包羅大無外，密入纖塵小無內。", "饑寒災禍不能加，物物頭頭歸主宰。", "一堆塵土百年形，如舟泛水憑人行。", "忽朝舟壞人登岸，枯木無主從沉傾。", "莫腐莫回顧，萬水千江幾番渡。", "這回到岸好焚舟，不須更說波濤苦。", "有緣舟居不居舟，終不虞昨夜風雷撼山嶽。", "虛空不動常如如，識得真空方不昧，古往今來鎮長在。", "掀翻世界露全身，盡度衆生超苦海。", "真空消息非頑空，縱橫變化無終窮。", "聽我一歌空裏曲，鐵蛇飛上崑崙峰。"]'),
('fde24ad4-fce0-439f-859a-6d7f0f19390b','休歇歌','張繼先','宋','宋诗','song-poetry','','[]','休休休歇歇，休休歇歇無分別。',222,'全唐诗/poet.song.67000.json','["休休休歇歇，休休歇歇無分別。", "千般要妙萬般玄，只是教人各休歇。", "既能休，復能歇，一切情緣皆斷絕。", "饑餐渴飲困時眠，萬死千生沒交涉。", "古聖賢，及明哲，一性綿綿周浩劫。", "光明相照合真空，休歇之餘更無別。", "地獄種，作冤業，六識熾然如火熱。", "立我爭人昧休歇，甘受碎身并拔舌。", "休與歇，真口訣，無愚無智無工拙。", "從上師真只恁修，不遇知心誰肯泄。", "休非休，歇非歇，大用現前無扭捏。", "主張元化絕形蹤，囊括虛空超起滅。", "亦無休，亦無歇，歇歇休休皆强說。", "欲知真歇與真休，一輪皎潔中秋月。"]'),
('efe915df-bfda-4972-a5f4-bc75db216e18','錢塘有作','張繼先','宋','宋诗','song-poetry','','[]','紅霞映朱欄，白雲隠青山。',108,'全唐诗/poet.song.67000.json','["紅霞映朱欄，白雲隠青山。", "塵中人不到，雙鶴舞柴關。", "瑶琴一曲詩數篇，山童煮茗爐無烟。", "爲思塵世去遊樂，一別洞天今幾年。", "湘江江上月初白，湘浦浦邊風色清。", "斷腸聲咽玉笛碎，愁殺霜堤多少情。", "人生總浮雲，仙家依舊春，歸去來兮樂吾真。"]'),
('a6d6dc89-0106-4002-9fc7-d049920f457c','和元規任從他歌','張繼先','宋','宋诗','song-poetry','','[]','任從他，儘教他，莫管他，他是他非柰我何。',212,'全唐诗/poet.song.67000.json','["任從他，儘教他，莫管他，他是他非柰我何。", "盡日閑同方外友，高吟落筆如懸河。", "世上無心結凡累，匣中有劍降陰魔。", "長生已悟玄關旨，從教烏兔走如梭。", "塵勞汩沒誠堪惡，孰肯飄蕩隨蹉跎。", "靜處每思喧處事，到頭空自競噓呵。", "任從他，儘教他，莫管他，但從元氣養沖和。", "有時恣把丹書讀，無事閑尋玉軫歌。", "我心非石不可動，任從俗論生乖訛。", "松簪布褐且自樂，豈戀浮華張綺羅。", "神爐交媾鍊金液，混乎湛湛而日多。", "功行圓成共歸去，飄飄飛蓋拂霄河。", "任從他，儘教他，莫管他。"]'),
('c527b371-82e2-42df-9c0b-8e657040f3d9','橐籥歌','張繼先','宋','宋诗','song-poetry','','[]','休言大道無爲作，須向房中明橐籥。',112,'全唐诗/poet.song.67000.json','["休言大道無爲作，須向房中明橐籥。", "過時不動片時閑，紫霧紅光亂灼灼。", "青龍喜，白虎惡，赤蛇纏定烏龜殻。", "縱然過得尾閭關，又被曹溪路隔著。", "兩條直上絜丹田，决言上有三清閣。", "閣下分明有玉池，內有長生不死藥。", "依時下手採將來，服了蓬萊受快樂。"]'),
('ab04e298-3dcc-4192-9731-ff19d37f06ba','靖通庵歌','張繼先','宋','宋诗','song-poetry','','[]','吾結草庵山之中，旁人笑我名靖通。',352,'全唐诗/poet.song.67000.json','["吾結草庵山之中，旁人笑我名靖通。", "都來方寸閑田地，大包世界同虛空。", "我庵非通亦非靖，玲瓏八面無形影。", "盈虛消息任天機，庵內主人都不省。", "有時風雪三冬天，山前盡日無人烟。", "頑空墨黑晝如夜，庵中光耀長周圓。", "有時風雷平地起，山沉江湧流雲氣。", "龍吟虎嘯萬形喧，庵內情緣無止起。", "環庵松竹連天青，冬不悴兮春不榮。", "人來謾笑庵居苦，徹骨貧來徹骨清。", "清貧生理十分好，翻憶朱門多餓殍。", "君能認得自家珠，終身豈羨他人寶。", "庵似身兮主似心，欲明庵主須參尋。", "馿胎馬腹河沙夢，那知鐵鑛藏精金。", "高著眼睛速下手，只今覓取無中有。", "言窮理絕妄緣空，無毛獅子撩天吼。", "庵前大厦皆蘧廬，知音有幾同庵居。", "若非捩斷縣崖手，誰解伊邊認得渠。", "閑中有樂無人識，靜處工夫閑裏得。", "自然妙用自然真，向上神仙皆此出。", "浮手短景甚悠悠，一切庵壞便須休。", "溥勸吾門諸學者，不昧此庵須早修。"]'),
('aae52ffb-f29f-4125-81c6-742886317c5c','野軒歌','張繼先','宋','宋诗','song-poetry','','[]','四海鯨魚不足釣，縱使上鈎吾不要。',204,'全唐诗/poet.song.67000.json','["四海鯨魚不足釣，縱使上鈎吾不要。", "三島神仙不足誇，長生不死數如麻。", "驚人名譽不足恃，萬古英雄一場戲。", "些些富貴不足欣，何如野軒卧閑雲。", "洞然劫火纖芥盡，此時睡著都不聞。", "野軒野軒在何處，宇宙茫茫無入路。", "十千仙子浪中潜，百萬摶鵬地底度。", "此一軒，實奇特，神不知，鬼不測。", "東徹西，南徹北，中心一竅塵沙國。", "塵沙國界有微塵，一一微塵一真人。", "一一真人一真源，威儀隊仗數亦然。", "時人若見野軒叟，正眼一覷皆奔走。", "呵呵呵，千古萬古野軒歌。"]'),
('566a663d-632f-47ff-b6f1-046393221bb5','寄林太守','張繼先','宋','宋诗','song-poetry','','[]','長生門戶誰不愛，只要自己下功大。',64,'全唐诗/poet.song.67000.json','["長生門戶誰不愛，只要自己下功大。", "九宮臺上黄芽生，白玉池邊蟠桃在。", "撞動天關鬼神伏，撥轉地軸陰魔敗。", "河車搬上九重天，日月鍊成金世界。"]'),
('83eeb3ab-cda7-4527-8709-c8d16bc76846','懷鬼谷山思真洞天因詠以贈元規','張繼先','宋','宋诗','song-poetry','','[]','思真洞兮雲水深，道人居兮鬼神欽。',50,'全唐诗/poet.song.67000.json','["思真洞兮雲水深，道人居兮鬼神欽。", "山花笑兮松竹陰，巖溜潺潺兮千古音。", "何時一造兮清神襟，攀石蘿兮共笑吟。"]'),
('e4d69f9d-1855-4c56-9025-6691e9f31974','得請還山元規遠迓遂成山頌','張繼先','宋','宋诗','song-poetry','','[]','喜見石渾淪，忘言意獨真。',48,'全唐诗/poet.song.67000.json','["喜見石渾淪，忘言意獨真。", "還尋石橋約，一洗客京塵。", "香篆丹爐靜，詩篇彩筆新。", "高霞不狐映，携手洞門春。"]'),
('e85384b0-12d2-4974-9406-1e843b4eb118','和渾淪庵超然即事韵','張繼先','宋','宋诗','song-poetry','','[]','自得逍遙趣，從來樂靜居。',48,'全唐诗/poet.song.67000.json','["自得逍遙趣，從來樂靜居。", "水邊紅杏小，烟外翠篁疏。", "有物真常應，忘形內本虛。", "人間役塵慮，到此盡消除。"]'),
('6e53233e-141b-42d2-816b-e4bc10b8cfae','簡元規泰定二公','張繼先','宋','宋诗','song-poetry','','[]','傍水弦歌者，當簷執卷人。',48,'全唐诗/poet.song.67000.json','["傍水弦歌者，當簷執卷人。", "人心各有趣，天樂一何真。", "畏日初交夏，閑花尚是春。", "不隨寒暑變，只有劫初身。"]'),
('9d98620a-4fba-4812-ba6e-00e923df5a70','立秋之夕對酒成章粗遣清景以招佳詠','張繼先','宋','宋诗','song-poetry','','[]','閃閃秋光好，行行萬寶成。',48,'全唐诗/poet.song.67000.json','["閃閃秋光好，行行萬寶成。", "松高孤鶴唳，竹密一蟬鳴。", "大醉衣襟濕，空歌風度清。", "腰琴宜更作，楚澤有餘情。"]'),
('d9b0c963-e2c3-4424-ac4b-00a2fccc881c','送元規遊麻姑','張繼先','宋','宋诗','song-poetry','','[]','拂袖麻源景，飄飄逸興清。',48,'全唐诗/poet.song.67000.json','["拂袖麻源景，飄飄逸興清。", "不辭千里遠，獨步五雲輕。", "自有琴書樂，應無世俗縈。", "我慚阻追逐，回首謾馳情。"]'),
('ee0849cd-b68d-466e-8d13-f5051dfaee88','和元規拂雲軒韵','張繼先','宋','宋诗','song-poetry','','[]','疏翠擁高軒，虛徐欲出雲。',48,'全唐诗/poet.song.67000.json','["疏翠擁高軒，虛徐欲出雲。", "兩楹清蔭共，一陣好風分。", "偏映琴書席，難栖燕雀群。", "主人憐直節，孰敢巧操斤。"]'),
('683ee94d-7c8d-4879-a917-4048892fca75','元規道人覽予心說作頌見寄次韵奉答','張繼先','宋','宋诗','song-poetry','','[]','新文博不繁，披誦已清魂。',48,'全唐诗/poet.song.67000.json','["新文博不繁，披誦已清魂。", "意在諸緣外，心爲萬法源。", "猶龍誰可測，牧馬自微言。", "三復難窮處，重來得細論。"]'),
('8db2b5be-9ca1-48f0-b9c4-6e0b97b8a57e','聽元規琴','張繼先','宋','宋诗','song-poetry','','[]','萬物紛然在，渾淪聲不流。',48,'全唐诗/poet.song.67000.json','["萬物紛然在，渾淪聲不流。", "昔人弦上取，今我意中求。", "水激崖邊石，風高島上秋。", "相看得真樂，天地共優游。"]'),
('4b7dc047-cd80-4853-94e0-f4805b44df20','喜晴','張繼先','宋','宋诗','song-poetry','','[]','芍藥都零落，山泉遂有聲。',48,'全唐诗/poet.song.67000.json','["芍藥都零落，山泉遂有聲。", "盡知春去晚，深喜夜來晴。", "高柳拂簷浄，閑花照塢明。", "松間携好酒，今日思方清。"]'),
('84fb8c18-9b6d-4456-8e1c-99c6dd5d686c','鄧程二子傳法於予清壇事畢賦詩以遺之','張繼先','宋','宋诗','song-poetry','','[]','不閉三天道，難回二子誠。',48,'全唐诗/poet.song.67000.json','["不閉三天道，難回二子誠。", "露章招有感，裂帛喜爲盟。", "神劍一日試，法燈千古明。", "內觀當自悟，至理本無情。"]'),
('48ae9a27-cbd9-4bae-a6bb-52464b2c0fc0','送正之法師','張繼先','宋','宋诗','song-poetry','','[]','道貌古昂藏，聲名萬里香。',48,'全唐诗/poet.song.67000.json','["道貌古昂藏，聲名萬里香。", "紫霞衣縹緲，丹佩玉琳琅。", "寂寞居巖館，殷勤詠洞章。", "佇看功行滿，飛蓋上寥陽。"]'),
('4c7f1e37-fde2-43e6-b867-347865b90770','曬經','張繼先','宋','宋诗','song-poetry','','[]','遲日滿高臺，書囊雲錦開。',48,'全唐诗/poet.song.67000.json','["遲日滿高臺，書囊雲錦開。", "梅蒸陽氣透，林隠景光回。", "尚究千神恍，高吟萬惡摧。", "殷勤能啟秘，須仗出群材。"]'),
('671b1c61-29d3-420b-bc3c-84c1aa466372','晚步山間有作','張繼先','宋','宋诗','song-poetry','','[]','宿鳥頻來語，尋巢未得間。',48,'全唐诗/poet.song.67000.json','["宿鳥頻來語，尋巢未得間。", "小星明更近，高桂冷初攀。", "拂露松都在，因風信未還。", "豈無虛歇處，青及謝家山。"]'),
('609799e7-e77a-4c1a-99f5-746a84a070b3','和元規寄楊子寓真巖韵','張繼先','宋','宋诗','song-poetry','','[]','應到最高處，翹思上古人。',48,'全唐诗/poet.song.67000.json','["應到最高處，翹思上古人。", "風來多柏子，雲去浄囂塵。", "潯暑不到處，天花自在春。", "仙蹤欲無著，流俗謾尋津。"]'),
('7249586b-a06a-47a7-bce7-873693e7d122','次韵上勉元規','張繼先','宋','宋诗','song-poetry','','[]','優游且消遣，認取本來人。',48,'全唐诗/poet.song.67000.json','["優游且消遣，認取本來人。", "痛苦邊是妄，杳冥中有真。", "煎煩徒自累，恬惔即長春。", "君豈知予念，予身非子身。"]'),
('1d86e179-a107-446f-9124-e3b6f19cf686','題度儀堂四首  其一','張繼先','宋','宋诗','song-poetry','','[]','屢賞中秋月，山堂亦悵哉。',48,'全唐诗/poet.song.67000.json','["屢賞中秋月，山堂亦悵哉。", "暫居行百日，常覺近三台。", "大木聲深夜，脩篁蔭靜階。", "倘非能自度，何以見歸來。"]'),
('7cdc2d3a-f291-4859-8e42-3dee2e4bae39','題度儀堂四首  其二','張繼先','宋','宋诗','song-poetry','','[]','近戶皆林杪，元非粧點成。',48,'全唐诗/poet.song.67000.json','["近戶皆林杪，元非粧點成。", "山中行不遍，雨後看尤清。", "桃向天邊種，雲從嶺上生。", "不通雞犬到，時聽度鸞笙。"]'),
('7b2193a9-e6e9-44e9-8226-80a09a2ec20a','題度儀堂四首  其三','張繼先','宋','宋诗','song-poetry','','[]','驟爾升堂者，同乎白日仙。',48,'全唐诗/poet.song.67000.json','["驟爾升堂者，同乎白日仙。", "崇深鄰聖像，超卓愧吾年。", "微月兼寒露，喬松間野田。", "宮成方數載，猶使扣鍾錢。"]'),
('81a7c904-04f1-48f2-9221-1a335f5b0575','題度儀堂四首  其四','張繼先','宋','宋诗','song-poetry','','[]','正向西窗處，兩峰蒼翠排。',48,'全唐诗/poet.song.67000.json','["正向西窗處，兩峰蒼翠排。", "白雲清晝入，玄鶴幾時回。", "剪厭如毛竹，鋤嫌繞砌苔。", "有時不開戶，烟雨蔽陽臺。"]'),
('f95a9c43-4770-4615-b11c-3745046731ee','翛然元規夜坐酌余德儒所惠酒因成聯句','張繼先','宋','宋诗','song-poetry','','[]','共飲名家酒，三杯亦未辭。',288,'全唐诗/poet.song.67000.json','["共飲名家酒，三杯亦未辭。", "攄懷談道妙，舉筆賦新詩。", "雖病仍牽率，爲歡信渺瀰。", "疏星聯遠漢，綠水湛前池。", "未及裴君句，慚教樂所知。", "翛然清且慧，泰定默如癡。", "有美新荷近，無塵皓月隨。", "山風來細細，銀燭耿離離。", "青眼便爲覽，朱簾莫下垂。", "睡魔渾散釋，吟思愈清奇。", "萬態付一笑，千春總片時。", "此情能共適，得志任人嗤。", "道重皆相契，心機獨耻爲。", "瞿曇作良友，老聖是真師。", "四海無餘事，諸公足自怡。", "仙巖拏釣艇，雲錦種丹芝。", "世俗爲無謂，吾人還有宜。", "紅塵聊應跡，紫府去非遲。", "終始懷觀子，友持愧伯慈。", "功成當並駕，六合恣傲嬉。", "酒厭高陽價，人懷中古情。", "把杯聊共樂，對景發新聲。", "十二分清氣，三千外世榮。", "天真聊所適，俗禮莫相嬰。"]'),
('5bb37da4-694e-46e8-9ad5-4f87f3c766d1','七言再詠','張繼先','宋','宋诗','song-poetry','','[]','醉倒尚誇雲液美，吟看尤覺羽毛輕。',160,'全唐诗/poet.song.67000.json','["醉倒尚誇雲液美，吟看尤覺羽毛輕。", "松軒悵望情何限，竹檻留連興愈清。", "水草遠含青翠色，野花仍吐細微英。", "風來晝榻消殘暑，雨過秋蟬送晚聲。", "仙境每看天路近，風騷不許世紛縈。", "饒君先駕雲間鶴，顧我還騎海上鯨。", "白帝氣剛群動肅，道人心正百魔驚。", "共欣淡泊居林石，翻笑驅馳到市城。", "溪上且同三笑樂，飲中要與八仙爭。", "莫言酒量全輸我，會是詩名數石卿。"]'),
('d8a00aaa-af62-498a-88ca-7c26da1c56c2','同遊棲真聯句','張繼先','宋','宋诗','song-poetry','','[]','興爲棲真來，情因昔人動。',72,'全唐诗/poet.song.67000.json','["興爲棲真來，情因昔人動。", "昔人道非孤，今人心乃共。", "靜有物外樂，清無世間夢。", "至論超形神，談歌徹巖洞。", "野色雜茶甌，松聲入琴弄。", "未可賦歸歟，更揭流霞甕。"]'),
('2ba55622-d5e8-4d1e-886e-48fb4a9018c2','禱雨應時喜而聯句','張繼先','宋','宋诗','song-poetry','','[]','何以慰黎民，山川朝出雲。',120,'全唐诗/poet.song.67000.json','["何以慰黎民，山川朝出雲。", "精誠動天地，丹懇在詞文。", "南畝苗初槁，西郊雨已紛。", "林巒添鬰鬰，草木共欣欣。", "休怪芝田茂，其如羽服勤。", "穹蒼豈私曲，流俗足妖氛。", "途路塵埃息，軒窗暑氣分。", "豐年慰農叟，盛德謝吾君。", "枝潤驚林鳥，厨清絕楚蚊。", "上真何以報，惟把寶香焚。"]'),
('786eddd8-ec29-49d9-b7b4-b35af5c829a3','渾淪庵成翛然子親慶因以何字爲韵共酌聯句','張繼先','宋','宋诗','song-poetry','','[]','作室觀靈境，功成事若何。',216,'全唐诗/poet.song.67000.json','["作室觀靈境，功成事若何。", "琴書消日月，耕釣老烟蘿。", "爲羨雲蹤遠，時將酒共過。", "東巖開玉洞，西澗瀉銀河。", "整珮思天柱，觀棋悟爛柯。", "真情敦澹薄，世業信蹉跎。", "絕跡求無累，澄心到不波。", "渾淪甘宴息，真率謝澆訛。", "塵穢千峰隔，風流萬氣和。", "乾坤堪比壽，烏兔任如梭。", "仙至不無讖，鶴來信有他。", "煮茶留客話，種藥救民痾。", "竹露延清蔭，蘭風動妙歌。", "閑尋仙傳讀，靜把玉經科。", "大道猶衣袂，囂塵自網羅。", "有生如石火，移世以燈蛾。", "欲入高仙調，毋教下鬼唆。", "茅簷無一事，時復動吟哦。"]'),
('0a6cc357-6536-45a3-a075-4a8623352fd7','次御製賜于真人韵','張繼先','宋','宋诗','song-poetry','','[]','玉篆金章詠洞真，真中高妙孰能倫。',64,'全唐诗/poet.song.67000.json','["玉篆金章詠洞真，真中高妙孰能倫。", "世緣撥去神常靜，精食休來甑已塵。", "且爲聖明常讚化，未應栖遯便終身。", "自循多幸因君命，得往琳宮見一人。"]'),
('af0d34ae-5035-4e34-ac57-c0bc46ffe6a7','京師夜坐懷渾淪庵有作寄之','張繼先','宋','宋诗','song-poetry','','[]','獨坐空廬靜可知，江城意味豈如斯。',64,'全唐诗/poet.song.67000.json','["獨坐空廬靜可知，江城意味豈如斯。", "君看鳳實初成處，自稱蟾華欲妙時。", "酒興願同雲叟樂，風塵無取慶宗詩。", "山中林壑虛明境，不得歸吟有所思。"]'),
('2a19dae2-2874-4451-9745-3eab33c095aa','次韵答趙尚書','張繼先','宋','宋诗','song-poetry','','[]','炎蒸時節別家山，霜雪如今却漸寒。',64,'全唐诗/poet.song.67000.json','["炎蒸時節別家山，霜雪如今却漸寒。", "恨我虛名徒涉世，憶君高語共憑欄。", "比因厭客連朝卧，長是援琴終夜彈。", "已得明春歸去旨，預驚靈鶴整翎翰。"]'),
('4210e06e-42a9-4f51-9f10-c7fa4a95c083','送于真人','張繼先','宋','宋诗','song-poetry','','[]','仰慕清聲實積時，前朝因幸拜彤闈。',64,'全唐诗/poet.song.67000.json','["仰慕清聲實積時，前朝因幸拜彤闈。", "稍瞻風致頻相見，又恨霜天遽告歸。", "至德謾勞中下笑，高才須信古來稀。", "自慚功行虧楊許，安得南真談太微。"]'),
('b923454f-149c-4f50-86b0-bff8e83bb54d','新荷','張繼先','宋','宋诗','song-poetry','','[]','敗荷已盡小荷圓，照眼含香尚忍憐。',64,'全唐诗/poet.song.67000.json','["敗荷已盡小荷圓，照眼含香尚忍憐。", "月帝來尋青玉匣，金童立認碧銅錢。", "已凝重露資清氣，何幸輕風掃淡烟。", "遠有華峰全美在，花開般捧爛紅鮮。"]'),
('71b43841-c2e8-47e8-962b-8a7ef5c6bc9b','錢塘','張繼先','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','幾萬人家水繞城，白雲開處見丹青。',64,'全唐诗/poet.song.67000.json','["幾萬人家水繞城，白雲開處見丹青。", "地連金色三千界，山映瑶峰六尺屏。", "曉凭闌干披宿露，夜收簾幕透寒星。", "浙江風物端無賽，半擬蓬萊半洞庭。"]'),
('9fd3487c-f50f-4bf3-9cb6-85792e8a2ae5','恒甫以新茶戰勝因詠歌之','張繼先','宋','宋诗','song-poetry','','[]','人言青白勝黄白，子有新芽賽舊芽。',64,'全唐诗/poet.song.67000.json','["人言青白勝黄白，子有新芽賽舊芽。", "龍舌急收金鼎火，羽衣爭認雪甌花。", "蓬瀛高駕應須發，分武微芳不足誇。", "更重主公能事者，蔡君須入陸生家。"]'),
('b4503cd3-0884-4366-b5c1-c97ba66c4291','題皇仙寶積觀','張繼先','宋','宋诗','song-poetry','','[]','仙去仙人往結廬，我來自喜駐雲車。',64,'全唐诗/poet.song.67000.json','["仙去仙人往結廬，我來自喜駐雲車。", "秋陽今日七月九，花蘂長春千載餘。", "一派松前流水出，數行沈約戲題書。", "圍棋注酒餐蓮實，聊復有無談太初。"]'),
('2411c978-530d-4075-9e47-4739b3f43ac1','京師七夕率賦','張繼先','宋','宋诗','song-poetry','','[]','七夕風光豈易闌，一年一度巧相干。',64,'全唐诗/poet.song.67000.json','["七夕風光豈易闌，一年一度巧相干。", "不驚高處流星過，盡向今宵仰面看。", "花月有情天闕冷，胭山隨分酒杯寒。", "從茲肅肅秋陰後，却恐衣衾未復單。"]'),
('a6ed611d-db68-4e08-8c81-d2ed30a89c79','自京還始來龍變軒覓故年幽致閑成長句粗寫虛心','張繼先','宋','宋诗','song-poetry','','[]','尋得故年香翠團，共將真賞倚闌干。',64,'全唐诗/poet.song.67000.json','["尋得故年香翠團，共將真賞倚闌干。", "幾隨白日飛仙變，半爲今朝寶黑乾。", "光冷未粘春物笑，影疏來趁月華看。", "江南秋景猶繁劇，頼此一襟風月寒。"]'),
('a34ed53a-63c8-4a82-ad7b-a1f65a7e5313','還山','張繼先','宋','宋诗','song-poetry','','[]','長年京國甚羈囚，丘壑歸來始自由。',64,'全唐诗/poet.song.67000.json','["長年京國甚羈囚，丘壑歸來始自由。", "流水有聲如共語，閑雲無迹可同遊。", "猿依松影看丹竈，鶴與蘆花入釣舟。", "如此栖遲良不惡，紅塵何事辱鳴騶。"]'),
('453bf71e-8ba8-4b77-82a1-dac4ab4cedbd','答太守虞察院遊仙巖詩','張繼先','宋','宋诗','song-poetry','','[]','累年林下意何長，巖谷風霜亦備嘗。',64,'全唐诗/poet.song.67000.json','["累年林下意何長，巖谷風霜亦備嘗。", "俗客不曾交得到，達人應未以爲狂。", "江亭昔造懷寧海，石屋今居似瀨鄉。", "誰擬上饒新太守，却因朝謁到山陽。"]'),
('e9e1f88e-2df3-4418-91b6-e677e8adbce4','翫月翛然堂','張繼先','宋','宋诗','song-poetry','','[]','密林崇岫往留連，十載官非上士班。',64,'全唐诗/poet.song.67000.json','["密林崇岫往留連，十載官非上士班。", "赤帝御龍行末伏，嫦娥分月入深山。", "關津洞遠干戈後，食息將安州里間。", "今也柳堤真吏隠，清流華薄地寬閑。"]'),
('d565611e-39e6-48a1-9edc-19375156ed41','題沖虛堂','張繼先','宋','宋诗','song-poetry','','[]','養其沖氣以全生，栖息虛堂只數楹。',64,'全唐诗/poet.song.67000.json','["養其沖氣以全生，栖息虛堂只數楹。", "南浦道高坊號美，太微風暖木蘭清。", "百章爲愛青林密，三體應書老子成。", "未有紫宸朝覲日，雨餘幾處白雲輕。"]'),
('53d62da5-c305-4d91-9f75-23c887a49fb3','琴齋乃予舊居以琴名齋吾爲之也項先生與諸生居之談莊講老有佳趣向嘗造焉而憶往事乃亦有分勝多捄之處成詩呈項先生者書其實耳','張繼先','宋','宋诗','song-poetry','','[]','琴齋高致有真風，山閤延賓未折中。',64,'全唐诗/poet.song.67000.json','["琴齋高致有真風，山閤延賓未折中。", "來問死生非碌碌，爲談莊老肯匆匆。", "喜今可與君還往，惜昨曾留客許同。", "處士或將方寸比，斯人爲不殢焦桐。"]'),
('669f1582-a23d-4121-86e8-40132bd5cb1f','渾淪庵慶成','張繼先','宋','宋诗','song-poetry','','[]','高齋忽已慶成功，赤石蒼崖入眼中。',64,'全唐诗/poet.song.67000.json','["高齋忽已慶成功，赤石蒼崖入眼中。", "貞節由來拘世業，稚川隨處是家風。", "紅金柜隠書尤祕，碧玉壺清酒不空。", "崑閬歸期應可展，我來時欲笑歌同。"]'),
('ca6cdb5c-b400-4f0a-8f51-fcf9c18ba955','仙巖寺','張繼先','宋','宋诗','song-poetry','','[]','依然仙迹倚巖開，真館何年竟草萊。',64,'全唐诗/poet.song.67000.json','["依然仙迹倚巖開，真館何年竟草萊。", "今日梵宮方得到，舊時玄鶴也飛來。", "一條澗水琉璃合，萬疊雲山紫翠堆。", "禪客夜深能共坐，滿窗明月正徘徊。"]'),
('f8d7db4b-cd5a-414f-a570-11866769a5f4','汪務玄降睡有作','張繼先','宋','宋诗','song-poetry','','[]','萬籟沉沉丹滿空，一枰初勝務玄翁。',64,'全唐诗/poet.song.67000.json','["萬籟沉沉丹滿空，一枰初勝務玄翁。", "金壺飲罷前村酒，玉軫閑歌太古風。", "羨我無眠神已爽，笑渠貪睡意何濃。", "回頭爲報孤雲道，清濁由來自不同。"]'),
('4beab2bc-3cc6-48d9-b6f2-1b6f9ddc3962','和答周提刑','張繼先','宋','宋诗','song-poetry','','[]','試於閑處尋閑境，松竹無言綠滿秋。',64,'全唐诗/poet.song.67000.json','["試於閑處尋閑境，松竹無言綠滿秋。", "方外每煩勤下諭，山隅何幸偶來遊。", "一簾芳草庭前長，千載遺書圯上求。", "得請南還樂居此，清談深感聖恩優。"]'),
('b6aae937-1732-409a-aa89-72db815dd416','本竹治','張繼先','宋','宋诗','song-poetry','','[]','有興來登最上山，真風長在可躋攀。',64,'全唐诗/poet.song.67000.json','["有興來登最上山，真風長在可躋攀。", "世間濁質能相信，雲外清遊豈肯閑。", "怪石欲飛明落落，驚湍直下響潺潺。", "尋常衆目應難見，雲擁真人暗往還。"]'),
('bf610d1f-af4f-4074-bb24-7d6a7259bb97','蒙秦治','張繼先','宋','宋诗','song-poetry','','[]','紫垣佳客有靈蹤，獨木爲橋處處同。',64,'全唐诗/poet.song.67000.json','["紫垣佳客有靈蹤，獨木爲橋處處同。", "一自渾家參太極，更誰連步上青空。", "檻前怪木冬長碧，巖下靈光夜久紅。", "真澤不隨時世斬，出塵人世入神功。"]'),
('1890cfed-1a91-4129-bbb3-0d0ea82b0fad','平蓋治','張繼先','宋','宋诗','song-poetry','','[]','昔人已去附龍鱗，神氣猶存錄籍真。',64,'全唐诗/poet.song.67000.json','["昔人已去附龍鱗，神氣猶存錄籍真。", "洞口記曾三拜日，雲間別是一家春。", "釣絲無迹龜魚靜，樵客忘機虎豹馴。", "金井未經新汲引，已無胸次一纖塵。"]');
